-- Poems batch 248
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('cb4420d0-500b-4ba5-986e-67e6525ea177','登黄龍峰','王奕','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','黄龍峰頂接天高，下視塵寰走蝟毛。',64,'全唐诗/poet.song.224000.json','["黄龍峰頂接天高，下視塵寰走蝟毛。", "坤野未能休血戰，鼎湖誰復戀烏號。", "一杯彭蠡空浮淚，萬里長江漫激濤。", "安得駕虬鞭霹靂，漲翻溟渤洗腥臊。"]'),
('35613eb2-f65b-4cf9-a410-5173e58566f0','題陶狄二賢祠','王奕','宋','宋诗','song-poetry','','[]','豐碑大字極譽揚，並祀淵明與狄梁。',64,'全唐诗/poet.song.224000.json','["豐碑大字極譽揚，並祀淵明與狄梁。", "宇宙事皆吾己分，君臣義亦本天常。", "休官彭澤當存晉，取日虞淵合爲唐。", "自是後人無遠識，不知遺臭與流芳。"]'),
('2fa97f68-245c-4a79-a943-9527ef2dec4c','彭澤新縣靖節祠','王奕','宋','宋诗','song-poetry','','[]','已曾采石酹詩仙，又拜書巖薦菊泉。',64,'全唐诗/poet.song.224000.json','["已曾采石酹詩仙，又拜書巖薦菊泉。", "京口火頭纔負乘，柴桑處士便歸田。", "馳驅名並諸公駕，尸祝誰碑百世賢。", "近代從容人死義，後先二尹合俱傳。"]'),
('2a7120fe-b07a-4ec4-b043-7e95e5c01d75','四絕呈周月湖  其一','王奕','宋','宋诗','song-poetry','','[]','丸中日月妙推移，纔過三千六百朞。',32,'全唐诗/poet.song.224000.json','["丸中日月妙推移，纔過三千六百朞。", "霽月光風無盡藏，不應便黑小圈兒。"]'),
('4dcef8b5-d5cc-4ac5-b7d1-7805b54c564c','四絕呈周月湖  其二','王奕','宋','宋诗','song-poetry','','[]','不畫脩眉不易粧，篋中猶是主衣裳。',32,'全唐诗/poet.song.224000.json','["不畫脩眉不易粧，篋中猶是主衣裳。", "起觀疆宇皆周土，只有西山尚屬商。"]'),
('97baabb8-098d-4d7f-95f1-df659b411d32','四絕呈周月湖  其三','王奕','宋','宋诗','song-poetry','','[]','君住山陽岸口磯，風帆雨驛去如飛。',32,'全唐诗/poet.song.224000.json','["君住山陽岸口磯，風帆雨驛去如飛。", "十年多少金臺客，曾有沿津問泗沂。"]'),
('58311cc4-9a74-46e0-bcc9-6bc44888dd84','四絕呈周月湖  其四','王奕','宋','宋诗','song-poetry','','[]','草带粘天只辨星，燧樓盡化作郵亭。',32,'全唐诗/poet.song.224000.json','["草带粘天只辨星，燧樓盡化作郵亭。", "柳橋梅驛多來使，只寄山中養鶴經。"]'),
('834d733b-1c8d-4991-8744-e817d09f5af6','鶴林寺絕句','王奕','宋','宋诗','song-poetry','','[]','應是鵑花笑口開，火頭天子果何哉。',32,'全唐诗/poet.song.224000.json','["應是鵑花笑口開，火頭天子果何哉。", "遠公滿眼沽春酒，引殺陶潛不肯來。"]'),
('fd7f8052-0c2e-4985-8a5a-a3ddd9233b47','題彭澤舊縣狄梁公祠','王奕','宋','宋诗','song-poetry','','[]','周紀唐綱一線間，旋乾容易轉坤難。',64,'全唐诗/poet.song.224000.json','["周紀唐綱一線間，旋乾容易轉坤難。", "不將廟祔來雄辨，焉得宗祧可再安。", "國事固當元老定，德碑留與具臣看。", "寄言彭澤親民者，須學好人爲好官。"]'),
('84622356-e155-4e02-818a-9769acc5636f','題小蒜嶺','王奕','宋','宋诗','song-poetry','','[]','西風策策麥花凉，重把新詩自品量。',64,'全唐诗/poet.song.224000.json','["西風策策麥花凉，重把新詩自品量。", "禽不爲人音自好，路因無驛里偏長。", "百年白髮空前輩，兩載黄花笑異鄉。", "歸去玉瑘牢閉戶，莫教舊隠姓名香。"]'),
('27662ca4-30f3-4577-af8b-6cecb2547cea','歸途有感','王奕','宋','宋诗','song-poetry','','[]','少小從師讀魯書，幾回掩卷想風雩。',64,'全唐诗/poet.song.224000.json','["少小從師讀魯書，幾回掩卷想風雩。", "得遊鄒魯聖賢地，誰創華夷道德塗。", "地勢雖然有離合，脚跟却莫放模糊。", "不知江右明經士，曾識春秋兩字無。"]'),
('bebd5687-72af-4c47-a93f-c78083285f0b','題池州郵亭','王奕','宋','宋诗','song-poetry','','[]','驛堠珠連輳北燕，西風落日幾枝蟬。',64,'全唐诗/poet.song.224000.json','["驛堠珠連輳北燕，西風落日幾枝蟬。", "唐儀漢令碑上下，楚館秦郵世後先。", "新柳不知迎送事，短藜聊信去來緣。", "如今亭長皆民尹，那復圯橋更授編。"]'),
('d2d6fa19-5db3-4b15-b2a6-87c53f91ae84','九月申屠伯驥同飲壽張蚩尤塚上','王奕','宋','宋诗','song-poetry','','[]','蚩尤一夢四千年，涿鹿如今又不然。',64,'全唐诗/poet.song.224000.json','["蚩尤一夢四千年，涿鹿如今又不然。", "柵上懸絲重放下，草門朽骨尚高眠。", "昇烏沉兔人今古，點鵲癡蟬事後先。", "醉插黄花供一笑，誰知吟客是喬仙。"]'),
('6e85b476-35ec-45b8-8353-c26fde4895d7','題泰山仁安殿壁','王奕','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','大極何年誕帝孫，中居岱嶽鎮乾坤。',64,'全唐诗/poet.song.224000.json','["大極何年誕帝孫，中居岱嶽鎮乾坤。", "三千餘載昭明代，七十二君來至尊。", "魯甸齊邱雄地勢，秦松漢柏護天門。", "兵塵不動綿香火，萬里車書壽一元。"]'),
('edc261b9-396a-420a-845a-a818d199c938','新州枕上有感二首  其一','王奕','宋','宋诗','song-poetry','','[]','尼山拜了又何求，馳騖中原作壯遊。',64,'全唐诗/poet.song.224000.json','["尼山拜了又何求，馳騖中原作壯遊。", "泰岱峰頭觀日出，汶陽城外看河流。", "朝吟闞縣蚩尤塚，暮醉新州太白樓。", "從此不消刪白髮，留歸江上對眠鷗。"]'),
('b1ab1e6f-1ec0-4041-a4cd-19aa66cd113a','新州枕上有感二首  其二','王奕','宋','宋诗','song-poetry','','[]','岱岳名山天下無，老來遊玩易嗟吁。',64,'全唐诗/poet.song.224000.json','["岱岳名山天下無，老來遊玩易嗟吁。", "帝孫池畔秦松老，聖母祠前漢柏孤。", "古篆蝕苔悲建武，漫碑宿草憶祥符。", "逢人不解從頭數，牢記山名畫作圖。"]'),
('ff81b442-9d88-4482-adf3-e2a3904dd9d7','和遺山呈太山倪布山真人','王奕','宋','宋诗','song-poetry','','[]','江右書生枉白頭，杖藜始得北山遊。',64,'全唐诗/poet.song.224000.json','["江右書生枉白頭，杖藜始得北山遊。", "手摩紅日登三觀，袖拂黄埃看九州。", "及下誠明真氣貌，方知歲月老春秋。", "更須梓就諸公什，焰焰聲名萬古留。"]'),
('c491d38e-137c-44ba-bef8-df525e561239','呈申屠御史忍齋二首  其一','王奕','宋','宋诗','song-poetry','','[]','世家矯矯漢申屠，博古通今命世儒。',64,'全唐诗/poet.song.224000.json','["世家矯矯漢申屠，博古通今命世儒。", "豪傑雅知真北學，扶摇久已作南圖。", "揚州臺近催騎鶴，闞水秋深尚憶鱸。", "好載白雲同一出，簷頭新港即榮塗。"]'),
('5eac7871-9814-4890-a99c-925655aa4476','呈申屠御史忍齋二首  其二','王奕','宋','宋诗','song-poetry','','[]','壯遊久負子長才，斥鷃幾成困草萊。',64,'全唐诗/poet.song.224000.json','["壯遊久負子長才，斥鷃幾成困草萊。", "千載幸逢皇極運，兩生端爲聖門來。", "誰知白髮餘年健，得共黄花笑口開。", "明日西風歸棹遠，懷人空憶古罇罍。"]'),
('49980ffa-dca4-4173-b603-218c45b398b6','次韻上雪樓程侍御','王奕','宋','宋诗','song-poetry','','[]','當年雪片大如席，獨立樓頭有此翁。',64,'全唐诗/poet.song.224000.json','["當年雪片大如席，獨立樓頭有此翁。", "集霰已知漫大地，行窗轉覺舞回風。", "洛陽公子衾誰共，姑射仙人夢不同。", "且倚玉欄看世界，郢歌一曲月明中。"]'),
('5077979c-693a-405c-b0dc-578ad8626893','別宣尉王中齋','王奕','宋','宋诗','song-poetry','','[]','自笑靈龜久不靈，巧逢天地換清寧。',64,'全唐诗/poet.song.224000.json','["自笑靈龜久不靈，巧逢天地換清寧。", "典型頓覺空諸老，肝膈未能忘六經。", "朔雪漸深頭轉白，洛山雖遠眼還青。", "杏壇寂寂遺音在，靠得汾亭有父兄。"]'),
('c78a3221-0664-44d6-8374-686e65c4c825','贄見五峰燕先生','王奕','宋','宋诗','song-poetry','','[]','康廬崒嵂撐青空，五峰下有神仙翁。',176,'全唐诗/poet.song.224000.json','["康廬崒嵂撐青空，五峰下有神仙翁。", "黄金爲佩白玉瑣，跨虹飛上燕臺穹。", "紫垣蒼瑣白日靜，薇花韻的明丹衷。", "帝謂公田久不井，爲提明月江西東。", "某邱某壑無隠耳，貯見漢庾堆陳紅。", "周官六典冢宰事，有功𤱶畝方爲忠。", "蹇予落魄不耕子，半生煮字悲吟窮。", "蓋頭不思戀茅屋，負笈遠拜夫子宮。", "黄河泰華幸一見，於人須識歐陽公。", "枯根纖芥盡收拾，藥籠未必遺芳藭。", "品題願借燕許筆，可以報德歌豳風。"]'),
('364486b1-ebfe-4073-bc15-7c3ec95d1e24','再和韻上石塘吳  其一','王奕','宋','宋诗','song-poetry','','[]','髮燥聞君響泮宮，玉溪旴水限西東。',32,'全唐诗/poet.song.224000.json','["髮燥聞君響泮宮，玉溪旴水限西東。", "惜哉宴罷瑶池晚，乃在崇臺拜下風。"]'),
('178a7ea7-b2f8-4adc-89cf-ba45abbd327e','再和韻上石塘吳  其二','王奕','宋','宋诗','song-poetry','','[]','不能隨調轉商宮，獨抱瑶琴過魯東。',32,'全唐诗/poet.song.224000.json','["不能隨調轉商宮，獨抱瑶琴過魯東。", "霜滿烏庭無過雀，非君誰與借東風。"]'),
('bb1f5faf-1e69-456c-a22e-c366c6bc70ca','再和韻上石塘吳  其三','王奕','宋','宋诗','song-poetry','','[]','人心六籍未嘗焚，千古師存道亦存。',32,'全唐诗/poet.song.224000.json','["人心六籍未嘗焚，千古師存道亦存。", "見說汶陽官路口，幾年鞍馬上君門。"]'),
('0dcc88f1-3072-4508-9bcf-3fb108430c84','再和韻上石塘吳  其四','王奕','宋','宋诗','song-poetry','','[]','破笈兵韜久已焚，床頭僅有易書存。',32,'全唐诗/poet.song.224000.json','["破笈兵韜久已焚，床頭僅有易書存。", "一觀周禮歸來後，依舊白雲深閉門。"]'),
('b31d3d19-5c9d-4fa0-a8ed-4d8ad0709f8c','見陳月觀二首  其一','王奕','宋','宋诗','song-poetry','','[]','鰲轉山空海失深，仙人抱月自高吟。',64,'全唐诗/poet.song.224000.json','["鰲轉山空海失深，仙人抱月自高吟。", "春秋兩字尊王義，皇極一編經世心。", "千載文聲扶學校，萬年史筆寄山林。", "太邱古矣元龍老，天壽先生續正音。"]'),
('fea22ff1-d748-4cb9-aa0e-59019e4d0c5a','見陳月觀二首  其二','王奕','宋','宋诗','song-poetry','','[]','仲尼日月幾曾昏，自古君師豈必存。',64,'全唐诗/poet.song.224000.json','["仲尼日月幾曾昏，自古君師豈必存。", "水陸三千遊聖域，風雲萬里望天閽。", "燕臺接武何多隗，吳國孤騫未見雲。", "觀上又分明月影，漫漫長夜與誰論。"]'),
('b4422563-8a62-4642-a4df-a864730800cc','五絕呈李惟學山長  其一','王奕','宋','宋诗','song-poetry','','[]','嘗笑藍仙踏踏歌，極知感慨欲如何。',32,'全唐诗/poet.song.224000.json','["嘗笑藍仙踏踏歌，極知感慨欲如何。", "簷頭白日蒼生共，到了聖賢分得多。"]'),
('c3b3ec34-526d-4ff4-84c3-e31c436a9b08','五絕呈李惟學山長  其二','王奕','宋','宋诗','song-poetry','','[]','鑄金爲蠡聲猶泯，磨石爲碑字亦漫。',32,'全唐诗/poet.song.224000.json','["鑄金爲蠡聲猶泯，磨石爲碑字亦漫。", "雜雜萬形歸五化，燼餘方策更長存。"]'),
('5e1ec63e-6693-4b21-b745-d79c271e851b','五絕呈李惟學山長  其三','王奕','宋','宋诗','song-poetry','','[]','朝餐暮飲逐塵寰，清鏡無情不駐顔。',32,'全唐诗/poet.song.224000.json','["朝餐暮飲逐塵寰，清鏡無情不駐顔。", "千古菊泉香火地，名賢多是靠名山。"]'),
('58e53818-762d-4350-ac72-c7504b6cab7d','五絕呈李惟學山長  其四','王奕','宋','宋诗','song-poetry','','[]','星氣西流一擲梭，起看斗柄夜如何。',32,'全唐诗/poet.song.224000.json','["星氣西流一擲梭，起看斗柄夜如何。", "篝燈急了床頭易，明發開門事又多。"]'),
('143dd904-5dbe-42c5-8be1-3f1c06ec43f2','五絕呈李惟學山長  其五','王奕','宋','宋诗','song-poetry','','[]','隻影隨陽逐稻粱，故山元自富蒼筤。',32,'全唐诗/poet.song.224000.json','["隻影隨陽逐稻粱，故山元自富蒼筤。", "孤雄不作山梁夢，晚歲收聲在鳳岡。"]'),
('fdb464d5-3505-41ca-89f4-a3d5819ec7fe','呈招討李春野  其一','王奕','宋','宋诗','song-poetry','','[]','元田種玉不傳方，春去春來野自香。',32,'全唐诗/poet.song.224000.json','["元田種玉不傳方，春去春來野自香。", "雁入燕雲丹未反，笑援明月醉山陽。"]'),
('c3a58616-2d58-4ef3-943c-4bf8b0819202','呈招討李春野  其二','王奕','宋','宋诗','song-poetry','','[]','袖拂徂徠涉太峰，曾同太白舞西風。',32,'全唐诗/poet.song.224000.json','["袖拂徂徠涉太峰，曾同太白舞西風。", "歸程鶴瘦揚州遠，著訪吾宗太乙翁。"]'),
('1ba8f01b-938e-4559-be64-08af57d45688','和中丞徐容齋貫戶維揚','王奕','宋','宋诗','song-poetry','','[]','嶽到東原掌樣平，南州師友樹高名。',64,'全唐诗/poet.song.224000.json','["嶽到東原掌樣平，南州師友樹高名。", "聖人門戶三千教，老子胸懷百萬兵。", "學要絕時須著繼，道逢夷處不消爭。", "鳳池烏府皆餘事，急拯蒼生作九京。"]'),
('0cca357a-a100-4f12-9602-7bd19180960b','和申屠忍齋隸籍秦郵韵呈苟治書生','王奕','宋','宋诗','song-poetry','','[]','笑認鸞江舊祐環，大槐夢覺已無關。',64,'全唐诗/poet.song.224000.json','["笑認鸞江舊祐環，大槐夢覺已無關。", "看花要在雪霜裏，品士莫於文字間。", "烏府清風如有約，鶴樓明月不教閒。", "直須存活蒼生了，却把丹囊貯九還。"]'),
('dfe9a9a9-9481-485e-b663-b4c77b426740','登秦郵文遊亭天壁亭長歌','王奕','宋','宋诗','song-poetry','','[]','湖天澹澹湖水碧，湖風冉冉湖雲收。',272,'全唐诗/poet.song.224000.json','["湖天澹澹湖水碧，湖風冉冉湖雲收。", "湖白幾頃菰米地，湖汊幾摺蘆花洲。", "幾千萬劫走盡夜，三十六鏡磨春秋。", "江南狂客歸自魯，騎馿載酒遊文遊。", "文遊已落鐘鼓界，斯文喪矣遊人羞。", "蚌胎明月吸莘老，鴉背落日悲少游。", "東坡雙井化異物，神光奕奕穿斗牛。", "文章不逐歲月老，精爽常與天地流。", "賞心倘得際美景，薄才自許追前修。", "安得老米雞距筆，生綃百疋橫戈矛。", "守臺舊卒年九十，頤隠於臍肩過頭。", "六十年前邊鄙事，且言且泣氣咽喉。", "甚言秦欲帝萬世，據此要地置急郵。", "海田陵谷無定在，如今非項亦非劉。", "王生感慨重抵掌，驚起一片湖中鷗。", "鷗飛沒入翠烟裏，乾坤納納歸雙眸。", "何當飛出天壁外，春風吹散眉峰愁。"]'),
('13b8863b-41bd-4f62-98a8-62c163d59ce3','庚寅五月十二日偕趙平甫拜采石神霄宮太白墳','王奕','宋','宋诗','song-poetry','','[]','孤風吹黄鵠，遠客歸自魯。',108,'全唐诗/poet.song.224000.json','["孤風吹黄鵠，遠客歸自魯。", "瓣香拜公墳，梁月重凄楚。", "比曾登太山，依韻踵遐武。", "生平景仰心，茲夕遂親覩。", "何地無青山，何人無黄土。", "艷艷謫仙翁，配月照今古。", "惜哉生死世，於道竟無補。", "世乏蹈海人，此事與誰語。", "徘徊暮雲亭，玄蟬訴輕暑。"]'),
('082fb0ba-e73b-48f2-823a-4e35ea0aaaf1','登青山太白墓文并歌','王奕','宋','宋诗','song-poetry','','[]','蘆筆書空兮風淒淒，竹墨泌地兮雨垂垂，青楓黑塞兮夢公者誰。',28,'全唐诗/poet.song.224000.json','["蘆筆書空兮風淒淒，竹墨泌地兮雨垂垂，青楓黑塞兮夢公者誰。"]'),
('f6ad8f95-17d2-405e-99f0-0376a22413be','青山二章章四句  其一','王奕','宋','宋诗','song-poetry','','[]','青青者山，並祠其間。',20,'全唐诗/poet.song.224000.json','["青青者山，並祠其間。", "郭李遐矣，高義莫攀。"]'),
('9158e030-5178-4144-838c-c3c1d0f990ac','青山二章章四句  其二','王奕','宋','宋诗','song-poetry','','[]','山之青青，策蹇來經。',20,'全唐诗/poet.song.224000.json','["山之青青，策蹇來經。", "千古一日，二公之靈。"]'),
('6dbd3bd0-08f0-462f-ac4a-aabcbb689999','彭澤祭陶靖節祠','王奕','宋','宋诗','song-poetry','','[]','嗚呼，典午去矣，柴桑歸矣，黄花老矣，徵士卒矣。',26,'全唐诗/poet.song.224000.json','["嗚呼，典午去矣，柴桑歸矣，黄花老矣，徵士卒矣。", "尚饗。"]'),
('14370078-38a5-4327-a6ec-6a57815b0c7a','謝疊山先生己丑九月被執北行閩士以詩送之倚歌以餞  其一','王奕','宋','宋诗','song-poetry','','[]','皇天久矣眼垂青，盼盼先生此一行。',64,'全唐诗/poet.song.224000.json','["皇天久矣眼垂青，盼盼先生此一行。", "遺表不隨諸葛死，離騷長伴屈原清。", "兩生無補秦興廢，一出誠關魯重輕。", "白骨青山如得所，何消兒女哭清明。"]'),
('3c95ca9e-2969-4283-a46e-c237811acd9b','謝疊山先生己丑九月被執北行閩士以詩送之倚歌以餞  其二','王奕','宋','宋诗','song-poetry','','[]','襄漢無人替一肩，遂令杞國墜青天。',64,'全唐诗/poet.song.224000.json','["襄漢無人替一肩，遂令杞國墜青天。", "是誰鑄此一大錯，此事公知三十年。", "盡愛中都爲宰相，豈知上界有神仙。", "縱饒不返南飛翼，也合津橋化血鵑。"]'),
('5750daa1-1dc9-4f9b-b00c-f6df99eee5f9','淮安路教謝西溪己丑二月飲疊山于敬義堂有詩後三月僕至西溪見示時疊山已行矣','王奕','宋','宋诗','song-poetry','','[]','收斂眉山草木英，心潜羲孔與時行。',64,'全唐诗/poet.song.224000.json','["收斂眉山草木英，心潜羲孔與時行。", "浣花杜老驚人句，采石虞公貫日誠。", "合上燕臺爲上宰，暫勞楚泮領諸生。", "沉吟敬義堂中句，莫贖豪狂禰正平。"]'),
('ef0bb75b-999c-408d-8cd0-fe93b406690d','和疊山到山陽郡學四詩  其一','王奕','宋','宋诗','song-poetry','','[]','一水西來衣带然，界開北極與南天。',64,'全唐诗/poet.song.224000.json','["一水西來衣带然，界開北極與南天。", "軌文齟齬二百載，豪傑疏違幾十年。", "幸際干戈屯禍極，挽回禮樂泰和先。", "酒廉米賤山陽郡，多少吟仙與醉仙。"]'),
('bed4c88f-6b5f-472b-983a-08fe306c3d73','和疊山到山陽郡學四詩  其二','王奕','宋','宋诗','song-poetry','','[]','齠時蠹簡剔殘灰，皓首誰知吻带埃。',64,'全唐诗/poet.song.224000.json','["齠時蠹簡剔殘灰，皓首誰知吻带埃。", "負笈有機尊魯國，扣閽無力上燕臺。", "茹芝四皓還須出，綿蕞兩生終不來。", "中道喜逢傾蓋友，相携一笑亦奇哉。"]'),
('3040db4f-2f0e-44d1-ba66-e866d4b9567e','和疊山到山陽郡學四詩  其三','王奕','宋','宋诗','song-poetry','','[]','神仙無藥可醫狂，未死男兒未易量。',64,'全唐诗/poet.song.224000.json','["神仙無藥可醫狂，未死男兒未易量。", "東海水應隨血碧，西山薇亦逐名香。", "君臣分義如能盡，天地鬼神終不忘。", "自有人心香火在，不消畏壘與桐鄉。"]'),
('621c09a9-a08b-41cc-a18f-bd91edad8db1','和疊山到山陽郡學四詩  其四','王奕','宋','宋诗','song-poetry','','[]','一代英雄不數人，百年聚散重傷神。',64,'全唐诗/poet.song.224000.json','["一代英雄不數人，百年聚散重傷神。", "歌闌牛角天還曉，鐸振鱣堂道又春。", "泗水尼山聖賢地，江雲楚月去來賓。", "淮安蕩蕩朝天路，附驥新吟莫厭頻。"]'),
('9b4d7053-5e1f-4e6a-bc36-3abb33f04f9d','聞疊山己丑四月七日死于燕','王奕','宋','宋诗','song-poetry','','[]','聲名如此付杯羹，滿腹琅玕不得呈。',64,'全唐诗/poet.song.224000.json','["聲名如此付杯羹，滿腹琅玕不得呈。", "諾士倘能如孔子，殺身未必死盆成。", "骨埋北壤名山重，冤入南天上帝驚。", "當日刀圭成謾爾，金華仙籍再書名。"]'),
('46af9a22-d01a-4c67-931b-71f5613f78c6','和疊山隆興阻風','王奕','宋','宋诗','song-poetry','','[]','休將鑄錯悔當年，事契天心或不然。',64,'全唐诗/poet.song.224000.json','["休將鑄錯悔當年，事契天心或不然。", "殷士莫嗟留楚棹，孟婆久送過河船。", "惜哉燕谷空埋骨，自是圯橋少授編。", "畢竟火龍科目貴，二山忠義貫蒼天。"]'),
('960149a8-ccfb-4bac-b36f-56be0ebe4a30','和疊山送淮安士友韻','王奕','宋','宋诗','song-poetry','','[]','金臺去棹倚雲開，和餞諸詩已罄懷。',64,'全唐诗/poet.song.224000.json','["金臺去棹倚雲開，和餞諸詩已罄懷。", "行計竟爲尊魯出，櫓聲相逐過江來。", "定逢歸旆榮桑里，豈料危機伏茗杯。", "願梓新吟留宇宙，也勝蘇武得生回。"]'),
('fcfb6669-5dee-4c0f-bc20-a7858cba7aa3','和疊山小姑廟','王奕','宋','宋诗','song-poetry','','[]','舟如飛葉浪如雷，寄與江神不用猜。',64,'全唐诗/poet.song.224000.json','["舟如飛葉浪如雷，寄與江神不用猜。", "貞士偶因諸老出，兩生端爲聖門來。", "但沿沂水求雩瑟，即返嚴灘訪釣臺。", "可惜漢江風浪定，磯頭不見予卿回。"]'),
('84c5bf50-487b-4b5c-95f7-6d50cd50b350','和疊山小姑海門第一關詩','王奕','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','此是長江第一關，孤峰矯首聳遐觀。',64,'全唐诗/poet.song.224000.json','["此是長江第一關，孤峰矯首聳遐觀。", "人今人古興亡事，帆去帆來上下瀾。", "廟有神明司地險，舟藏鬼蜮過門難。", "吾儕出處憑天道，浪自舂撞意自寬。"]'),
('35aa46c0-6a4c-4f3a-a361-07a5e4ffe40e','和疊山舟過瀂港','王奕','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江幾載界殘棋，未著何知此地危。',64,'全唐诗/poet.song.224000.json','["長江幾載界殘棋，未著何知此地危。", "萬舸軍中焉用汝，一聲鑼罷竟何之。", "六民墮劫誰階厲，百罰鞭尸悔莫追。", "欲識開頭摇手處，推篷一一問篙師。"]'),
('b4494488-2540-4489-af10-27493c3adb7b','和疊山拜李白墓','王奕','宋','宋诗','song-poetry','','[]','唐朝組綬不能羈，馿背人者醉似泥。',64,'全唐诗/poet.song.224000.json','["唐朝組綬不能羈，馿背人者醉似泥。", "自欲駕虬憑化往，不因飛燕誤宮題。", "江涵采石吟天闊，月落青山塚未齊。", "雅廢倫亡知己少，青楓黑塞夢淒淒。"]'),
('d0af2077-7882-483d-ba53-b2d46c6d1e5f','再和前韻蛾眉亭','王奕','宋','宋诗','song-poetry','','[]','天經地緯脫籠羈，團拓乾坤作彈泥。',64,'全唐诗/poet.song.224000.json','["天經地緯脫籠羈，團拓乾坤作彈泥。", "采石青山知己少，渝州明月爲誰題。", "令公望重恩尤重，杜老名齊命亦齊。", "擬和岱吟才氣短，半眉蛾影暮雲凄。"]'),
('83c91b90-05bd-4260-bd56-1cde5174da8c','和疊山拜虞雍公廟','王奕','宋','宋诗','song-poetry','','[]','滴血書箋籲帝言，此功端已與之天。',64,'全唐诗/poet.song.224000.json','["滴血書箋籲帝言，此功端已與之天。", "是非成敗人間事，生死去來方外仙。", "龜背豐碑昏落日，鴉巢老木倚孤烟。", "廟前萬舸隨風下，應笑當年瀂港船。"]'),
('1ba98bb3-8433-4b39-ac2c-e957616f7c5d','送泰山倪布山真人','王奕','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','赤松宗世遠，嶽地作神仙。',60,'全唐诗/poet.song.224000.json','["赤松宗世遠，嶽地作神仙。", "粲粲龜瞳碧，昂昂鶴骨堅。", "五全皇極福，三受聖朝宣。", "道德交前輩，聲名在集賢。", "作詩聊紀實，歸與世人傳。"]'),
('7768777b-353c-4a9e-86f3-320f020576e7','和徐中丞容齋舊泰山一百四韻贄見','王奕','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u8861\u5c71"]','蹇予鉛槧生，角角雞鶩食。',288,'全唐诗/poet.song.224000.json','["蹇予鉛槧生，角角雞鶩食。", "青衿學校身，白髮書傳癖。", "萬卷老邊笥，一區守雄宅。", "媚俗懶低眉，慕古展長揖。", "少年塗抹技，志願靡終畢。", "幾載拂高駝，蒼梧與西極。", "開雲上衡山，景仰昌黎伯。", "史記在山川，遐蹤喜馳轢。", "望嶽企少陵，吟岱擬太白。", "惜哉阻關河，遊齒朽塵屐。", "悠悠鄒魯心，坐見歲月歷。", "雩壇想風沂，恨不沃焦膈。", "文理思楷林，手植槐檜柏。", "雖難陋巷回，豈不束带赤。", "髫年誦魯論，掩卷望天級。", "神哉六鰲轉，一夜混藩國。", "驅車上金臺，卿相去如織。", "逐日未化鄧，心血自撞激。", "既慚西山夫，尚堪東魯客。", "心旌久摇摇，夢寐在屋壁。", "忽逢緱山仙，扶我玉川腋。", "百拜揖溫良，敘此宇宙隔。", "秋丁杏壇下，展膝陪丈席。", "三聖長幼間，罇俎見徐疾。"]'),
('9d474879-df75-4cbd-8d3b-81b11d63177f','石塘歌呈吳侍郎','王奕','宋','宋诗','song-poetry','','[]','誰剜太素一拳石，石殻皴皺涵芳塘。',178,'全唐诗/poet.song.224000.json','["誰剜太素一拳石，石殻皴皺涵芳塘。", "塘中清淑族查滓，積成土塊如浮航。", "三千界分有南贍，休王帝伯更皇王。", "堯衢漲作九年潦，秦火煎成百沸湯。", "入昏出曉烏兔浴，韜風蓄電蛟龍藏。", "巫姒鑿開通浩浩，女媧煉熟補蒼蒼。", "三山縹緲出塘外，人云此是蓬萊鄉。", "誰令海乾白石爛，黑風吹散天風裳。", "黿腥蜃穢贔屭立，蝦螺鰍鱔生毫光。", "西江老子一口吸，噴作萬頃澄汪汪。", "何當長嘯挈斗柄，與君塘上酬酢傾天漿。"]'),
('72a3caef-9574-4522-8abd-8978f3169cf2','謝吳侍郎  其一','王奕','宋','宋诗','song-poetry','','[]','屋角梅花枕魯宮，柏臺借重過江東。',32,'全唐诗/poet.song.224000.json','["屋角梅花枕魯宮，柏臺借重過江東。", "月明鳥定文書靜，九郡譙樓起烈風。"]'),
('176028ba-91dd-497b-8148-a6c146d5197b','謝吳侍郎  其二','王奕','宋','宋诗','song-poetry','','[]','誰道靈光獨不焚，孔堂金石至今存。',32,'全唐诗/poet.song.224000.json','["誰道靈光獨不焚，孔堂金石至今存。", "皇王帝伯從開闢，不毀乾坤一合門。"]'),
('c8b6f9c8-3491-4b3f-9de8-8e46ef5bba03','黄池大水歌','王奕','宋','宋诗','song-poetry','','[]','玉斗山人歸自魯，迂途携酒酬謫仙。',304,'全唐诗/poet.song.224000.json','["玉斗山人歸自魯，迂途携酒酬謫仙。", "丹陽滯留十日雨，坐見平陸成長川。", "不衝不激不澎湃，漫高漫長漫囂塵。", "黄池地勢低且壙，築堤種柳名圩田。", "一圩動是數百頃，耕民縛舍沿郊阡。", "良苗懷新交翠浪，一刻漭作蛟龍淵。", "倉皇老釋競祈禱，搬移兒女爭牽連。", "村莊草屋浮斷梗，黄流黑氣蒸腥羶。", "市民運土積堘脊，危如燕壘懸杗前。", "中宵突爾駃一决，盡與河伯裾相牽。", "或云嶽瀆潴魍魎，呴沫吹浪如吹煎。", "昌黎諭鱷許戮蜃，古今此理容或然。", "粵從天一中入坎，水德流動隨乾圜。", "彝倫攸斁五行汩，君舟民水幾覆顛。", "神姒鑿窟踰九載，到今三千七百年。", "三時粟麥天不雨，蒼生何頼無瘠捐。", "天變不能違者水，民命自以君爲天。", "當今君相即堯禹，蓄積期會誰當先。", "靈均李杜在水部，叫天爲我箋長編。"]'),
('38ef9c74-f24a-4e33-91ac-17c05f8d6f86','回建德寄馮和峰隠士','王奕','宋','宋诗','song-poetry','','[]','王子歸鄒魯，知公隠德鄉。',48,'全唐诗/poet.song.224000.json','["王子歸鄒魯，知公隠德鄉。", "道爲千載惜，身抱六經藏。", "青壁丹崖遠，黄花白骨香。", "百年交一臂，悔不拜龐床。"]'),
('486ccdd4-b769-43d0-b6b7-de0399c23d09','和李提學存耕鉛山酌廉韻','王奕','宋','宋诗','song-poetry','','[]','先生在荷峰，此日賦泉石。',144,'全唐诗/poet.song.224000.json','["先生在荷峰，此日賦泉石。", "及今又重午，領客酌蓮碧。", "教雨落九垓，隨地成廉澤。", "師友係天倫，豈必同過客。", "孔孟與曾顔，日月照不息。", "袖香拜鄒魯，歷歷撫遺跡。", "沂水并尼山，雩壇儼如昔。", "晞髮濯我纓，埃溘盡湔滌。", "歸來見佳吟，轉覺肝膽易。", "此事不得再，此日良可惜。", "自憐飲食身，猶受氣形役。", "何當坐百原，一嘯脫塵屐。"]'),
('a5e951d1-5328-4142-9399-560f13b7c49c','過江絕句','王奕','宋','宋诗','song-poetry','','[]','玉勒金臺逐去塵，十年多少渡江民。',32,'全唐诗/poet.song.224000.json','["玉勒金臺逐去塵，十年多少渡江民。", "中流試扣金山老，曾有深衣過魯人。"]'),
('e51b2be6-d6ae-4414-bf10-4cd77864c435','梅','王奕','宋','宋诗','song-poetry','','[]','愛梅坐至夜三更，坐至三更意未平。',64,'全唐诗/poet.song.224000.json','["愛梅坐至夜三更，坐至三更意未平。", "潜以晉來爲己任，亮將漢去與天爭。", "是心或可道前哲，此理如何語後生。", "莫笑書生窮到老，雖窮到老也留名。"]'),
('d945882e-2374-4a79-96b4-bca97df100d0','泰山','王奕','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','扆齊機魯鎮天關，左右微垣列兩班。',32,'全唐诗/poet.song.224000.json','["扆齊機魯鎮天關，左右微垣列兩班。", "大展明堂俱翕受，黄河東畔少遊山。"]'),
('f53591ee-4b86-4700-baab-6cddc832a7fa','茂陵封禪壇','王奕','宋','宋诗','song-poetry','','[]','祥符天子舊明堂，二丈豐碑宿草荒。',32,'全唐诗/poet.song.224000.json','["祥符天子舊明堂，二丈豐碑宿草荒。", "人世已非壇更是，摩挲老淚濕斜陽。"]'),
('e0f9dc7b-d326-44f9-960d-0bc3f4991b43','漢柏','王奕','宋','宋诗','song-poetry','','[]','膚剝心枯歲月深，孫枝已解作龍吟。',32,'全唐诗/poet.song.224000.json','["膚剝心枯歲月深，孫枝已解作龍吟。", "烈風吹起孤高韻，猶作峰頭梁甫音。"]'),
('27f6ef50-60ed-4d5d-98d9-fae2db3be022','孫明復石守道祠堂','王奕','宋','宋诗','song-poetry','','[]','師生高掠二山名，千載誰云道義輕。',32,'全唐诗/poet.song.224000.json','["師生高掠二山名，千載誰云道義輕。", "嶽府柏林風雨夜，琅然猶带讀書聲。"]'),
('fd562119-68b5-43ff-9cd3-ebe695e182bf','水簾洞','王奕','宋','宋诗','song-poetry','','[]','密織多因雨線添，泉紳高掛月鈎纖。',32,'全唐诗/poet.song.224000.json','["密織多因雨線添，泉紳高掛月鈎纖。", "洞仙羞見秦丞相，故遣東風放下簾。"]'),
('73965765-72ad-455f-b7bb-02e560dce96f','回馬嶺','王奕','宋','宋诗','song-poetry','','[]','嶺入青天不可梯，六飛到此盡遭遲。',32,'全唐诗/poet.song.224000.json','["嶺入青天不可梯，六飛到此盡遭遲。", "異哉猶有秦皇馬，回向庭前化鹿兒。"]'),
('f02283d1-191b-4986-8f06-73b66e0d8859','護駕泉','王奕','宋','宋诗','song-poetry','','[]','嶽泉匹練落雲間，萬折東流不得閑。',32,'全唐诗/poet.song.224000.json','["嶽泉匹練落雲間，萬折東流不得閑。", "駕到源頭猶且護，如何護不到崖山。"]'),
('dce34290-37f1-413d-b744-0a5d0ec69e73','大夫松','王奕','宋','宋诗','song-poetry','','[]','立身地位本清寒，下界虛明孰敢干。',32,'全唐诗/poet.song.224000.json','["立身地位本清寒，下界虛明孰敢干。", "驚駕不因風雨惡，到頭猶守舊蒼官。"]'),
('9a63d7a3-4d18-4251-9c3c-f6a3bad02910','和段好古外郎二首  其一','王奕','宋','宋诗','song-poetry','','[]','休煩蜀鳥勸歸頻，正欲尼山拜聖人。',64,'全唐诗/poet.song.224000.json','["休煩蜀鳥勸歸頻，正欲尼山拜聖人。", "若使詩書灰烈燄，便應天地化微塵。", "漢書牛角雖漫夜，魯史麟經不斷春。", "花市一番風雨後，幾多桃李又重新。"]'),
('ea67ff3f-c98c-44ed-b956-fed608269fb1','和段好古外郎二首  其二','王奕','宋','宋诗','song-poetry','','[]','黍峰蒲糝正關情，况復登高望冶城。',64,'全唐诗/poet.song.224000.json','["黍峰蒲糝正關情，况復登高望冶城。", "驚見北方真學者，尚憐南國舊書生。", "風遺異世晉有笏，猶在君家唐未輕。", "三復謾行詩句好，雩壇從此振吟聲。"]'),
('88a4c9f9-a08d-4976-b222-16d45d3b8ad3','病後感興寄車玉峰先生二首  其一','李景文','宋','宋诗','song-poetry','','[]','北風何颼颼，木葉下未已。',72,'全唐诗/poet.song.224000.json','["北風何颼颼，木葉下未已。", "閉門讀古書，世念書中起。", "酒饌傾南鄰，笙歌喧北里。", "歡娛極寒夜，不知漏下幾。", "忽聞南來雁，起坐頻撫几。", "樹蘐未有期，食芹空嘆美。"]'),
('a8f225ab-1337-49d6-b568-2246ac09b5f0','病後感興寄車玉峰先生二首  其二','李景文','宋','宋诗','song-poetry','','[]','折梅寄故人，故人青雲間。',60,'全唐诗/poet.song.224000.json','["折梅寄故人，故人青雲間。", "青雲杳無路，夢裏相往還。", "我愛梅花娟，彼惜桃李顔。", "相逢不相契，何事勞追攀。", "守此歲寒心，持以遺所歡。"]'),
('7ab3cc5a-d779-4fc8-bdb1-b34f8c10affd','廬墓有感','李景文','宋','宋诗','song-poetry','','[]','流水遶門去，愁雲壓徑斜。',48,'全唐诗/poet.song.224000.json','["流水遶門去，愁雲壓徑斜。", "無人燒柏子，有客問梅花。", "橘熟猨窺樹，池空鳥啄沙。", "自傷寒谷日，不及照昏鴉。"]'),
('538e83e4-3fe2-4b8f-a0e2-4880973ddc8f','遊委羽山','李景文','宋','宋诗','song-poetry','','[]','王國風塵暗，仙山景物新。',48,'全唐诗/poet.song.224000.json','["王國風塵暗，仙山景物新。", "龍宮逾紫禁，鶴寓遠朱輪。", "冰融溪上日，花發洞門春。", "一似桃源路，從今學避秦。"]'),
('93b8f01b-2f6d-4cfa-800d-16a6b2e2dd32','訪開公不遇','胡子期','宋','宋诗','song-poetry','','[]','獨步小庵清，憑軒數小星。',48,'全唐诗/poet.song.224000.json','["獨步小庵清，憑軒數小星。", "霜華連野白，山色滿門青。", "風定松猶響，香銷室自馨。", "孤雲何處宿，案上掩蓮經。"]'),
('dc8a88cb-f117-4d00-9b2c-9a235352d293','梅花  其一','陳景沂','宋','宋诗','song-poetry','','[]','標薰江雪情偏韻，影墨窗蟾夢半回。',32,'全唐诗/poet.song.224000.json','["標薰江雪情偏韻，影墨窗蟾夢半回。", "耐凍有何香可述，雅交還喜淡相陪。"]'),
('1ab02489-63b7-4861-9618-be283b0dd702','梅花  其二','陳景沂','宋','宋诗','song-poetry','','[]','從來造化有何私，自是梅花南北枝。',32,'全唐诗/poet.song.224000.json','["從來造化有何私，自是梅花南北枝。", "只爲北枝太寒苦，東君消息故應遲。"]'),
('76291821-d491-4d65-abe5-5cb26e65bba1','梅花  其三','陳景沂','宋','宋诗','song-poetry','','[]','行人立馬闖烟梢，爲底寒香尚寂寥。',32,'全唐诗/poet.song.224000.json','["行人立馬闖烟梢，爲底寒香尚寂寥。", "是則孤根未回暖，已應春意到溪橋。"]'),
('52fb4dbb-4e01-4a49-876a-f6796d68b6e2','梅花  其四','陳景沂','宋','宋诗','song-poetry','','[]','重崗複嶺萬千程，霜褪紅稀步恰輕。',32,'全唐诗/poet.song.224000.json','["重崗複嶺萬千程，霜褪紅稀步恰輕。", "瞥有暗香松下過，不知何處隠梅兄。"]'),
('321ee2ef-d693-4d09-b146-5fb1b8c49a50','梅花  其五','陳景沂','宋','宋诗','song-poetry','','[]','平生足迹遍天下，正一東嘉却弗來。',32,'全唐诗/poet.song.224000.json','["平生足迹遍天下，正一東嘉却弗來。", "行到劉山無所寄，謾留冷句伴江梅。"]'),
('ab6d4376-fc70-4902-980f-49ab421953fb','紅梅','陳景沂','宋','宋诗','song-poetry','','[]','色異味同失主張，厭寒附暖逐群芳。',32,'全唐诗/poet.song.224000.json','["色異味同失主張，厭寒附暖逐群芳。", "當知不改冰霜操，戲學陶家艷冶粧。"]'),
('18187625-1cfb-442c-bc54-87f57cdaf24c','石榴花','陳景沂','宋','宋诗','song-poetry','','[]','陰霾渺渺接江鄉，登陸猶褰未涉裳。',64,'全唐诗/poet.song.224000.json','["陰霾渺渺接江鄉，登陸猶褰未涉裳。", "入晚天容糊水色，拂明雲影帽山光。", "悶拈昌歜嗟香玉，披讀離騷玩徹章。", "最是荷榴兩懷古，對人無語濕紅粧。"]'),
('f3749440-ed92-4985-96b8-19de34bb9d62','海棠','陳景沂','宋','宋诗','song-poetry','','[]','自是司花別有神，要憑詩句寫花真。',64,'全唐诗/poet.song.224000.json','["自是司花別有神，要憑詩句寫花真。", "風翻翠袖愜寒薄，雨湔紅妝啼暈新。", "爲困未眠嬌欲吐，將唇微褪笑如嗔。", "牡丹芍藥尤無那，君識鶑聲識燕身。"]'),
('492732a6-ce0d-412c-93c1-bf2e20c5a29a','桃花','陳景沂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','江銜洞庭急，君山屹半川。',48,'全唐诗/poet.song.224000.json','["江銜洞庭急，君山屹半川。", "別知江有國，大率水多仙。", "環繞八百里，洪濛十萬年。", "晚春桃正碧，南客曉浮船。"]'),
('a792d25e-8b00-4e91-98d7-c5c182268e78','葵花','陳景沂','宋','宋诗','song-poetry','','[]','人情物理要推求，不早敷黄隸晚秋。',32,'全唐诗/poet.song.224000.json','["人情物理要推求，不早敷黄隸晚秋。", "黄得十分雖好看，風霜爭奈在前頭。"]'),
('fc1d32df-0115-45ec-b905-da248a986e35','牽牛花','陳景沂','宋','宋诗','song-poetry','','[]','牽牛易斯藥，固特取其義。',172,'全唐诗/poet.song.224000.json','["牽牛易斯藥，固特取其義。", "安用柔軟蔓，曲爲縈絆地。", "汝若不巧沿，何能可旁致。", "始者無附託，頭腦極細殢。", "一得風動摇，四畔亂拈綴。", "搭著纖毫末，走上牆壁際。", "儻得梯此身，戀纏松竹外。", "吐花白而青，敷葉光且膩。", "裛露作嬌態，舞風示豪氣。", "便忘抑鬰時，剩有誇逞意。", "誑言松和竹，如我兄與弟。", "下盼蘭菊群，反欲眇其視。", "如此無忌憚，不過是瞞昧。", "教知早晚霜風高，杪表何曾見牛翠。"]'),
('8dc69572-1778-4d3d-9831-26106d894c1b','含笑花','陳景沂','宋','宋诗','song-poetry','','[]','此花枝葉山礬類，氣味雖殊本共行。',64,'全唐诗/poet.song.224000.json','["此花枝葉山礬類，氣味雖殊本共行。", "鐵定青門瓜魄變，否因李白酒魂香。", "紫唇半吐胭脂重，素臉初開玉色裝。", "懊惱酴醾詫名色，亂施冶鬢過低牆。"]'),
('05569f39-26f8-48f1-8f48-3ced598feaf8','楊梅  其一','陳景沂','宋','宋诗','song-poetry','','[]','紅實綴青枝，爛漫照前塢。',24,'全唐诗/poet.song.224000.json','["紅實綴青枝，爛漫照前塢。", "不及杏繁時，林間有仙虎。"]'),
('0128888c-e37a-4e09-b02d-89cc5fe72e47','楊梅  其二','陳景沂','宋','宋诗','song-poetry','','[]','止渴還相似，和羹諒亦同。',24,'全唐诗/poet.song.224000.json','["止渴還相似，和羹諒亦同。", "不思五和裏，調濟荷元功。"]'),
('d8d7af1b-954b-4697-b676-26848a0768e2','草  其一','陳景沂','宋','宋诗','song-poetry','','[]','淡烟荒草六朝宮，萬感叢生一眺中。',64,'全唐诗/poet.song.224000.json','["淡烟荒草六朝宮，萬感叢生一眺中。", "不識群公互虓虎，獨於此地必爭熊。", "秦河濺淚西風泣，淮巘含羞晚照紅。", "醖得許多愁爲底，祗緣悞倚大江東。"]'),
('4568dbe3-7ca3-4639-a93d-fecef12d5b3d','草  其二','陳景沂','宋','宋诗','song-poetry','','[]','未破滁陽亭屢易，亭亡今又幾經年。',64,'全唐诗/poet.song.224000.json','["未破滁陽亭屢易，亭亡今又幾經年。", "峰回路轉勢不改，木秀陰繁直到巔。", "流下山泉音若咽，燒餘寺刻塊如拳。", "柴王一殿今何在，衰草殘煙護曉娟。"]'),
('145f0aa8-efc4-436d-a6d0-11912662a5fa','草  其三','陳景沂','宋','宋诗','song-poetry','','[]','江城滕閣倚空寒，鶴勢鶱飛遠耐看。',64,'全唐诗/poet.song.224000.json','["江城滕閣倚空寒，鶴勢鶱飛遠耐看。", "旁列西山青玉案，高擎南浦白銀盤。", "摩挲王記猶無恙，拂拭韓碑尚未刓。", "翻憶賞心亭下水，草洲埋沒貯愁酸。"]'),
('f4d5447e-d89c-4899-b001-7e845b2d8ec7','草  其四','陳景沂','宋','宋诗','song-poetry','','[]','長淮何處雁聲多，西去渦心北邁河。',64,'全唐诗/poet.song.224000.json','["長淮何處雁聲多，西去渦心北邁河。", "影逐泗濱煙月艇，陣驚亳邑水雲簑。", "小王草筆終難學，蘇武陵書果若何。", "陲草邊蘆兩蕭索，遠陪砌女作離歌。"]'),
('47cf4b59-8283-49aa-b4dd-b71e830e19b8','蘆  其一','陳景沂','宋','宋诗','song-poetry','','[]','風雨蕭蕭夕，春寒燈較昏。',48,'全唐诗/poet.song.224000.json','["風雨蕭蕭夕，春寒燈較昏。", "茅簷數椽屋，荻浦幾家村。", "網到江鱗活，沽來市酒渾。", "焙衾共結局，一覺眇乾坤。"]'),
('9b3fd922-cfb8-4452-b6ab-9f7cc0de76bc','蘆  其二','陳景沂','宋','宋诗','song-poetry','','[]','一一溪邊石，堆成幾別離。',48,'全唐诗/poet.song.224000.json','["一一溪邊石，堆成幾別離。", "青蒲駛檣本，黄葦掠船墀。", "話別從今日，云來是幾時。", "藏心栗黄蟹，歸買配香炊。"]'),
('6fa4962a-19c4-4832-b05d-fb65077f7eaa','松  其一','陳景沂','宋','宋诗','song-poetry','','[]','仙往徑獨在，亭高山若堆。',48,'全唐诗/poet.song.224000.json','["仙往徑獨在，亭高山若堆。", "知非凡木比，識得洞賓來。", "骨蛻棧沉水，壇緣薜荔栽。", "于何穉松子，有記弗詳該。"]'),
('8c077e55-da57-4c2f-b91c-22bc1dc80863','松  其二','陳景沂','宋','宋诗','song-poetry','','[]','遠吹疏疏奏竹房，亂撩松友發清狂。',64,'全唐诗/poet.song.224000.json','["遠吹疏疏奏竹房，亂撩松友發清狂。", "雲拖雨陣沿山至，巖溲泉聲走澗長。", "和我微吟似音律，續他高韻費思量。", "誰人宅裏遺簪處，碧玉橫釵十二行。"]'),
('544d191d-85d0-4e1b-94e0-395ac05559f4','楊柳  其一','陳景沂','宋','宋诗','song-poetry','','[]','美笑千黄金，駐景雙白璧。',60,'全唐诗/poet.song.224000.json','["美笑千黄金，駐景雙白璧。", "東風楊柳津，幾度千絲碧。", "款款白面郎，畫舫宮樣粧。", "新隄五里長，回頭意悠揚。", "幽人興不忙，得志汀草芳。"]'),
('0914147f-0f7d-46a5-9f65-1751fe1a7267','楊柳  其二','陳景沂','宋','宋诗','song-poetry','','[]','非綠非青麴雨塵，顛頭倒尾亂江陰。',32,'全唐诗/poet.song.224000.json','["非綠非青麴雨塵，顛頭倒尾亂江陰。", "金衣公子經過處，不辨其身只辨音。"]'),
('ef6594a6-dff3-4a3f-a1d3-1e36b48b40dc','楊柳  其三','陳景沂','宋','宋诗','song-poetry','','[]','相尚津涯臨畫舫，栽從亭館近華筵。',32,'全唐诗/poet.song.224000.json','["相尚津涯臨畫舫，栽從亭館近華筵。", "別離自是無聊頼，于甚垂楊有糾牽。"]'),
('c295eed6-abac-4732-84ca-be7d4addeedc','楊柳  其四','陳景沂','宋','宋诗','song-poetry','','[]','爲爾生來體態柔，因情感物寓風流。',32,'全唐诗/poet.song.224000.json','["爲爾生來體態柔，因情感物寓風流。", "汝無血氣何知覺，自是詩人想像求。"]'),
('5e02b8e7-0042-4aa2-830f-031e4627c3ca','句  其一','陳景沂','宋','宋诗','song-poetry','','[]','海棠已入老娼籍，芍藥初登童子科。',16,'全唐诗/poet.song.224000.json','["海棠已入老娼籍，芍藥初登童子科。"]'),
('de9c69ad-3c37-47de-aef0-b95a1505c393','句  其二','陳景沂','宋','宋诗','song-poetry','','[]','賦質太輕難作主，飄蹤無著易粘人。',16,'全唐诗/poet.song.224000.json','["賦質太輕難作主，飄蹤無著易粘人。"]'),
('86fc5c3b-4d7a-4f0a-8224-33394dc79507','聚八仙花歌贈江淮肥遯子','韓似山','宋','宋诗','song-poetry','','[]','春皇自厭花多紅，欲得花顔如玉容。',397,'全唐诗/poet.song.224000.json','["春皇自厭花多紅，欲得花顔如玉容。", "春皇青女深相得，先教臉似秋霜色。", "乃有雪月供光、星榆獻白，斗量銀漢琉璃濕。", "人間美玉搗作灰，荆山崑山鬼神泣。", "天上有人名玉女，投壺之外能爲絮。", "姑射神人會種花，先須此物爲根芽。", "天罅地竅掏精碎，蟾身璃領輸光華。", "其時正值天地交，二氣上下陰陽調。", "此花孕育得其正，其間邪氣無纖毫。", "所以其色爲正色，出乎其類拔其萃。", "一如君子有諸內，晬然其色見乎外。", "三月將盡四月前，百花開盡春蕭然。", "揚州日暖花開未，春風不動花房閉。", "仙掌秋高玉露濃，蛟人泣下真珠淚。", "黄鸝本是花間客，啼盡好聲求不得。", "春皇費盡養花心，春風使盡開花力。", "春歸鶑老花始開，誰人放出深闌來。", "唐家天子太平君不見揚州后土惜瓊花，鬼神守護祝史誇。", "要令天下頌無雙，掉頭不住君王家。", "支流遠自靈源至，顔色雖同別名氏。", "風流晚宿蝴蝶圍，環珮曉聚仙人戲。", "仙人已往今無蹤，身在花枝窈窕中。", "似聞飲中之八仙，飄飄豪氣摩蒼穹。", "身雖可滅名不窮，魂交心與之死靡。"]'),
('1415de29-55ad-49bb-9329-8667926c3c08','題陳山飛星石','魯應龍','宋','宋诗','song-poetry','','[]','錦石雙星下翠微，忽看移入小巖扉。',64,'全唐诗/poet.song.224000.json','["錦石雙星下翠微，忽看移入小巖扉。", "靈光夜靜歸山逕，翠影秋寒上拂衣。", "滇海始知鯨欲動，零陵不獨燕能飛。", "只今五色曾何補，自採奇峰築釣磯。"]'),
('e49289bd-a9bb-47c4-bdfc-8fa696cc6403','蓮房魚包','林洪','宋','宋诗','song-poetry','','[]','錦□金蓑織幾重，問魚何事得相容。',32,'全唐诗/poet.song.224000.json','["錦□金蓑織幾重，問魚何事得相容。", "湧身既入蓮房去，好度華池獨化龍。"]'),
('91e41ab0-d64c-4339-86c1-cab0ba3983ee','西湖','林洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','烟生楊柳一痕月，雨弄荷花數點秋。',32,'全唐诗/poet.song.224000.json','["烟生楊柳一痕月，雨弄荷花數點秋。", "此景此時摹不盡，畫船歸去有漁舟。"]'),
('129ea5c9-77ef-4ae0-b679-c1564847d51d','宮詞','林洪','宋','宋诗','song-poetry','','[]','金殿當頭紫閣重，仙人掌上玉芙蓉。',32,'全唐诗/poet.song.224000.json','["金殿當頭紫閣重，仙人掌上玉芙蓉。", "太平天子朝元日，五色雲車駕六龍。"]'),
('89d8e007-7508-42f0-8815-a44e41e261c6','水仙花','林洪','宋','宋诗','song-poetry','','[]','清真處子面，剛烈丈夫心。',36,'全唐诗/poet.song.224000.json','["清真處子面，剛烈丈夫心。", "翠带拖雲舞，金巵照雪斟。", "苦吟吟不得，移入伯牙琴。"]'),
('522dcc6c-e792-40cb-877c-7f5f7d770e3e','春宮','林洪','宋','宋诗','song-poetry','','[]','桃李六宮寂，君王在石渠。',24,'全唐诗/poet.song.224000.json','["桃李六宮寂，君王在石渠。", "臨鸞悔梳洗，女色不如書。"]'),
('5f7b6e33-8fc7-4ccd-b61b-d37c329417e2','桐下','林洪','宋','宋诗','song-poetry','','[]','無名花草上閑坡，病葉成堆客罕過。',64,'全唐诗/poet.song.224000.json','["無名花草上閑坡，病葉成堆客罕過。", "注易欠工知學少，種桐收效得陰多。", "破籬自補憂邊事，斷簡重穿憶世科。", "近日轉知閑最好，旋沽鄰酒謝詩魔。"]'),
('8318ce46-2f66-4adf-8d0d-e376338bc6bd','枕上作','林洪','宋','宋诗','song-poetry','','[]','天街月未沈，來者已駸駸。',48,'全唐诗/poet.song.224000.json','["天街月未沈，來者已駸駸。", "夜若可無睡，人應更有心。", "香凝衾正暖，燈隔帳如陰。", "亦欲呼童起，誰門能賞音。"]'),
('0a6acdd3-c44b-4a9a-9373-7d4092e698fb','折柳','林洪','宋','宋诗','song-poetry','','[]','湖邊楊柳色如金，幾日不來成綠陰。',32,'全唐诗/poet.song.224000.json','["湖邊楊柳色如金，幾日不來成綠陰。", "折得柔條入城去，教人知道已春深。"]'),
('8bc803f9-2b42-40b6-8e52-24e453ede64f','樓居','林洪','宋','宋诗','song-poetry','','[]','梅邊未有屋三間，僦得樓居特暫安。',64,'全唐诗/poet.song.224000.json','["梅邊未有屋三間，僦得樓居特暫安。", "天下事非容易說，門前山可久長看。", "瓶花頻換春常在，階草不除秋自殘。", "豈是江湖難著脚，如今平地亦狂瀾。"]'),
('f526ca8c-1124-4dbe-9c4d-e862ee98af8f','孤山隠居','林洪','宋','宋诗','song-poetry','','[]','爲怕因詩題姓名，特尋孤處隠吟身。',32,'全唐诗/poet.song.224000.json','["爲怕因詩題姓名，特尋孤處隠吟身。", "當時祗向梅花說，不道梅花說與人。"]'),
('c4341d06-2aae-4450-bf82-9e2059e3596b','謀隠','林洪','宋','宋诗','song-poetry','','[]','篋書如葉半飄零，尚自浮家客帝京。',64,'全唐诗/poet.song.224000.json','["篋書如葉半飄零，尚自浮家客帝京。", "每遇事添新感慨，怕逢人說舊升平。", "山如有約青常在，髮幸相饒白未生。", "便作陰謀猶是晚，栽松何日得陰成。"]'),
('bf7fb4a8-8d1c-4920-9e1c-b28417ccf5ec','釣臺','林洪','宋','宋诗','song-poetry','','[]','三聘殷勤起富春，如何一宿便辭君。',32,'全唐诗/poet.song.224000.json','["三聘殷勤起富春，如何一宿便辭君。", "早知閑脚無伸處，只合青山卧白雲。"]'),
('f27743bb-62c3-4560-a782-3c2aef5933d0','冷泉','林洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一泓清可沁詩脾，冷暖年來只自知。',32,'全唐诗/poet.song.224000.json','["一泓清可沁詩脾，冷暖年來只自知。", "流出西湖載歌舞，回頭不是在山時。"]'),
('2bdfe3a3-2226-41a2-90d4-e114c6c9b9ed','句','林洪','宋','宋诗','song-poetry','','[]','雪翻夜鉢裁成玉，春化寒酥剪作金。',16,'全唐诗/poet.song.224000.json','["雪翻夜鉢裁成玉，春化寒酥剪作金。"]'),
('f2d788fc-8980-4020-93b9-2822164598bd','寄林可山','許介軒','宋','宋诗','song-poetry','','[]','不必孤山是故廬，江湖穩處即安居。',64,'全唐诗/poet.song.224000.json','["不必孤山是故廬，江湖穩處即安居。", "家貧無料可供鶴，池小有泉能活魚。", "好客每傾賒到酒，因吟猶讀老來書。", "屋頭但得梅常在，日月春風自有餘。"]'),
('30505ae1-36e0-4d1c-955e-522d4f64a85a','燕','許介軒','宋','宋诗','song-poetry','','[]','柳影芹香二月春，一巢纔定即棲身。',32,'全唐诗/poet.song.224000.json','["柳影芹香二月春，一巢纔定即棲身。", "不應它處無華屋，自是難忘舊主人。"]'),
('e2954f75-2a8f-46cb-8d80-e65a87e1a1d5','嘲林洪','無名子','宋','宋诗','song-poetry','','[]','和靖當年不娶妻，只留一鶴一童兒。',32,'全唐诗/poet.song.224000.json','["和靖當年不娶妻，只留一鶴一童兒。", "可山認作孤山種，正是瓜皮搭李皮。"]'),
('cf8f3041-c7a3-49cd-aa67-e0f2bdf0b7cd','題鳳林橋','高仁邱','宋','宋诗','song-poetry','','[]','一道長虹跨北河，往來憑此涉清波。',64,'全唐诗/poet.song.224000.json','["一道長虹跨北河，往來憑此涉清波。", "帆從寶相叢中度，人向金鼇頂上過。", "此日高車題字少，昔年驅石敘功多。", "鳳凰已去無遺響，只此江鷗答棹歌。"]'),
('6c5d9f26-81d0-4e25-abb3-3b284b2ebd5c','戒惜字紙','張淵微僕母','宋','宋诗','song-poetry','','[]','萬般諸字文，即與藏經同。',24,'全唐诗/poet.song.224000.json','["萬般諸字文，即與藏經同。", "安在不浄處，墮作厠中蟲。"]'),
('63ab3116-f30a-4cd8-9c2d-daf2d7822676','詠羣玉山','趙與沔','宋','宋诗','song-poetry','','[]','一山幾臺觀，羣玉錫佳名。',48,'全唐诗/poet.song.224000.json','["一山幾臺觀，羣玉錫佳名。", "遷客品題處，高人燕坐清。", "池荒欠溶漾，石瘦儘崢嶸。", "怪怪奇奇處，山陰道上行。"]'),
('a361b2a2-00f7-448f-8cd4-e41e6c31a175','卞壼忠孝堂','錢汝元','宋','宋诗','song-poetry','','[]','哀哉戰死國門邊，忠孝千年獨兩全。',32,'全唐诗/poet.song.224000.json','["哀哉戰死國門邊，忠孝千年獨兩全。", "蓋有完軀保妻子，誕謾奏凱說麋捐。"]'),
('5df99040-0a0c-417e-a8eb-9b1055cfb8d4','詩一首','文儀','宋','宋诗','song-poetry','','[]','乙卯之春鳳詔頒，二孫指擬上春官。',32,'全唐诗/poet.song.224000.json','["乙卯之春鳳詔頒，二孫指擬上春官。", "蘭宮綰却藍袍了，猶恨麻衣淚未乾。"]'),
('2e0a281e-f2ca-4617-9846-8e8436b73ccc','梅','徐霖','宋','宋诗','song-poetry','','[]','萋萋細碧江南地，上有梅花朔易天。',32,'全唐诗/poet.song.224000.json','["萋萋細碧江南地，上有梅花朔易天。", "鐵石空餘心已盡，霜明日潤若爲妍。"]'),
('93c661c4-2330-4071-a754-bb055aba310c','西城亭餞趙架閣','徐霖','宋','宋诗','song-poetry','','[]','天闊五雲開彩陰，王孫萬里驊騮駸。',64,'全唐诗/poet.song.224000.json','["天闊五雲開彩陰，王孫萬里驊騮駸。", "風烟泱漭年華老，雲樹淒迷別思深。", "此日江城樽酒話，當年故國棟梁心。", "夜闌秉燭匆匆劇，頼有梅花生短吟。"]'),
('7e6c0a13-2945-46ff-82ba-796e406733a7','笋石','徐霖','宋','宋诗','song-poetry','','[]','玉茗亭西石笋春，偶來相對作閒人。',32,'全唐诗/poet.song.224000.json','["玉茗亭西石笋春，偶來相對作閒人。", "千年未爛應還待，化鶴叮嚀日未曛。"]'),
('800ad52e-aae4-4fd6-9559-bdaa83800839','芙蓉池亭','徐霖','宋','宋诗','song-poetry','','[]','仲冬多美曝，散步有餘真。',48,'全唐诗/poet.song.224000.json','["仲冬多美曝，散步有餘真。", "老樹槎牙晚，初花的爍春。", "清歌動落日，遠岫得幽人。", "空返無佳句，知爲暮靄嗔。"]'),
('bd3a23b8-25fc-42a8-9a1f-28036539b4e2','爛柯山','徐霖','宋','宋诗','song-poetry','','[]','尚書勝跡留千載，太守離思去十八。',32,'全唐诗/poet.song.224000.json','["尚書勝跡留千載，太守離思去十八。", "難得地主真可人，載酒問字石須伐。"]'),
('51a77599-d8b6-4288-aa66-cdc31d06c67f','春望','吳錫疇','宋','宋诗','song-poetry','','[]','春事今如此，憑高興未闌。',48,'全唐诗/poet.song.224000.json','["春事今如此，憑高興未闌。", "半簾疏雨過，一院落花閒。", "草色迷幽逕，禽聲出晚山。", "東風能育物，不改鬢毛斑。"]'),
('2bd4e9f7-51b4-481c-a7b8-d63a28d5a201','迂拙','吳錫疇','宋','宋诗','song-poetry','','[]','迂拙安吾分，炎涼任世情。',48,'全唐诗/poet.song.224000.json','["迂拙安吾分，炎涼任世情。", "簞瓢自鐘鼎，風月即勳名。", "春樹重重暗，晴雲片片明。", "滄波山閣外，浩蕩一鷗輕。"]'),
('c20ae47f-19cd-4427-a885-cb0d1995a584','晚步','吳錫疇','宋','宋诗','song-poetry','','[]','晚日弄晴陰，徐行野逕深。',48,'全唐诗/poet.song.224000.json','["晚日弄晴陰，徐行野逕深。", "山寒梅韻峭，林杳鶴聲沈。", "緩水元無響，飛雲豈有心。", "頗知閒最樂，天地入清吟。"]'),
('514441f9-bdf0-4fc1-92fd-baf82b0bd713','烟波奇觀寫興','吳錫疇','宋','宋诗','song-poetry','','[]','層樓一望立斜暉，三兩人家出翠微。',64,'全唐诗/poet.song.224000.json','["層樓一望立斜暉，三兩人家出翠微。", "淺瀨欲流山影去，疏簾不礙月明歸。", "自來樵釣無榮辱，到底功名有是非。", "識得老天窮我意，免教世俗踐危機。"]'),
('79129a79-28a1-4d1a-9458-261671f9ee99','林和靖墓','吳錫疇','宋','宋诗','song-poetry','','[]','遺稿曾無封禪文，鶴歸何處但孤墳。',32,'全唐诗/poet.song.224000.json','["遺稿曾無封禪文，鶴歸何處但孤墳。", "清風千載梅花共，說著梅花定說君。"]'),
('7f4660a6-38b0-45bc-a6a3-f3c6543d0ef0','春日','吳錫疇','宋','宋诗','song-poetry','','[]','韶光大半去匆匆，幾許幽情遞不通。',64,'全唐诗/poet.song.224000.json','["韶光大半去匆匆，幾許幽情遞不通。", "燕未成家寒食雨，人如中酒落花風。", "一窗草憶濂溪老，五畝園思涑水翁。", "無賦招魂成獨嘯，且排春句答春工。"]'),
('58c0eff6-0080-439b-9850-8c4b937ed880','蘭','吳錫疇','宋','宋诗','song-poetry','','[]','石畔稜稜翠葉長，葳蕤紫蕊吐幽芳。',32,'全唐诗/poet.song.224000.json','["石畔稜稜翠葉長，葳蕤紫蕊吐幽芳。", "靈均去後無人問，林密山深只自香。"]'),
('95aa76b7-a14b-43a1-99a0-11198aa15800','夕陽','吳錫疇','宋','宋诗','song-poetry','','[]','夕陽牛背數家村，一笛聲中欲斷魂。',32,'全唐诗/poet.song.224000.json','["夕陽牛背數家村，一笛聲中欲斷魂。", "人世百年雙短鬢，不知禁得幾黄昏。"]'),
('93e25266-1930-4849-98ef-b06a2e1e7bcc','洲上','吳錫疇','宋','宋诗','song-poetry','','[]','藜杖步芳洲，風花點碧流。',48,'全唐诗/poet.song.224000.json','["藜杖步芳洲，風花點碧流。", "詩情鳬泛泛，心事水悠悠。", "有約山長翠，無名草自幽。", "聲聲啼布穀，夜雨足西疇。"]'),
('1dc7f5db-1fc0-4323-bbe7-90ce3151b393','寄漫客汪子美兼簡竹牖東美','吳錫疇','宋','宋诗','song-poetry','','[]','雁斷無書到筆峰，暮雲空自滿江東。',64,'全唐诗/poet.song.224000.json','["雁斷無書到筆峰，暮雲空自滿江東。", "漫郎一片襟期杳，子美三生習氣同。", "身外有貲惟老硯，竹邊無價是清風。", "何時共聽檐花雨，小醉微吟夜燭紅。"]'),
('ef0fbee7-2d06-469a-9481-1a6491f60895','晚春','吳錫疇','宋','宋诗','song-poetry','','[]','書策爐熏了日閒，雨餘庭砌綠迴環。',64,'全唐诗/poet.song.224000.json','["書策爐熏了日閒，雨餘庭砌綠迴環。", "一春又是尋常過，兩鬢誰知容易斑。", "輕薄楊花芳草岸，凄涼杜宇夕陽山。", "不嫌貧有雙飛燕，依舊銜泥自往還。"]'),
('480d98a0-58c7-4edc-a2b2-bde1673263d3','新荷','吳錫疇','宋','宋诗','song-poetry','','[]','園林春去後，幽景屬池塘。',48,'全唐诗/poet.song.224000.json','["園林春去後，幽景屬池塘。", "過雨鈿猶小，吹襟風已香。", "莫期包作饋，好待集爲裳。", "太極翁何在，花時愛敢忘。"]'),
('999c33b4-bd69-4ea1-b433-b74bd60a45dc','夜坐','吳錫疇','宋','宋诗','song-poetry','','[]','蕭蕭下庭葉，未晚閉柴門。',48,'全唐诗/poet.song.224000.json','["蕭蕭下庭葉，未晚閉柴門。", "故篋搜詩讀，殘燈喚酒溫。", "砧鳴深巷月，犬吠隔溪村。", "人世如無夜，勞生事更繁。"]'),
('45184cf0-9675-4379-9227-32f464c6efac','聞鶑','吳錫疇','宋','宋诗','song-poetry','','[]','湖邊春壓柳絲低，雲淡風輕一杖藜。',32,'全唐诗/poet.song.224000.json','["湖邊春壓柳絲低，雲淡風輕一杖藜。", "伐木詩亡交道絕，綿蠻空爲盡情啼。"]'),
('dc857169-4a29-43fb-be4b-fab15810504f','漁父','吳錫疇','宋','宋诗','song-poetry','','[]','笭箵儘自了生涯，岸尾沙頭即是家。',32,'全唐诗/poet.song.224000.json','["笭箵儘自了生涯，岸尾沙頭即是家。", "入夜醉歸橫短笛，滿江明月浸蘆花。"]'),
('eb0ea01c-ad11-4520-a9b9-d9b16194c0ce','春日從伯氏領子姪郊行','吳錫疇','宋','宋诗','song-poetry','','[]','寒食清明共一時，柔紅開遍野棠梨。',64,'全唐诗/poet.song.224000.json','["寒食清明共一時，柔紅開遍野棠梨。", "繁禽聲樂風光麗，弱柳陰濃日脚遲。", "身外生涯何似酒，人間局面只如棋。", "行春莫待花飛却，藉草開樽剩賦詩。"]'),
('7e0757e7-d9f8-490b-9e20-59abb9c56882','棣華堂先大父國錄叔大父安撫教授之地堂前古桂巋然獨存花時踏月徘徊其下誦先君舊隠之詩次韻追感','吳錫疇','宋','宋诗','song-poetry','','[]','古桂吹香秋月明，當年曾聽讀書聲。',32,'全唐诗/poet.song.224000.json','["古桂吹香秋月明，當年曾聽讀書聲。", "角弓有賦門人在，邂逅猶須問悴榮。"]'),
('1a3ef6f5-e8be-4b4b-96c9-eb394977b1a5','醉吟','吳錫疇','宋','宋诗','song-poetry','','[]','一徑碧苔深，蕭閒幾醉吟。',48,'全唐诗/poet.song.224000.json','["一徑碧苔深，蕭閒幾醉吟。", "野花開自落，春色霽還陰。", "涉世謀多拙，逢人口欲瘖。", "門前流水浄，洗盡利名心。"]'),
('9bb5c14a-04b7-44dc-9bd5-8c2ec13745f1','山村問宿','吳錫疇','宋','宋诗','song-poetry','','[]','問宿山村裏，人烟斷復連。',48,'全唐诗/poet.song.224000.json','["問宿山村裏，人烟斷復連。", "高峰明落日，危石響幽泉。", "世事雙眉上，年華兩鬢邊。", "滄洲森萬玉，飛夢月娟娟。"]'),
('1bff570f-4c39-4c04-9039-89c1078db9ae','郡侯奏請爲先竹洲易名因送逢原入京','吳錫疇','宋','宋诗','song-poetry','','[]','一封奏入五雲開，褒錄儒先動九垓。',64,'全唐诗/poet.song.224000.json','["一封奏入五雲開，褒錄儒先動九垓。", "生意欲回洲上竹，好風已遞隴頭梅。", "誌銘標揭留幽隧，謚法昭彰在曲臺。", "去去片帆春水滑，捧持飛誥看歸來。"]'),
('d439321f-1166-473c-837c-1e4f7e3d28eb','友人有約未至','吳錫疇','宋','宋诗','song-poetry','','[]','梅破疏英餞歲華，尋梅有約過山家。',32,'全唐诗/poet.song.224000.json','["梅破疏英餞歲華，尋梅有約過山家。", "短窗昨夜占佳晤，挑盡寒燈未肯花。"]'),
('15e1202d-49fd-4939-b101-a80b1094939d','分題牡丹','吳錫疇','宋','宋诗','song-poetry','','[]','此花誰實與封王，公道東皇有品量。',64,'全唐诗/poet.song.224000.json','["此花誰實與封王，公道東皇有品量。", "宿露低垂蒼玉佩，暄風輕振紫羅裳。", "精神因爲得春久，富貴何妨到晚芳。", "醉把一枝簪帽側，從教人笑老夫狂。"]'),
('1ed0cb68-5da6-43e9-a06b-94914798edd6','荷葭塢呈秋崖方工部','吳錫疇','宋','宋诗','song-poetry','','[]','怕驚啼鳥推棋罷，爲愛落花迂屐行。',32,'全唐诗/poet.song.224000.json','["怕驚啼鳥推棋罷，爲愛落花迂屐行。", "窈窈綠雲春一塢，遊絲飛絮弄新晴。"]'),
('2cbde444-f478-4e6b-b79b-c6fa8b630b74','晚眺','吳錫疇','宋','宋诗','song-poetry','','[]','日未沈西月色東，一山秋葉染霜紅。',32,'全唐诗/poet.song.224000.json','["日未沈西月色東，一山秋葉染霜紅。", "鮮明恰勝春花好，不似春花耐得風。"]'),
('2ef8c861-6800-4ea5-a080-55daffb294d8','聞雁','吳錫疇','宋','宋诗','song-poetry','','[]','暮霞天角正紅酣，渺渺飛鳴雁兩三。',32,'全唐诗/poet.song.224000.json','["暮霞天角正紅酣，渺渺飛鳴雁兩三。", "萬里中原消息斷，頼能带得過江南。"]'),
('478fe439-6404-4c56-887c-2b6c7d3d6cd3','僮諭','吳錫疇','宋','宋诗','song-poetry','','[]','小隠生涯無別事，護持蓑笠傍鷗沙。',64,'全唐诗/poet.song.224000.json','["小隠生涯無別事，護持蓑笠傍鷗沙。", "清泉頻注吟邊硯，活火隨煎飯後茶。", "趁早須來添鶴料，便忙也去看梅花。", "焚香掃地齊書帙，客到鄰牆有酒賒。"]'),
('dce2a7b4-4223-4548-9d3a-934c48369bac','遇梅初花','吳錫疇','宋','宋诗','song-poetry','','[]','隴上無人寄一枝，疏花忽見喜生眉。',64,'全唐诗/poet.song.224000.json','["隴上無人寄一枝，疏花忽見喜生眉。", "巖稜面瘦霜明裏，瀟灑香寒月上時。", "比姑射仙同調度，與林逋老共襟期。", "孤芳不競能堅守，肯向離騷怨未知。"]'),
('35931bf5-afb8-4b60-923f-fd43c4e1de5f','秋日','吳錫疇','宋','宋诗','song-poetry','','[]','西風吹雨故將寒，斗室盤旋宇宙寬。',64,'全唐诗/poet.song.224000.json','["西風吹雨故將寒，斗室盤旋宇宙寬。", "蘆已成花衰鬢白，楓猶染葉醉容丹。", "人間歲月幾羊胛，身外勳名一鼠肝。", "領略秋光無限意，東籬閒掇落英餐。"]'),
('eb01e80f-8683-404f-beff-7893ee99bf40','聞笛','吳錫疇','宋','宋诗','song-poetry','','[]','乾坤沈萬籟，風露杳雙清。',48,'全唐诗/poet.song.224000.json','["乾坤沈萬籟，風露杳雙清。", "城近更初轉，山空月正明。", "攬裘寒意重，看劍壯心驚。", "迢遞誰家笛，淒涼此夜情。"]'),
('8ff2e9a6-1a30-412c-bbf7-730228efb463','楊花  其一','吳錫疇','宋','宋诗','song-poetry','','[]','爲見春風不久歸，顛狂上下弄晴暉。',32,'全唐诗/poet.song.224000.json','["爲見春風不久歸，顛狂上下弄晴暉。", "只饒天與無拘束，入幕穿簾任意飛。"]'),
('9d55ef92-7768-4e3c-978c-fd088c59bfba','楊花  其二','吳錫疇','宋','宋诗','song-poetry','','[]','飛舞隨春去不停，空條留得罩郵亭。',32,'全唐诗/poet.song.224000.json','["飛舞隨春去不停，空條留得罩郵亭。", "狂心未肯沾泥死，猶作輕浮水上萍。"]'),
('36ef246b-90ab-4b4a-8be6-9d3148253ee3','次韻答吳仲山','吳錫疇','宋','宋诗','song-poetry','','[]','聲利驅人萬轂忙，何如林下玩幽芳。',64,'全唐诗/poet.song.224000.json','["聲利驅人萬轂忙，何如林下玩幽芳。", "一池草色春不盡，半樹梅花月也香。", "古錦忽分詩眼巧，短牋難寄話頭長。", "相望正恨相逢晚，莫惜來過剪韭黄。"]'),
('079e621d-fdb2-4a28-a5ad-86b935d80153','舟中','吳錫疇','宋','宋诗','song-poetry','','[]','一笑起推篷，烟雲望眼中。',48,'全唐诗/poet.song.224000.json','["一笑起推篷，烟雲望眼中。", "艣鳴無調樂，帆飽有情風。", "山近水偏綠，鵑啼花正紅。", "前途足奇觀，行色莫怱怱。"]'),
('e4726bdf-ba1e-488c-9364-3cf73ef32851','次韻題純老房竹','吳錫疇','宋','宋诗','song-poetry','','[]','有竹便不俗，蕭疏三數竿。',48,'全唐诗/poet.song.224000.json','["有竹便不俗，蕭疏三數竿。", "雲深茶竈濕，雨過佛燈寒。", "紀壁何年種，停經了日看。", "塵勞應可滌，幾欲借薄團。"]'),
('2fb499f5-529d-4b79-9987-5df9adfa92ef','元日','吳錫疇','宋','宋诗','song-poetry','','[]','寂寞柴門賀客疏，已輸漸後飲屠蘇。',64,'全唐诗/poet.song.224000.json','["寂寞柴門賀客疏，已輸漸後飲屠蘇。", "花情柳思開新歲，竹簡蒲團只故吾。", "獻楚有誰能辨玉，求齊正自不工竽。", "朝來笑挽春風問，亦解重青兩鬢無。"]'),
('c162f7c7-52c2-488a-b894-62fe10dab1e5','臨川憶舊','吳錫疇','宋','宋诗','song-poetry','','[]','漫浪同爲逆旅人，倏然離合入思頻。',64,'全唐诗/poet.song.224000.json','["漫浪同爲逆旅人，倏然離合入思頻。", "清明上巳多愁雨，芍藥荼䕷各殿春。", "不改交情山翠舊，漸添老色鬢華新。", "近來世念寒烟薄，已辦青蓑理釣綸。"]'),
('1d5abf66-ff95-4e15-bb16-aa909b9e5ef8','擘蟹','吳錫疇','宋','宋诗','song-poetry','','[]','寒蒲就縛失橫行，已矣甘從五鼎烹。',64,'全唐诗/poet.song.224000.json','["寒蒲就縛失橫行，已矣甘從五鼎烹。", "憑恃甲戈名以躁，貯藏風露敗於清。", "蘆花洲冷霜威健，竹葉杯深飲興生。", "且與老饕成後賦，正須一笑付薑橙。"]'),
('a5a25a2b-73ee-4d12-b04e-5c6bff495381','次韻逢原偶興','吳錫疇','宋','宋诗','song-poetry','','[]','曾共清燈坐夜闌，依然故我只儒酸。',64,'全唐诗/poet.song.224000.json','["曾共清燈坐夜闌，依然故我只儒酸。", "昏眸但覺看山易，倦足方知行路難。", "捫虱坐談思傲睨，聞雞起舞歎衰殘。", "閒中恰續無功記，以醉爲鄉儘自寬。"]'),
('9600ab7b-ba7c-4e6a-a626-87b6ce0614ec','晚晴','吳錫疇','宋','宋诗','song-poetry','','[]','雨脚風收斷，斜陽漏晚天。',48,'全唐诗/poet.song.224000.json','["雨脚風收斷，斜陽漏晚天。", "徑蕪蛙張王，花霽蝶輕儇。", "畫思平林外，詩情步屧邊。", "無山將亦隠，底用買山錢。"]'),
('99a773a3-4492-4dd9-8a96-25e89830c9d8','還友人詩卷','吳錫疇','宋','宋诗','song-poetry','','[]','壇荒杜陵後，何以續詩名。',48,'全唐诗/poet.song.224000.json','["壇荒杜陵後，何以續詩名。", "千里江山秀，一襟風露清。", "淡中無淺短，豪處有和平。", "細讀松間集，如聞雅奏聲。"]'),
('e56f4d6f-22e5-44eb-a2d9-9af2ede191a8','籠鶴','吳錫疇','宋','宋诗','song-poetry','','[]','本是雲霄萬里身，樊籠著向綠槐陰。',32,'全唐诗/poet.song.224000.json','["本是雲霄萬里身，樊籠著向綠槐陰。", "雖然祿料曾無欠，孤却寬閒自在心。"]'),
('44b2c554-9720-465a-bc0e-d42f8955a688','送春  其一','吳錫疇','宋','宋诗','song-poetry','','[]','紅襯晴霞一角天，小樓重上眺前川。',32,'全唐诗/poet.song.224000.json','["紅襯晴霞一角天，小樓重上眺前川。", "莫言春去無蹤迹，盡在枝頭嫩綠邊。"]'),
('b6cac440-42c7-4afa-8f46-77438016ac7e','送春  其二','吳錫疇','宋','宋诗','song-poetry','','[]','惆悵春歸自不禁，日長門巷靜沈沈。',32,'全唐诗/poet.song.224000.json','["惆悵春歸自不禁，日長門巷靜沈沈。", "應知不止爲花地，沃沃桑麻雨露深。"]'),
('0b387da1-0a90-4811-9d07-c173db304603','送春  其三','吳錫疇','宋','宋诗','song-poetry','','[]','新綠迴環暗竹扉，靜中物物總天機。',32,'全唐诗/poet.song.224000.json','["新綠迴環暗竹扉，靜中物物總天機。", "啼鶑戲蝶渾如舊，莫是春風尚未歸。"]'),
('1535a56a-441c-4650-852f-0ef6e9ba2e1f','九日集客','吳錫疇','宋','宋诗','song-poetry','','[]','佳節欲酬須酩酊，東籬不記幾飛觴。',64,'全唐诗/poet.song.224000.json','["佳節欲酬須酩酊，東籬不記幾飛觴。", "從教烏帽吹將去，且對黄花領取香。", "世事漫勞三太息，人生寬破百重陽。", "英雄蓋代今何在，戲馬高臺久已荒。"]'),
('05243479-4dfb-40e7-8c04-1b5d0c739168','聽雨','吳錫疇','宋','宋诗','song-poetry','','[]','細細檐花雨，青燈耿客魂。',48,'全唐诗/poet.song.224000.json','["細細檐花雨，青燈耿客魂。", "輕烟騰柏子，流水響桐孫。", "日月雙車轂，乾坤一酒樽。", "螘柯分已定，人自苦追奔。"]'),
('0ec1bbc1-dee6-4465-a4cb-400fe9390db4','次韻謝元壽','吳錫疇','宋','宋诗','song-poetry','','[]','曾被儒冠誤，謀生事事疏。',48,'全唐诗/poet.song.224000.json','["曾被儒冠誤，謀生事事疏。", "洲無千樹橘，家有五車書。", "疊石和苔斸，移梅带雪鋤。", "好非人所好，習氣未能除。"]'),
('90be79a1-5dcd-4e3f-bec4-497688975cca','贈寫照陳生','吳錫疇','宋','宋诗','song-poetry','','[]','燕頷鳶肩總屬夫，幾何人得上凌烟。',32,'全唐诗/poet.song.224000.json','["燕頷鳶肩總屬夫，幾何人得上凌烟。", "且煩寫在山巖裏，野服黄冠看瀑泉。"]'),
('cd15b607-b36f-44ab-8ae5-c9dbf148de9a','山中雜言  其一','吳錫疇','宋','宋诗','song-poetry','','[]','小小柴門傍竹開，幽深不慣有人來。',32,'全唐诗/poet.song.224000.json','["小小柴門傍竹開，幽深不慣有人來。", "頗嫌老鶴無情思，啄損庭前一徑苔。"]'),
('3682c2c2-f1b6-4e8c-a6f4-be5213f8914b','山中雜言  其二','吳錫疇','宋','宋诗','song-poetry','','[]','老作山翁行輩人，素衣曾不化京塵。',32,'全唐诗/poet.song.224000.json','["老作山翁行輩人，素衣曾不化京塵。", "只應猿鶴無驚怨，從自龍蛇有屈伸。"]'),
('a7d8a0d9-d9a3-40b6-9032-1024e9f5360f','山中雜言  其三','吳錫疇','宋','宋诗','song-poetry','','[]','數家雞犬小成村，一带岡巒近入門。',32,'全唐诗/poet.song.224000.json','["數家雞犬小成村，一带岡巒近入門。", "怕有漁人來問訊，溪流那得截雲根。"]'),
('4431f1ab-af33-4b4f-a0fc-88cc816c4551','山中雜言  其四','吳錫疇','宋','宋诗','song-poetry','','[]','草色侵除雨後深，天教閒靜在山林。',32,'全唐诗/poet.song.224000.json','["草色侵除雨後深，天教閒靜在山林。", "無田種秫供桑落，有地栽蘭當水沈。"]'),
('03f362f0-cbfe-49bf-aacf-8ae18fc9398e','山中雜言  其五','吳錫疇','宋','宋诗','song-poetry','','[]','移春有檻遍京華，剩種人間富貴花。',32,'全唐诗/poet.song.224000.json','["移春有檻遍京華，剩種人間富貴花。", "誰識山中窮活計，眼前沃沃只桑麻。"]'),
('d36370d3-a2df-46ab-8b65-47af254ca526','山中雜言  其六','吳錫疇','宋','宋诗','song-poetry','','[]','得失升沈是與非，紛紛世上局如棋。',32,'全唐诗/poet.song.224000.json','["得失升沈是與非，紛紛世上局如棋。", "白雲谷口橫遮斷，萬事山中總不知。"]'),
('19e483af-03e4-4919-8762-08d1370b890f','山中雜言  其七','吳錫疇','宋','宋诗','song-poetry','','[]','謬有生涯類蠹魚，蕭然四壁一牀書。',32,'全唐诗/poet.song.224000.json','["謬有生涯類蠹魚，蕭然四壁一牀書。", "兒曹未信儒冠誤，猶事青燈廢耒鋤。"]'),
('be2c48ff-edfc-4df8-ba29-f0d7f6bac4bc','次韻題璜原僧舍','吳錫疇','宋','宋诗','song-poetry','','[]','魚鼓無聲晝閴沈，荒碑積雨古苔侵。',32,'全唐诗/poet.song.224000.json','["魚鼓無聲晝閴沈，荒碑積雨古苔侵。", "忽飛寒雀窺齋鉢，偶有馴猿聽梵音。"]'),
('a7b169ef-71b4-4dda-adde-965013173c03','寂寂','吳錫疇','宋','宋诗','song-poetry','','[]','寂寂閉門坐，身閒心太平。',48,'全唐诗/poet.song.224000.json','["寂寂閉門坐，身閒心太平。", "豆花含雨重，梧葉坐秋鳴。", "道路風波惡，山林夢寐清。", "少狂無復在，未減是詩情。"]'),
('7f7f34de-e49b-4f9c-8ada-e168ecf967d1','鸂鶒','吳錫疇','宋','宋诗','song-poetry','','[]','滿身文彩漫成愁，一曲清池强滯留。',32,'全唐诗/poet.song.224000.json','["滿身文彩漫成愁，一曲清池强滯留。", "翹足有時雙睡去，夢魂依舊繞滄洲。"]'),
('aad4311f-3820-48c5-8197-80d0645015d9','桂花','吳錫疇','宋','宋诗','song-poetry','','[]','許多香却不多花，灝氣浮空月滿家。',32,'全唐诗/poet.song.224000.json','["許多香却不多花，灝氣浮空月滿家。", "明日石壇金屑富，旋收賸馥入龍茶。"]'),
('0c060c60-586e-4e92-b069-ca92dec4e1c3','次韻寫興','吳錫疇','宋','宋诗','song-poetry','','[]','不學韓公咎斗牛，此心無愧許沙鷗。',64,'全唐诗/poet.song.224000.json','["不學韓公咎斗牛，此心無愧許沙鷗。", "陰晴明日自難料，得失頻年已熟籌。", "癡計空爲千載慮，虛名翻誤一生憂。", "閒中菘韭皆真味，絕勝羊腔進膳羞。"]'),
('79e21616-02c6-468e-a68f-ede71f81582e','老境','吳錫疇','宋','宋诗','song-poetry','','[]','老境已駸駸，功名負壯心。',48,'全唐诗/poet.song.224000.json','["老境已駸駸，功名負壯心。", "昏眸雲霧隔，短鬢雪霜侵。", "身爲貧長客，詩因病懶吟。", "春山歸未得，門徑蘚花深。"]'),
('fc8c0a7b-040e-4f2a-b4a2-54696e6464d3','客枕聞鵑','吳錫疇','宋','宋诗','song-poetry','','[]','烟新寒食過，月皎子規來。',48,'全唐诗/poet.song.224000.json','["烟新寒食過，月皎子規來。", "萬里他鄉恨，千年故國哀。", "窗深敧枕聽，夢短到家回。", "爲爾添愁寂，春風不耐催。"]'),
('00337b0f-28bf-4b0d-b7da-1531a7a2eda0','尋梅','吳錫疇','宋','宋诗','song-poetry','','[]','迤邐尋梅過別村，歸來新月照黄昏。',32,'全唐诗/poet.song.224000.json','["迤邐尋梅過別村，歸來新月照黄昏。", "更無可覓春風面，撚斷冰髭立斷魂。"]'),
('96bd2d17-aadc-45ad-b0b1-83ee5d686ebb','晚春喜友人至','吳錫疇','宋','宋诗','song-poetry','','[]','柳門竹巷靜生苔，節序俄驚物物催。',64,'全唐诗/poet.song.224000.json','["柳門竹巷靜生苔，節序俄驚物物催。", "一雨拉將寒食過，百花讓與牡丹開。", "若爲繾綣留春日，正可淋漓縱酒杯。", "呼舞忽聞猿鶴喜，兒童忙報故人來。"]'),
('ea8cdda0-d7da-4e1a-894d-544a676dfa06','竹洲重葺仁壽堂','吳錫疇','宋','宋诗','song-poetry','','[]','抗章當日勇辭榮，三詠循陔世念輕。',64,'全唐诗/poet.song.224000.json','["抗章當日勇辭榮，三詠循陔世念輕。", "娛悅高堂仁者壽，壅培遺植聖之清。", "雲涵翠葆添新蔭，秋逼青琅戛舊聲。", "故址依然成棟宇，水心題扁尚晶明。"]'),
('471c11fd-843e-4b08-b18f-ac4b16b5832d','雨中過昱嶺','吳錫疇','宋','宋诗','song-poetry','','[]','下輿扶杖過山蹊，雨濺征裾屐濺泥。',32,'全唐诗/poet.song.224000.json','["下輿扶杖過山蹊，雨濺征裾屐濺泥。", "正自不禁行路苦，一聲何處竹雞啼。"]'),
('cb66b2ef-2525-42a7-8d89-2cae91449330','湖上聞鵑','吳錫疇','宋','宋诗','song-poetry','','[]','湧金門外買湖船，綠樹陰陰叫杜鵑。',32,'全唐诗/poet.song.224000.json','["湧金門外買湖船，綠樹陰陰叫杜鵑。", "恰莫叫從城裏去，有誰人肯辦歸田。"]'),
('3abd10ca-107f-4a12-b830-3ab3d4ee821c','獨酌','吳錫疇','宋','宋诗','song-poetry','','[]','獨酌悠然醉，應無語笑譁。',48,'全唐诗/poet.song.224000.json','["獨酌悠然醉，應無語笑譁。", "百年柯上螘，萬事琖中蛇。", "詩定重刪草，燈挑又作花。", "不煩眠遣客，長嘯岸烏紗。"]'),
('561ce3a9-1d19-4cee-b2d5-5f5634a48d04','秋懷','吳錫疇','宋','宋诗','song-poetry','','[]','雁聲叫斷一天秋，寒氣憑陵季子裘。',64,'全唐诗/poet.song.224000.json','["雁聲叫斷一天秋，寒氣憑陵季子裘。", "莫恨蛾眉偏薄命，曾知猿臂自難侯。", "繞黄花有詩消遣，持紫螯兼酒拍浮。", "未用淒涼如宋玉，月明清思滿前洲。"]'),
('330ebc9e-aa44-4941-9608-25e6371a2ad7','悼鶴','吳錫疇','宋','宋诗','song-poetry','','[]','乘化歸遼海，雙籠一不開。',48,'全唐诗/poet.song.224000.json','["乘化歸遼海，雙籠一不開。", "墜翎留片雪，遺迹印荒苔。", "月朗憐孤唳，琴閒憶共來。", "瘞銘爲琢石，雞鶩不須猜。"]'),
('dd08b19e-0f12-4748-ab96-94bb39b3e87a','次韻孫艮夫贈別  其一','吳錫疇','宋','宋诗','song-poetry','','[]','第一江山第一程，新詩快讀逼梅清。',32,'全唐诗/poet.song.224000.json','["第一江山第一程，新詩快讀逼梅清。", "碧雲不斷飛帆急，立盡檣竿晚日明。"]'),
('31fcc7e8-de9f-4d66-8a66-4a03698cabdb','次韻孫艮夫贈別  其二','吳錫疇','宋','宋诗','song-poetry','','[]','揚子江頭欵乃歌，一天星斗絡斜河。',32,'全唐诗/poet.song.224000.json','["揚子江頭欵乃歌，一天星斗絡斜河。", "怕無才思堪風月，拾入奚囊未必多。"]'),
('9a7869db-7095-443b-9cb8-f59094134f62','次韻葉介夫','吳錫疇','宋','宋诗','song-poetry','','[]','芳草垂楊浥嫩寒，苔痕新過雨斑斑。',64,'全唐诗/poet.song.224000.json','["芳草垂楊浥嫩寒，苔痕新過雨斑斑。", "一年春付花開落，長日庭分燕往還。", "世事祇堪頻對酒，詩情自可飽看山。", "儘窮莫用文爲送，郊島曾容季孟間。"]'),
('1a99f7c1-06e1-4534-9de5-d72d5bb870b9','秋夜','吳錫疇','宋','宋诗','song-poetry','','[]','寂寂虛堂風露涼，邊聲驚聽雁南翔。',64,'全唐诗/poet.song.224000.json','["寂寂虛堂風露涼，邊聲驚聽雁南翔。", "短筇夢涉秋三逕，長笛思乘月一航。", "老眼添昏如濁鏡，吟懷多感類寒螿。", "久知拙不趁時樣，肯羨東鄰鬭靚妝。"]'),
('e1f2ddf9-9c41-4201-886b-648525e85101','荆溪舟中對月','吳錫疇','宋','宋诗','song-poetry','','[]','歷眼旬餘半，終宵月在天。',48,'全唐诗/poet.song.224000.json','["歷眼旬餘半，終宵月在天。", "若將今歲看，僅有此番圓。", "寒逼鴻洲外，光摇螘甕邊。", "家山千里遠，應共一嬋娟。"]'),
('a395d4c2-c98a-4974-a2ce-5a1a157c8ada','姑蘇晚泊','吳錫疇','宋','宋诗','song-poetry','','[]','有味吟邊景，無愁醉裏身。',48,'全唐诗/poet.song.224000.json','["有味吟邊景，無愁醉裏身。", "如何連夜夢，只是到家頻。", "更永遲留月，梅寒漏泄春。", "吳王臺下泊，訪古待清晨。"]'),
('9338c58e-19ad-4e7d-a3e1-4cdb47494492','山行','吳錫疇','宋','宋诗','song-poetry','','[]','策蹇又山行，看山不識名。',48,'全唐诗/poet.song.224000.json','["策蹇又山行，看山不識名。", "平林秋後薄，疊嶂日邊明。", "雲近侵衣濕，泉幽照影清。", "歸樵饒樂意，笛弄兩三聲。"]'),
('df1e52f5-1007-4f65-afda-79e30320687a','醉起','吳錫疇','宋','宋诗','song-poetry','','[]','水宿篙師報歇程，維舟聊此問旗亭。',32,'全唐诗/poet.song.224000.json','["水宿篙師報歇程，維舟聊此問旗亭。", "醉來頓覺鄉愁失，苦被霜風吹又醒。"]'),
('f39c4fcf-ebf0-432c-9a66-03a0e2448cdb','嚴灘','吳錫疇','宋','宋诗','song-poetry','','[]','極目飛鴻外，蒼茫一渺然。',48,'全唐诗/poet.song.224000.json','["極目飛鴻外，蒼茫一渺然。", "風清垂釣瀨，月淡放梅天。", "展卷評詩句，探囊結酒緣。", "舟中無此樂，但只閉篷眠。"]'),
('5a7ce139-04fb-4f14-a2cd-88538f4ffbdd','新城','吳錫疇','宋','宋诗','song-poetry','','[]','短棹泊新城，江寬風易生。',48,'全唐诗/poet.song.224000.json','["短棹泊新城，江寬風易生。", "帆隨潮共上，烟接岸俱平。", "冷蕊江南信，孤鴻塞北聲。", "詩成休朗誦，怕有老龍驚。"]'),
('74a6bed3-2a2c-4d4a-82a5-6cf577e3a7b8','晚山','吳錫疇','宋','宋诗','song-poetry','','[]','晚山欣靜對，杳杳碧無垠。',48,'全唐诗/poet.song.224000.json','["晚山欣靜對，杳杳碧無垠。", "病葉明殘照，飛鴻带斷雲。", "自憐麋鹿性，宜入鷺鷗群。", "世路多殊轍，升沈迹已分。"]'),
('14d2e1d4-9d61-46f1-ad2b-421361e6ff9d','夜感','吳錫疇','宋','宋诗','song-poetry','','[]','少年未識隄防老，不辦坡翁大字書。',64,'全唐诗/poet.song.224000.json','["少年未識隄防老，不辦坡翁大字書。", "猶有壯心躭萬卷，其如昏目負三餘。", "睡遲祇怕中宵覺，交淡從教俗軌疏。", "瞑坐漫搜詩撥遣，靈臺一片炯如初。"]'),
('fdfb8a50-b2f9-4971-9f7e-f3669a351bea','憑欄','吳錫疇','宋','宋诗','song-poetry','','[]','劉伯龍如鬼笑何，居然幻境螘南柯。',64,'全唐诗/poet.song.224000.json','["劉伯龍如鬼笑何，居然幻境螘南柯。", "世間知止人應少，天下難言事最多。", "梧葉淒涼依節序，雁聲依約自關河。", "憑欄莫起悲秋意，老色何妨借酒酡。"]'),
('0f3a8932-3582-4e29-a866-387de3fb26e0','無弦古琴','吳錫疇','宋','宋诗','song-poetry','','[]','寥寥誰是識琴心，得趣元來不在音。',32,'全唐诗/poet.song.224000.json','["寥寥誰是識琴心，得趣元來不在音。", "可惜伯牙猶未達，絕弦當日恨徒深。"]'),
('2f9c551d-cdd5-4f3b-81f0-6f2e1e12c212','偶成  其一','吳錫疇','宋','宋诗','song-poetry','','[]','酒能成病姑停飲，詩怕傷時莫浪吟。',32,'全唐诗/poet.song.224000.json','["酒能成病姑停飲，詩怕傷時莫浪吟。", "客又不來春欲去，一簾花影哢鳴琴。"]'),
('71fb2e12-bca1-4026-bf5f-1295b4e0fcd3','偶成  其二','吳錫疇','宋','宋诗','song-poetry','','[]','釀蜜山蜂初割戶，銜泥梁燕已成家。',32,'全唐诗/poet.song.224000.json','["釀蜜山蜂初割戶，銜泥梁燕已成家。", "春愁漠漠連芳草，閒過東園數落花。"]'),
('5550400b-9c5d-480d-9688-7a589b1c7db0','多景樓','吳錫疇','宋','宋诗','song-poetry','','[]','欄干投北是神州，莫怪諸公怯上樓。',32,'全唐诗/poet.song.224000.json','["欄干投北是神州，莫怪諸公怯上樓。", "千載潮聲如有恨，猶能含怒到瓜洲。"]'),
('940212af-fda6-470e-b083-25c9b93d5ac8','姑蘇臺','吳錫疇','宋','宋诗','song-poetry','','[]','歌舞聲消迹已陳，危臺今日壓城闉。',32,'全唐诗/poet.song.224000.json','["歌舞聲消迹已陳，危臺今日壓城闉。", "麋遊莫恨終亡國，誰把鴟夷載諫臣。"]'),
('eeabe53f-6930-49bd-8a70-6d1160f33821','三高祠','吳錫疇','宋','宋诗','song-poetry','','[]','去越思吳居甫里，並祠千載說三高。',32,'全唐诗/poet.song.224000.json','["去越思吳居甫里，並祠千載說三高。", "到頭杞菊饒餘味，不涉人間富貴勞。"]'),
('81b3762c-ac22-4c8b-bc33-7887613f05f5','旅舟度歲呈范堯臣','吳錫疇','宋','宋诗','song-poetry','','[]','柏琖椒盤且罷休，呂蒙城下泊孤舟。',64,'全唐诗/poet.song.224000.json','["柏琖椒盤且罷休，呂蒙城下泊孤舟。", "昏燈獨照還鄉夢，久客新添別歲愁。", "爆竹無聲驚寂寞，梅花有意伴淹留。", "明朝例是加年事，不信公侯不白頭。"]'),
('1ea3d171-7728-4ced-9d59-2c93e4102215','夏日','吳錫疇','宋','宋诗','song-poetry','','[]','雨作年豐計，涼爲午睡媒。',48,'全唐诗/poet.song.224000.json','["雨作年豐計，涼爲午睡媒。", "不煩思飲露，已可洗飛埃。", "延月簾高捲，看山牖盡開。", "心閒逢事懶，褦襶且休來。"]'),
('9dd519bf-349b-499d-97db-027134dd3580','菊邊持螯','吳錫疇','宋','宋诗','song-poetry','','[]','奔火狂難改，橫戈事已非。',48,'全唐诗/poet.song.224000.json','["奔火狂難改，橫戈事已非。", "形模雖可怪，風味故應稀。", "玉斫雙螯潔，金披一殻肥。", "持杯籬菊畔，又見醉忘歸。"]'),
('c9f6c79e-f483-4494-9238-a16e6a95856a','對月有懷','吳錫疇','宋','宋诗','song-poetry','','[]','破晴斜月入簾陰，鬢影蕭騷老不禁。',64,'全唐诗/poet.song.224000.json','["破晴斜月入簾陰，鬢影蕭騷老不禁。", "九十日春風與雨，百千年事後猶今。", "牡丹紅褪殘妝面，杜宇聲寒故國心。", "眼底交游期又誤，飛鴻杳杳鯉沈沈。"]'),
('a424f8ae-ad60-48d6-adad-46f50f2f23ad','哭趙成德','吳錫疇','宋','宋诗','song-poetry','','[]','鶴悵東巖夜，聲悲不可聞。',48,'全唐诗/poet.song.224000.json','["鶴悵東巖夜，聲悲不可聞。", "有圖留水月，無句管烟雲。", "身後空傳稿，生前事作墳。", "忍思携手日，濺淚漫紛紛。"]'),
('d6815a7b-b5a2-4991-bcc7-48690f753b1e','重午於潛道中','吳錫疇','宋','宋诗','song-poetry','','[]','逢人篸艾知重午，漫把青錢問酒杯。',32,'全唐诗/poet.song.224000.json','["逢人篸艾知重午，漫把青錢問酒杯。", "豈是醉狂慵弔古，獨醒不禁客愁來。"]'),
('05e1e0c3-cd85-4ade-aa96-c3f69ac44926','六和塔','吳錫疇','宋','宋诗','song-poetry','','[]','直上浮屠最上頭，茫茫渺渺入雙眸。',32,'全唐诗/poet.song.224000.json','["直上浮屠最上頭，茫茫渺渺入雙眸。", "斜陽斷雁新秋意，惹起西風一段愁。"]'),
('078b9ae0-39e3-4233-8202-f17d04c256ea','次韻汪仁甫','吳錫疇','宋','宋诗','song-poetry','','[]','斜河炯炯雁飛飛，老却斯人天未知。',64,'全唐诗/poet.song.224000.json','["斜河炯炯雁飛飛，老却斯人天未知。", "三逕秋光猶在菊，一年心事可無詩。", "歲華迅似離弦箭，愁思多於盈杼絲。", "寂寂空山明月裏，誰拈霜竹倚風吹。"]'),
('c8b92849-0631-4000-a36c-d53894e332cf','結屋','吳錫疇','宋','宋诗','song-poetry','','[]','結屋須教坐對山，把茅纔此有三間。',64,'全唐诗/poet.song.224000.json','["結屋須教坐對山，把茅纔此有三間。", "澆花抱甕調停懶，洗硯裁牋準備閒。", "未問丹砂能蛻骨，久知綠酒可酡顔。", "江湖浪迹成何事，抖擻歸囊句不慳。"]'),
('f536b084-ca36-4749-8a9f-ff4ff52897ac','夜雨','吳錫疇','宋','宋诗','song-poetry','','[]','漠漠春陰未肯晴，空階滴點到平明。',32,'全唐诗/poet.song.224000.json','["漠漠春陰未肯晴，空階滴點到平明。", "應知不入笙歌耳，來作愁人枕畔聲。"]'),
('1fab28f3-b15a-4689-b8d8-e299a0aa90ae','客思','吳錫疇','宋','宋诗','song-poetry','','[]','淹留爲客久，蕭散與心違。',48,'全唐诗/poet.song.224000.json','["淹留爲客久，蕭散與心違。", "妻病家緣廢，奴逃書問稀。", "雨荒招鶴逕，苔滑釣魚磯。", "愧爾汀頭鷺，滄波自在飛。"]'),
('94a8c903-6f87-4b21-902d-042513f3227b','藍溪道中','吳錫疇','宋','宋诗','song-poetry','','[]','綠窈雨初歇，清和日正長。',48,'全唐诗/poet.song.224000.json','["綠窈雨初歇，清和日正長。", "乳禽穿薄靄，弱蔓上頹牆。", "村市筍厨美，田家麰餌香。", "老翁扶杖出，小立看移秧。"]'),
('a9aeded8-e2e3-4716-9493-a26d1a4ecd66','看山','吳錫疇','宋','宋诗','song-poetry','','[]','一寒未辦買山貲，隨處看山總可詩。',32,'全唐诗/poet.song.224000.json','["一寒未辦買山貲，隨處看山總可詩。", "人事無常山換主，青山依舊不曾移。"]'),
('7755430d-3dbe-4b37-a19a-05136814907f','秋來','吳錫疇','宋','宋诗','song-poetry','','[]','秋來病葉不禁風，漸覺虛檐墜片紅。',64,'全唐诗/poet.song.224000.json','["秋來病葉不禁風，漸覺虛檐墜片紅。", "斜日半溪人喚渡，斷雲千里雁橫空。", "詩情得似馴鷗子，世事徐觀失馬翁。", "忻戚莫將爲我役，此懷拍拍自春融。"]'),
('82a3bae1-4c06-42fb-af00-eb9a1a684962','九日','吳錫疇','宋','宋诗','song-poetry','','[]','九日今朝是，風吹帽欲斜。',48,'全唐诗/poet.song.224000.json','["九日今朝是，風吹帽欲斜。", "愁惟添白髮，貧莫負黄花。", "蟹上橙初熟，秋登酒易賒。", "茱萸休把玩，且辦醉生涯。"]'),
('929feed6-717d-4e27-b1b4-9d7461ed8112','江氏靜山堂','吳錫疇','宋','宋诗','song-poetry','','[]','一炷清香萬疊山，依仁體艮寂然間。',32,'全唐诗/poet.song.224000.json','["一炷清香萬疊山，依仁體艮寂然間。", "油雲自去爲霖雨，千古蒼蒼只恁閒。"]'),
('01eb1d2a-b61a-49af-bb1a-0a93de4db169','楚東歲暮','吳錫疇','宋','宋诗','song-poetry','','[]','樓高霜冷漏聲遲，獨立闌干憶別離。',64,'全唐诗/poet.song.224000.json','["樓高霜冷漏聲遲，獨立闌干憶別離。", "明月一奩磨後鏡，疏星幾點劫殘棋。", "歲寒時節難爲客，老日頭顱盡付詩。", "頗覺淒涼無晤語，臨風說與凍梅知。"]'),
('7047f85d-e303-41da-ba6b-ed7b8077831f','重題釣臺','吳錫疇','宋','宋诗','song-poetry','','[]','不向雲臺戀故袍，清風固自釣臺高。',32,'全唐诗/poet.song.224000.json','["不向雲臺戀故袍，清風固自釣臺高。", "渭川八十年烟雨，豈是漁竿把不牢。"]'),
('46b8e5a6-0584-4c9f-9494-540a4696321c','除夜  其一','吳錫疇','宋','宋诗','song-poetry','','[]','日月跳丸歲又除，書生作計太迂疏。',32,'全唐诗/poet.song.224000.json','["日月跳丸歲又除，書生作計太迂疏。", "也知窮鬼難驅逐，鬰壘神荼莫用渠。"]'),
('6d51a593-6a3e-48d5-a742-7b8c65e74ad7','除夜  其二','吳錫疇','宋','宋诗','song-poetry','','[]','守歲兒童語笑頻，老翁醉擁地爐春。',32,'全唐诗/poet.song.224000.json','["守歲兒童語笑頻，老翁醉擁地爐春。", "欠伸起喚梅花說，明日平頭五十人。"]'),
('8a21ac0c-d3b7-4a2b-a018-f3ca24ad6829','冬日  其一','吳錫疇','宋','宋诗','song-poetry','','[]','日薄霜清水見沙，水邊偶到野人家。',32,'全唐诗/poet.song.224000.json','["日薄霜清水見沙，水邊偶到野人家。", "滿階風葉渾慵掃，爲愛深紅似落花。"]'),
('c089b54d-a070-4955-b849-bbdce115b7bc','冬日  其二','吳錫疇','宋','宋诗','song-poetry','','[]','夕陽孤倚立溪頭，三兩漁舟遡碧流。',32,'全唐诗/poet.song.224000.json','["夕陽孤倚立溪頭，三兩漁舟遡碧流。", "驚起一行新宿雁，斜飛又過別汀洲。"]'),
('eb292559-e520-471c-8da2-82d0fa8675f8','冬日  其三','吳錫疇','宋','宋诗','song-poetry','','[]','誰人雅趣似林逋，繞屋栽梅入畫圖。',32,'全唐诗/poet.song.224000.json','["誰人雅趣似林逋，繞屋栽梅入畫圖。", "淡日籠晴霜轉暖，從頭看過有花無。"]'),
('61d3f6d3-7f4d-4490-bf06-f8441114a14b','癸酉元日','吳錫疇','宋','宋诗','song-poetry','','[]','一聲爆竹又驚春，荼壘中間寫此心。',64,'全唐诗/poet.song.224000.json','["一聲爆竹又驚春，荼壘中間寫此心。", "忽忽行年周六甲，便便癡腹擬三壬。", "酒泉郡裏寧甘飲，飯顆山頭尚苦吟。", "强健得閒元是福，何妨終老住雲林。"]'),
('8ff15e78-fc0a-47d4-842c-e1d93f99e8dd','琴枕','吳錫疇','宋','宋诗','song-poetry','','[]','三尺焦桐稱醉眠，邯鄲底用遇囘仙。',32,'全唐诗/poet.song.224000.json','["三尺焦桐稱醉眠，邯鄲底用遇囘仙。", "夢中髣髴聞流水，元是山間響瀑泉。"]'),
('e3a26860-cde8-402a-b730-56b4c017fff8','別吳仲俊','吳錫疇','宋','宋诗','song-poetry','','[]','背人春事水趁東，淺紫深紅次第空。',64,'全唐诗/poet.song.224000.json','["背人春事水趁東，淺紫深紅次第空。", "宿靄未乾桑葉雨，薄羅初試楝花風。", "詩聯鍛鍊微吟裏，豪氣施行半醉中。", "此去相逢堪幾度，別懷作惡老來同。"]'),
('0c093943-e270-4244-85b4-918c35b31e5c','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其一','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，扶藜步晚晴。',48,'全唐诗/poet.song.224000.json','["我愛山居好，扶藜步晚晴。", "俗醇存古意，境寂快詩情。", "杜老銀絲膾，坡翁玉糝羹。", "隨緣清供足，儘可佚餘生。"]'),
('fd3a1752-0556-420d-bc30-6d6afc804e20','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其二','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，蔬畦間蒔花。',48,'全唐诗/poet.song.224000.json','["我愛山居好，蔬畦間蒔花。", "筧泉歸爨舍，篝火乞鄰家。", "茁嫩貓頭筍，焙芳雀舌茶。", "野人曾拜號，何用給黄麻。"]'),
('ca8007e1-796b-40b2-bf55-7e66594f4b2b','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其三','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，乾坤自在身。',48,'全唐诗/poet.song.224000.json','["我愛山居好，乾坤自在身。", "林泉睎隠士，風月謚閒人。", "村釀添春困，庖蔬勝鼎珍。", "幾携蓑笠去，保社在鷗津。"]'),
('db0d0f9c-9b6c-47f5-b6d8-f1a9cfca21c1','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其四','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，軒窗傍水開。',48,'全唐诗/poet.song.224000.json','["我愛山居好，軒窗傍水開。", "遊鱼吹墮絮，閒鶴啄荒苔。", "有字人誰問，無租吏不來。", "寂寥門逕側，數尺長蒿萊。"]'),
('e5376c3b-2a61-4963-9876-4095b0d8b38f','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其五','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，陶然與世忘。',48,'全唐诗/poet.song.224000.json','["我愛山居好，陶然與世忘。", "細聽泉潄玉，那羨珮鳴璫。", "乳燕飛閒宇，新篁出矮牆。", "靜觀機不息，天地爲誰忙。"]'),
('07ebe0ee-ce36-4f69-b549-d99c339cae0d','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其六','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，崖雲濕爨烟。',48,'全唐诗/poet.song.224000.json','["我愛山居好，崖雲濕爨烟。", "琴橫雙鶴舞，犁閣一牛眠。", "酒熟花開日，詩成雨霽天。", "逢場聊適意，總結喜歡緣。"]'),
('fe38c4a7-bcb5-42e8-8dcc-41555ff52d79','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其七','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，枌榆老故丘。',48,'全唐诗/poet.song.224000.json','["我愛山居好，枌榆老故丘。", "好峰當戶立，遠水護田流。", "鼓響移秧日，耞鳴穫稻秋。", "年豐身老健，一飽外無求。"]'),
('d168ea67-e649-47df-8255-5d5cd4c6d4dc','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其八','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，蒼磯一釣竿。',48,'全唐诗/poet.song.224000.json','["我愛山居好，蒼磯一釣竿。", "白鷗春水闊，黄犢綠坡寬。", "徑菊香秋晚，溪梅約歲寒。", "人間幽意足，詩思倚欄干。"]'),
('7bd8cbe5-1870-419c-9b6c-eea1fb73b8ff','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其九','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，茶甌困解圍。',48,'全唐诗/poet.song.224000.json','["我愛山居好，茶甌困解圍。", "松邊橫蘚石，柳下敞漁扉。", "細雨噞喁出，斜陽觳觫歸。", "交情殊貴賤，似覺故人非。"]'),
('97136376-680e-4088-b259-9e14176a61df','山居寂寥與世如隔是非不到榮辱兩忘因憶秋崖工部嘗教以我愛山居好十詩追次其韻聊寫窮山之趣  其一○','吳錫疇','宋','宋诗','song-poetry','','[]','我愛山居好，田園在力耘。',48,'全唐诗/poet.song.224000.json','["我愛山居好，田園在力耘。", "樵歌風外斷，猿嘯月中聞。", "舴艋夜招鶴，轆轤曉汲雲。", "久慚呼處士，未必應星文。"]'),
('4e7002a9-8d11-49da-bed6-590bfd07bb2f','對雪','吳錫疇','宋','宋诗','song-poetry','','[]','婆娑舞忽凌空去，散漫狂還掃地來。',32,'全唐诗/poet.song.224000.json','["婆娑舞忽凌空去，散漫狂還掃地來。", "幾片飛黏梅樹上，恍疑昨夜有花開。"]'),
('c8915edd-57ca-4c4b-a543-6843a54ea9bf','友人幽居','吳錫疇','宋','宋诗','song-poetry','','[]','空谷境常寂，幽居趣最真。',48,'全唐诗/poet.song.224000.json','["空谷境常寂，幽居趣最真。", "蛙鳴聊當樂，花發即爲春。", "白首惟詩酒，青山自主賓。", "惜無騷雅筆，寫寄市朝人。"]'),
('70f3d2b7-2c54-40e2-ab33-6a6cc32ef3fc','對燈詠感','吳錫疇','宋','宋诗','song-poetry','','[]','竛竮瘦影伴孤燈，兩鬢蕭然失舊青。',64,'全唐诗/poet.song.224000.json','["竛竮瘦影伴孤燈，兩鬢蕭然失舊青。", "豪在尚堪論劍術，骨凡何用泥丹經。", "半生踪跡如春燕，少日交游類曙星。", "閒拂桐絲寫幽意，洋洋不爲有人聽。"]'),
('d253ed51-08a4-47bc-9ea5-eb118fc9b3c9','詩一首','趙順孫','宋','宋诗','song-poetry','','[]','母在堂前爲父憂，特令兒子謁公侯。',32,'全唐诗/poet.song.224000.json','["母在堂前爲父憂，特令兒子謁公侯。", "大人若肯行方便，一點春風在筆頭。"]'),
('5ba03845-6e9c-4c61-8bba-c978e750ac04','小松','趙順孫','宋','宋诗','song-poetry','','[]','小小青松未透欄，枝枝葉葉傲霜寒。',32,'全唐诗/poet.song.224000.json','["小小青松未透欄，枝枝葉葉傲霜寒。", "如今正好低頭看，異日沖霄仰望難。"]'),
('86939c4f-ace4-40cc-af2a-f1525eabe2f5','建回吟','趙順孫','宋','宋诗','song-poetry','','[]','烽火年來報虜塵，每回回首即長顰。',64,'全唐诗/poet.song.224000.json','["烽火年來報虜塵，每回回首即長顰。", "明眸皓齒今何在，異服殊音不可親。", "幾樹好花閒白晝，數株殘柳不勝春。", "狂風落盡深紅色，水遠山長愁殺人。"]'),
('64402d92-ae1c-48ca-a5ea-a323820027ea','染疾吟','趙順孫','宋','宋诗','song-poetry','','[]','百年世事不勝悲，大厦原非一木支。',32,'全唐诗/poet.song.224000.json','["百年世事不勝悲，大厦原非一木支。", "慷慨西風淚橫臆，此心唯有老天知。"]'),
('fc68386f-c9b3-4c2e-822f-6a9c57636252','傷景吟','趙順孫','宋','宋诗','song-poetry','','[]','門前不改舊山河，蓮渚愁紅蕩碧波。',64,'全唐诗/poet.song.224000.json','["門前不改舊山河，蓮渚愁紅蕩碧波。", "墜葉飄花難再復，浮雲流水竟如何。", "魚龍寂寞秋江冷，鴻雁不來風雨多。", "窮巷悄然車馬絕，磬聲深戛出煙霞。"]'),
('485ca7e5-c07a-4b39-b390-aed9dcf6519e','病篤吟','趙順孫','宋','宋诗','song-poetry','','[]','不見人煙空見花，烟籠寒水月籠沙。',32,'全唐诗/poet.song.224000.json','["不見人煙空見花，烟籠寒水月籠沙。", "人生自古誰無死，莫怨東風當自嗟。"]'),
('461d6bd4-0234-4fe0-ab4e-0cec70b93a81','感情吟','趙順孫','宋','宋诗','song-poetry','','[]','豪傑消磨嘆五陵，髮衝烏帽氣填膺。',64,'全唐诗/poet.song.224000.json','["豪傑消磨嘆五陵，髮衝烏帽氣填膺。", "眼前不是無豪傑，身後何須論廢興。", "當道有蛇魂己斷，渡江無馬讖難憑。", "可憐一片中原地，虎嘯龍騰幾戰爭。"]'),
('a9054db8-7e0c-4841-8a6f-56da3f585cd2','辭世偈','清溪沅禪師','宋','宋诗','song-poetry','','[]','六十七年，無法可說。',20,'全唐诗/poet.song.224000.json','["六十七年，無法可說。", "一片雲收，澄潭皎月。"]'),
('b200830c-39b8-4b7f-9193-36ae1b55558c','送硯與吳元真廣文','俞君選','宋','宋诗','song-poetry','','[]','插天萬仞芙蓉峰，茫茫積翠連青空。',192,'全唐诗/poet.song.224000.json','["插天萬仞芙蓉峰，茫茫積翠連青空。", "中有千年蒼玉骨，山奇水怪秀所鍾。", "斷崖絕壁不可到，虎豹守護烟蘿封。", "一朝良工奪天造，雲斤月斧磨玲瓏。", "踏天下割碧雲髓，往往霹靂驚蛇龍。", "冰蠶吐絲織新就，羅文光瑩浮青銅。", "人間何處用此物，造化欲付文章公。", "先生早晚運椽筆，判花視草蓬萊宮。", "手揮五色補天漏，放開白日消陰虹。", "坐令萬物無疵癘，盡從筆底生春風。", "此時濃墨書大字，正須巨石相追從。", "願公收拾此至寶，相伴他年參化工。"]'),
('682e6283-fafc-41e2-bff3-938732226e76','送道士歸得日觀','章鑑','宋','宋诗','song-poetry','','[]','風月詩幾卷，江湖屐一雙。',48,'全唐诗/poet.song.224000.json','["風月詩幾卷，江湖屐一雙。", "斷蛟懷劍石，跨鶴叩禪窗。", "土潤巖生雨，林幽寺隔江。", "歸當訪仙隠，相對酒盈缸。"]'),
('785097da-7ab3-491a-9a3b-9ff3d879e831','杭山','章鑑','宋','宋诗','song-poetry','','[]','買得漁磯繫釣船，魚龍吹浪駭鷗眠。',64,'全唐诗/poet.song.224000.json','["買得漁磯繫釣船，魚龍吹浪駭鷗眠。", "從來白石清泉地，勝似青山小洞天。", "浪對客吟思却虜，偶觀人弈悟籌邊。", "夜來風雨秋聲早，一段新愁雪滿顛。"]'),
('0d669c17-4dcd-44c8-96a3-3e59f86ab9ac','過毛竹山','章鑑','宋','宋诗','song-poetry','','[]','一重關復一重關，一步難於一步難。',64,'全唐诗/poet.song.224000.json','["一重關復一重關，一步難於一步難。", "地僻林深晴亦溼，山高風猛夏猶寒。", "斷崖雲影掛枯樹，劈澗雷聲走怒湍。", "不信世間陵谷變，野樵偏識舊衣冠。"]'),
('bde6cfe2-dba5-4c60-ab98-afa812b6da31','杭山八景  其一','章鑑','宋','宋诗','song-poetry','','[]','萬箇長松覆短牆，碧流深處讀書房。',64,'全唐诗/poet.song.224000.json','["萬箇長松覆短牆，碧流深處讀書房。", "香生石覲春雲溼，影落篝燈夜雨涼。", "亙代陶鎔周禮樂，百年嘉會宋文章。", "天機悟到忘言表，又喜濤聲送夕陽。"]'),
('13454c8f-61c8-477c-ada8-b23b144249b5','杭山八景  其二','章鑑','宋','宋诗','song-poetry','','[]','古洞春泉一脈遥，驟施雷雨過清宵。',64,'全唐诗/poet.song.224000.json','["古洞春泉一脈遥，驟施雷雨過清宵。", "飛湍直下三千丈，急溜橫穿十二橋。", "雪灑石矼瓊練碎，翠分柳樹玉花飄。", "曉來醉倚高樓望，疑是銀河墮碧霄。"]'),
('6a196c2d-ac0b-47f3-9729-17976f0b3a50','杭山八景  其三','章鑑','宋','宋诗','song-poetry','','[]','泠泠雙澗瀉秋音，萬齒溪頭奏一琴。',64,'全唐诗/poet.song.224000.json','["泠泠雙澗瀉秋音，萬齒溪頭奏一琴。", "雨後更添猿鶴操，夜寒真是水龍吟。", "年光送盡從朝暮，律調含來自古今。", "借得許由當日耳，聽頻誰不爲清心。"]'),
('43ae1dbf-1bf3-40de-a135-83fe848558de','杭山八景  其四','章鑑','宋','宋诗','song-poetry','','[]','達邦大道兩迢迢，金轡玲瓏匹馬驕。',64,'全唐诗/poet.song.224000.json','["達邦大道兩迢迢，金轡玲瓏匹馬驕。", "腰褭嘶風蹄蹀躞，驤騰掣電尾蕭騷。", "雄聲已騁才人德，猛氣尤思大將驍。", "鳳臆龍髯誰可並，郭家獅子著先朝。"]'),
('91056a60-6635-4b39-9273-d4b393722eaa','杭山八景  其五','章鑑','宋','宋诗','song-poetry','','[]','內史名題古釣臺，高風凜凜勢崔嵬。',64,'全唐诗/poet.song.224000.json','["內史名題古釣臺，高風凜凜勢崔嵬。", "晚烟楊柳垂青縷，春雨桃花點綠苔。", "百尺絲綸波蕩漾，一宗詩派水瀠洄。", "何時來借閒燈覽，滌盡塵襟萬斛埃。"]'),
('9864419f-2720-44be-8ef9-77a5f29e9e5c','杭山八景  其六','章鑑','宋','宋诗','song-poetry','','[]','一邦佳景萃峰頭，宇宙鍾靈自有由。',64,'全唐诗/poet.song.224000.json','["一邦佳景萃峰頭，宇宙鍾靈自有由。", "銀竹霏霏山氣盛，火輪顆顆水光浮。", "年逢旱澇他方苦，世際豐穰此處優。", "瞻望巍峨殊不遠，登臨彷彿帝王州。"]'),
('b76964f2-0c35-46b7-8ee7-4f20d40172f6','杭山八景  其七','章鑑','宋','宋诗','song-poetry','','[]','昔賢曾此著名香，地位雙清四座涼。',64,'全唐诗/poet.song.224000.json','["昔賢曾此著名香，地位雙清四座涼。", "吹送幾多攀桂客，照來無數探花郎。", "光浮盞面龍鱗動，聲透琴心兔魄揚。", "爽我襟期明我德，步蟾擬駕大鵬翔。"]'),
('0ec3b331-705b-4c8a-b798-07d53203f1cc','杭山八景  其八','章鑑','宋','宋诗','song-poetry','','[]','同雲收盡日曈曈，曉霽分明見九宮。',64,'全唐诗/poet.song.224000.json','["同雲收盡日曈曈，曉霽分明見九宮。", "百里遠排銀筆架，半峰高疊玉屏風。", "螺鬟矗矗深藏翠，石劍稜稜欲露鋒。", "縱使丹青施妙手，難將寫入畫圖中。"]'),
('cda75691-e037-4017-bb1a-257ba802bf33','清輝堂','王朝佐','宋','宋诗','song-poetry','','[]','古汴寒灰不可溫，熒熒孤嶼火猶存。',64,'全唐诗/poet.song.224000.json','["古汴寒灰不可溫，熒熒孤嶼火猶存。", "一抔未問長陵土，兩字先勞萬乘尊。", "卓筆有鋒兵自弱，投戈無志藝何論。", "清輝堂外重回首，謾說旋乾與轉坤。"]'),
('09e6bd22-5615-4a02-beef-17378485786b','敬軒','王朝佐','宋','宋诗','song-poetry','','[]','作聖階梯義甚明，豈容惰慢倒儀形。',64,'全唐诗/poet.song.224000.json','["作聖階梯義甚明，豈容惰慢倒儀形。", "氣將六馬收銜轡，心不多歧守性靈。", "上帝鑒茲恒翼翼，主翁喚醒更惺惺。", "揭楣倘有希賢志，合把齋箴究考亭。"]'),
('5cf6678e-749b-45ae-a80d-2b304a45f5a0','題英藪山房','王朝佐','宋','宋诗','song-poetry','','[]','築室傍丹梯，新顔手自題。',48,'全唐诗/poet.song.224000.json','["築室傍丹梯，新顔手自題。", "空涵龍洞雨，壁污燕巢泥。", "樹色圍春晝，書聲雜暮溪。", "南園花正發，携酒聽鶑啼。"]'),
('d3b88166-b9a9-48d0-833a-768f5e32a515','送林道會歸平陽','王朝佐','宋','宋诗','song-poetry','','[]','研硃點易已多年，洞底烟霞別有天。',64,'全唐诗/poet.song.224000.json','["研硃點易已多年，洞底烟霞別有天。", "千里漫來騎隻鶴，一官歸去領群仙。", "藥爐煖養燒丹火，茶竈晴分瀹茗泉。", "安得塵襟都掃却，相從細讀悟真篇。"]'),
('893ed803-54ad-47b9-8b0d-78df3027f0f7','貞義女祠','王朝佐','宋','宋诗','song-poetry','','[]','瀨水何泱泱，携篚向水旁。',120,'全唐诗/poet.song.224000.json','["瀨水何泱泱，携篚向水旁。", "低頭事漂洗，不惜溼羅裳。", "晨出未暮歸，老母在高堂。", "三十不願適，焉知繡鴛鴦。", "道逢困丈夫，行乞良可傷。", "一飯婦女仁，况有殘壺漿。", "終焉感禮義，出詞何慨慷。", "貞潔恐無知，清流見肝腸。", "悲哉伍子胥，百金何足償。", "惟有鴟夷心，可與增輝光。"]'),
('a2885177-5185-488a-bb15-d2a1b8dddf7d','呈立齋先生','車若水','宋','宋诗','song-poetry','','[]','童牙苦呫畢，嚼瓜燈燼爛。',60,'全唐诗/poet.song.224000.json','["童牙苦呫畢，嚼瓜燈燼爛。", "衡縮高于丘，纔作文字看。", "精微隔幾塵，健筆抵流湍。", "開眼天地燎，始識用書難。", "千葩慚一實，本根耐歲寒。"]'),
('1d35693f-9383-4e63-be91-0865e72d2cd1','玉澗尋梅思先祖隘軒著書處','車若水','宋','宋诗','song-poetry','','[]','澗水流亭北，莓苔片石平。',48,'全唐诗/poet.song.224000.json','["澗水流亭北，莓苔片石平。", "寒山幾點白，殘日一杯清。", "希聖言猶在，斯人天不生。", "當年結深屋，豈爲適閒情。"]'),
('db4392c6-62fd-447f-9720-3aaffe691003','思遠','車若水','宋','宋诗','song-poetry','','[]','白兔速圩頂，暗壁收遺編。',132,'全唐诗/poet.song.224000.json','["白兔速圩頂，暗壁收遺編。", "握之不盈掬，而能千萬年。", "天地可無人，秦火乃可然。", "其粗灑埽間，其精造化先。", "後來讀書者，暗引佛與仙。", "之人胡弗靈，所論各有偏。", "囂祲礙亭毒，三精慘不鮮。", "塗飾爲善治，制作埋九淵。", "固有二三子，梯級堪攀緣。", "夜永發孤啑，思遠能廢眠。", "拔地爲五嶽，豈其高到天。"]'),
('003e8623-731e-4f0b-ba88-3de175b7b9b5','儳言','車若水','宋','宋诗','song-poetry','','[]','媧皇識五石，煉之能補天。',72,'全唐诗/poet.song.224000.json','["媧皇識五石，煉之能補天。", "補天有何迹，五石世不傳。", "五石豈不傳，人心稟靈堅。", "一日彝倫敘，千年造化全。", "此石經幾煉，天亦經幾補。", "火候吾有之，吾師魯男子。"]'),
('538ee52a-bfa1-4cb7-a820-8eb79ad4a942','偶書呈雪溪葛守正','車若水','宋','宋诗','song-poetry','','[]','秦埃幻六籍，斯文天地屯。',84,'全唐诗/poet.song.224000.json','["秦埃幻六籍，斯文天地屯。", "詝言嘈萬喙，渺不游其津。", "作者能幾何，落落星已晨。", "單其千載傳，覷斑尤苦辛。", "毫芒忽有會，不能全吾神。", "頗怪十年前，出語輒可人。", "功深道更拙，敝帚聊自珍。"]'),
('6ad1ef7b-ceb1-425e-9a43-76a86cee6479','不寐','車若水','宋','宋诗','song-poetry','','[]','通夕不能寐，隔戶聞鍾聲。',68,'全唐诗/poet.song.224000.json','["通夕不能寐，隔戶聞鍾聲。", "野雞四方啼，披衣天未明。", "蕭條六合內，耿耿華髮生。", "斷鼇何能立四極，杞人憂天自心失。", "黄昏野沽添一盂，孔孟行世非我力。"]'),
('e2f0817e-3342-4f2b-b089-0121b4b26c90','見篔窗先生','車若水','宋','宋诗','song-poetry','','[]','關扃守殘經，坐几刓無漆。',92,'全唐诗/poet.song.224000.json','["關扃守殘經，坐几刓無漆。", "風驚雨劫破窗寒，猛心直矢聖賢室。", "蟄蠅眩光彈夜紙，一膜不透千千里。", "帢幘檠奎照屋明，中津弗截衣带水。", "敦彝久掩生深塵，大啟戶牖來無人。", "眼中孺子差可語，可語不語悔千古。"]'),
('d1fd364f-493b-4851-ba60-00876480e101','寄鮑府教宏博','車若水','宋','宋诗','song-poetry','','[]','漆文蟲章孔壁冷，秦煙不燼收餘鑛。',96,'全唐诗/poet.song.224000.json','["漆文蟲章孔壁冷，秦煙不燼收餘鑛。", "人心萬古無代謝，六龍當天樞極炯。", "赤帝芟嬴能幾年，叢葭亂葦書千千。", "商盤周敦贋今古，魏殿吳宮鑿後先。", "汗將九牛牽不上，從容一絲經萬象。", "百年文獻來典謨，我欲盟君分石渠。"]'),
('d359c7e3-6cb2-4c9e-b3b8-57e88405e406','慟立齋先生','車若水','宋','宋诗','song-poetry','','[]','元元含望久，及是事方新。',48,'全唐诗/poet.song.224000.json','["元元含望久，及是事方新。", "四海看更化，皇天忍誤人。", "多於閒論議，得聽古經綸。", "豈不懷斯世，吾今愛此身。"]'),
('bf4766dc-c91d-4958-85eb-14676ead1332','江湖偉觀','車若水','宋','宋诗','song-poetry','','[]','十年不到一憑闌，景色依然兩鬢斑。',64,'全唐诗/poet.song.224000.json','["十年不到一憑闌，景色依然兩鬢斑。", "龍蜃吐雲天入海，樓臺倒影水銜山。", "僧于僻寺難爲隠，人在扁舟不是閑。", "孤鶴似尋和靖宅，盤空飛下又飛還。"]'),
('f7ade058-732c-4037-9abd-1da8144c6adb','小溪道中時己亥荒甚','車若水','宋','宋诗','song-poetry','','[]','風前有地皆榆葉，秋後何人問菊花。',32,'全唐诗/poet.song.224000.json','["風前有地皆榆葉，秋後何人問菊花。", "客路一杯茅店酒，相逢僧亦話生涯。"]'),
('78da040a-77b6-49eb-bf80-fe4ee82a8f8a','與史宰山泉','車若水','宋','宋诗','song-poetry','','[]','十畝山田手自耕，括囊安分是平生。',32,'全唐诗/poet.song.224000.json','["十畝山田手自耕，括囊安分是平生。", "西州豪傑無皇甫，嬾去虛干向上名。"]'),
('aa888372-b6a9-4d34-936e-549ddfd2379a','庚申','車若水','宋','宋诗','song-poetry','','[]','襄陽耆舊總堪羞，只有龐公已入州。',32,'全唐诗/poet.song.224000.json','["襄陽耆舊總堪羞，只有龐公已入州。", "自向芭蕉眠夜雨，不堪更鼓在牀頭。"]'),
('66588d6c-cc7e-423d-ac5c-708552a1fe15','和立齋先生雁山韻','車若水','宋','宋诗','song-poetry','','[]','洗山出穹石，削空蹲蒼城。',84,'全唐诗/poet.song.224000.json','["洗山出穹石，削空蹲蒼城。", "一清屹萬古，何物相與形。", "步涉貪深遊，往往神所兵。", "立齋立千仞，天地鑑清聲。", "平平遡龍準，不見猿鳥驚。", "斯道今泬寥，斯人世重輕。", "擎天隻柱健，此囑誰堪膺。"]'),
('3ac0e5fe-f65d-4764-bf67-61167f1c9ae6','遊靈巖','車若水','宋','宋诗','song-poetry','','[]','一徑碧如合，四山危欲墮。',120,'全唐诗/poet.song.224000.json','["一徑碧如合，四山危欲墮。", "天低鳥不飛，露濕龍常過。", "巖根小葉下，境凈不可唾。", "深杳洞出雲，冷鐘佛驚卧。", "川僧住八年，有此清福大。", "而我尋盟來，坐借蒲團破。", "燈深眼雙青，各話其所課。", "我穀未必實，他華已成果。", "歸來宜有餘，吾道豈全懦。", "壁間清獻存，當年愧輕和。"]'),
('7b02505a-0f2c-46f2-b9e5-790e30017d5a','明妃','車若水','宋','宋诗','song-poetry','','[]','萬里來朝拜寵歸，琵琶下馬冊閼氏。',32,'全唐诗/poet.song.224000.json','["萬里來朝拜寵歸，琵琶下馬冊閼氏。", "虛傳千古和戎話，不道當年虜自衰。"]'),
('e024c49a-64eb-499a-9667-8e878f74d91a','中秋有感','車若水','宋','宋诗','song-poetry','','[]','村屋半蹲鵜鴂晚，吳江一葉鷾鴯秋。',32,'全唐诗/poet.song.224000.json','["村屋半蹲鵜鴂晚，吳江一葉鷾鴯秋。", "北邊又聽寒來信，近日何人萬戶侯。"]'),
('06442f2c-bd8b-4128-b20d-bb50ab25deeb','寄瑞巖老煜無取','車若水','宋','宋诗','song-poetry','','[]','涼月空山挂祖衣，猿啼塔樹昔人非。',32,'全唐诗/poet.song.224000.json','["涼月空山挂祖衣，猿啼塔樹昔人非。", "春風早已青青柳，莫在梅花飛後飛。"]'),
('9dd79903-b05c-4012-9ee8-661079d6e1c9','句','車若水','宋','宋诗','song-poetry','','[]','江右文章今四葉，水心氣脈近三台。',16,'全唐诗/poet.song.224000.json','["江右文章今四葉，水心氣脈近三台。"]'),
('f1d8995b-142f-4057-bbae-c6c87a838e01','明堂侍祠十絕  其一','王庭','宋','宋诗','song-poetry','','[]','禮行肆類又稱禋，喜見承平景鑠信。',32,'全唐诗/poet.song.224000.json','["禮行肆類又稱禋，喜見承平景鑠信。", "堪笑漢人誇肸飾，何如明德達精純。"]'),
('77878ee9-57c8-4639-a50f-3edb650dd408','明堂侍祠十絕  其二','王庭','宋','宋诗','song-poetry','','[]','先皇鴻烈冠重興，廟社依然總燕寧。',32,'全唐诗/poet.song.224000.json','["先皇鴻烈冠重興，廟社依然總燕寧。", "今日孝思嚴陟配，必知深妥在天靈。"]'),
('9b3ec37a-5134-478a-81d6-0b1375483c73','明堂侍祠十絕  其三','王庭','宋','宋诗','song-poetry','','[]','玉軑纔馳霽色開，都人驩謼殷如雷。',32,'全唐诗/poet.song.224000.json','["玉軑纔馳霽色開，都人驩謼殷如雷。", "曰晹曰雨元無定，都自吾皇一念來。"]'),
('39b608e1-d04a-4d0d-9a08-ffb3094aaa3d','明堂侍祠十絕  其四','王庭','宋','宋诗','song-poetry','','[]','唱徹嚴更鳳鑰開，侍祠濟濟列崇陔。',32,'全唐诗/poet.song.224000.json','["唱徹嚴更鳳鑰開，侍祠濟濟列崇陔。", "小臣亦忝廊西獻，惟秉溫恭對越來。"]'),
('133f42d1-9cf1-4779-895a-e43d25e5814a','明堂侍祠十絕  其五','王庭','宋','宋诗','song-poetry','','[]','玉佩珊珊出禁扉，金蓮分炬散芳菲。',32,'全唐诗/poet.song.224000.json','["玉佩珊珊出禁扉，金蓮分炬散芳菲。", "祠班咫尺臨黄道，惹得天香滿袖歸。"]'),
('820426e7-b539-4158-a0d7-96df86c56d05','明堂侍祠十絕  其六','王庭','宋','宋诗','song-poetry','','[]','登歌奏罷樂初成，懿懿芬芬薦德馨。',32,'全唐诗/poet.song.224000.json','["登歌奏罷樂初成，懿懿芬芬薦德馨。", "好是天心彰信順，故教華月吐青冥。"]'),
('ed11a232-c8f7-4007-99c1-6dddbebabc52','明堂侍祠十絕  其七','王庭','宋','宋诗','song-poetry','','[]','合宮深敞帀脩廊，萬燭煇煇粲奉璋。',32,'全唐诗/poet.song.224000.json','["合宮深敞帀脩廊，萬燭煇煇粲奉璋。", "自有質文昭儉度，不須揚厲述齋房。"]'),
('a29ae423-96de-4f73-ab9e-1fe4cc47e28a','明堂侍祠十絕  其八','王庭','宋','宋诗','song-poetry','','[]','左个明堂是集英，鵠袍曾此接文明。',32,'全唐诗/poet.song.224000.json','["左个明堂是集英，鵠袍曾此接文明。", "餕餘款聽鈞天奏，疑是吾伊雅頌聲。"]'),
('4f6cff19-ad8b-4fc5-9d52-3a09c0a26921','明堂侍祠十絕  其九','王庭','宋','宋诗','song-poetry','','[]','千官移杖拱端門，一日雞竿萬里春。',32,'全唐诗/poet.song.224000.json','["千官移杖拱端門，一日雞竿萬里春。", "湯網本疏民自格，要知家法在深仁。"]'),
('ac97c956-d102-4dfb-817d-bcc4c21ab274','明堂侍祠十絕  其一○','王庭','宋','宋诗','song-poetry','','[]','肸蠁豐融富媼釐，班迴長樂奉愉怡。',32,'全唐诗/poet.song.224000.json','["肸蠁豐融富媼釐，班迴長樂奉愉怡。", "休嘉最易生安逸，翼翼當如未祼時。"]'),
('5e1a3f3d-770c-4a70-94dd-9402dc7a3df4','裂衣書詩寄弟','趙卯發','宋','宋诗','song-poetry','','[]','城池不高深，無財又無兵。',24,'全唐诗/poet.song.224000.json','["城池不高深，無財又無兵。", "惟有死報國，來生作弟兄。"]'),
('adf83e85-da74-4a10-a2cd-d779f621a531','題於壁','趙卯發','宋','宋诗','song-poetry','','[]','國不可負，城難以降。',20,'全唐诗/poet.song.224000.json','["國不可負，城難以降。", "夫婦俱死，節義成雙。"]'),
('8bf31171-e2b0-4281-b2c2-389582c8356a','招撫峒猺歌','顔得遇','宋','宋诗','song-poetry','','[]','率土王民樂陶陶，犬戎亦民今婆娑。',32,'全唐诗/poet.song.224000.json','["率土王民樂陶陶，犬戎亦民今婆娑。", "適正人天依中和，日月不老朝山河。"]'),
('8d18c3ed-6e47-4083-9473-78dee995ed53','鹿鳴宴','虞兟','宋','宋诗','song-poetry','','[]','儒雅從來說雉山，抱琴何幸預榮觀。',64,'全唐诗/poet.song.224000.json','["儒雅從來說雉山，抱琴何幸預榮觀。", "六人同榜昔猶有，一邑三魁今所難。", "方喜棘闈連鶚薦，又欣碧海起鵬摶。", "聯科甲第應餘事，須把聲名久遠看。"]'),
('ddd6fe8a-7111-4f48-b575-cef0da0c9905','送林道士歸茅山','鄧道樞','宋','宋诗','song-poetry','','[]','多載事茅君，麻衣與葛巾。',48,'全唐诗/poet.song.224000.json','["多載事茅君，麻衣與葛巾。", "眼知人貴賤，心鍊己形神。", "丁甲常爲使，王侯不得臣。", "華陽歸洞晚，芝草幾回春。"]'),
