('a282858f-c1c5-4f6c-8a33-87f72246cb7b','次鄒希賢買魚不得三首衍爲漁翁問答六詩 答漁翁','姚勉','宋','宋诗','song-poetry','','[]','茅屋無金可滿籯，湖邊小艇却堪撐。',32,'全唐诗/poet.song.224000.json','["茅屋無金可滿籯，湖邊小艇却堪撐。", "縱無介甫魚羹飯，也學東坡飽菜羹。"]'),
('19b71230-fd99-4636-8dd2-01a2e4acfb4d','和陳和卿四絕  其一','姚勉','宋','宋诗','song-poetry','','[]','絕交久是孔方兄，賒得村醪小款迎。',32,'全唐诗/poet.song.224000.json','["絕交久是孔方兄，賒得村醪小款迎。", "君豈真無食肉相，夜來蔬筍太僧清。"]'),
('539a0a4f-1092-4254-8134-15849789c4ff','和陳和卿四絕  其二','姚勉','宋','宋诗','song-poetry','','[]','梁燕無聲晝掩扃，若爲消此畫堂清。',32,'全唐诗/poet.song.224000.json','["梁燕無聲晝掩扃，若爲消此畫堂清。", "急呼覓句陳無己，莫撚吟髭且一枰。"]'),
('c4c120ec-afa4-4730-b977-5d5bfb54f569','和陳和卿四絕  其三','姚勉','宋','宋诗','song-poetry','','[]','蚤裏溪人又饋魚，未容歸興動蓴鱸。',32,'全唐诗/poet.song.224000.json','["蚤裏溪人又饋魚，未容歸興動蓴鱸。", "祇今更辦開蔬供，君若來遲釜恐無。"]'),
('a240e1d3-9122-44cb-a794-907ab7360f73','和陳和卿四絕  其四','姚勉','宋','宋诗','song-poetry','','[]','空齋長夏永如年，鶑囀林陰鷺水田。',32,'全唐诗/poet.song.224000.json','["空齋長夏永如年，鶑囀林陰鷺水田。", "只好更尋棋一局，莫孤花影午時天。"]'),
('d126e859-7009-4b7f-a81f-7c98aed29a22','和龔宗諭五絕  其一','姚勉','宋','宋诗','song-poetry','','[]','多少掄魁豈獨今，道心誰勝利名心。',32,'全唐诗/poet.song.224000.json','["多少掄魁豈獨今，道心誰勝利名心。", "只知晁董前頭立，何似周程樂處尋。"]'),
('bd570ba7-28c9-451f-a245-cb21a322b11e','和龔宗諭五絕  其二','姚勉','宋','宋诗','song-poetry','','[]','吾儕從仕爲家邦，豈羨科名世少雙。',32,'全唐诗/poet.song.224000.json','["吾儕從仕爲家邦，豈羨科名世少雙。", "激浪須看巋柱立，犯顔安可畏郎撞。"]'),
('da07a16f-4055-4e67-934b-5926e227a192','和龔宗諭五絕  其三','姚勉','宋','宋诗','song-poetry','','[]','學不求名况爲官，官甜初不似儒酸。',32,'全唐诗/poet.song.224000.json','["學不求名况爲官，官甜初不似儒酸。", "無能富貴都磨滅，直作浮雲一樣看。"]'),
('2c3eca03-842b-4d19-a38d-6c5d8a3161cd','和龔宗諭五絕  其四','姚勉','宋','宋诗','song-poetry','','[]','聞僅二知雖賜也，道傳一貫必參乎。',32,'全唐诗/poet.song.224000.json','["聞僅二知雖賜也，道傳一貫必參乎。", "己私克盡融天理，表裏通明月在壺。"]'),
('69bc8d83-16d3-4ff4-b886-43ac74c4763c','和龔宗諭五絕  其五','姚勉','宋','宋诗','song-poetry','','[]','名下惟知不可居，誨言終日反三隅。',32,'全唐诗/poet.song.224000.json','["名下惟知不可居，誨言終日反三隅。", "愛人以德今忠獻，莫道前賢久已無。"]'),
('2eb795cf-7db0-44c8-b083-195e8737bd88','勸學示子元夫','姚勉','宋','宋诗','song-poetry','','[]','事業功名在讀書，聖賢妙處著工夫。',32,'全唐诗/poet.song.224000.json','["事業功名在讀書，聖賢妙處著工夫。", "區區只爲潭潭府，不敢如韓訓阿符。"]'),
('1f52f5e6-ea11-40a6-bf74-4755358af3c6','弈棋有感','姚勉','宋','宋诗','song-poetry','','[]','奕秋鴻鵠未須驚，一著才差敗一枰。',32,'全唐诗/poet.song.224000.json','["奕秋鴻鵠未須驚，一著才差敗一枰。", "不信但來茅屋裏，紙棋盤上看輸贏。"]'),
('3f941913-c9b8-4409-b44a-8ee17ac5938b','己未秋杪虜騎雲擾聖主神斷斥逐元姦臺臣始有抨彈之疏因成二絕一惜言者之後時二願局面之堅凝也  其一','姚勉','宋','宋诗','song-poetry','','[]','窗紙暾紅枕上知，破寒初聽一聲雞。',32,'全唐诗/poet.song.224000.json','["窗紙暾紅枕上知，破寒初聽一聲雞。", "雖無風雨瀟瀟度，也勝隣家曉不啼。"]'),
('03015ca8-5cd2-4826-90e4-133bfe1d3483','己未秋杪虜騎雲擾聖主神斷斥逐元姦臺臣始有抨彈之疏因成二絕一惜言者之後時二願局面之堅凝也  其二','姚勉','宋','宋诗','song-poetry','','[]','積雨霖霪忽報晴，元來依舊有清明。',32,'全唐诗/poet.song.224000.json','["積雨霖霪忽報晴，元來依舊有清明。", "霜天護取晴牢著，莫放寒雲半點生。"]'),
('a42e2f60-bbc1-47f8-8e77-5ba43f71d601','嘲貓','姚勉','宋','宋诗','song-poetry','','[]','斑虎皮毛潔且新，綉裀嬌睡似親人。',32,'全唐诗/poet.song.224000.json','["斑虎皮毛潔且新，綉裀嬌睡似親人。", "梁間縱鼠渾無策，門外攘雞太不仁。"]'),
('b8f7583c-760f-43a9-8c4e-e26d88170487','嘲燕','姚勉','宋','宋诗','song-poetry','','[]','蓬蒿塞徑掩柴關，紫燕離巢更不還。',32,'全唐诗/poet.song.224000.json','["蓬蒿塞徑掩柴關，紫燕離巢更不還。", "大厦連雲成就日，重遊簾幙有何顔。"]'),
('54cf02df-dbe0-4754-abf9-aa7e1e3e0781','詠蜂','姚勉','宋','宋诗','song-poetry','','[]','百花頭上選羣芳，收拾香腴入洞房。',32,'全唐诗/poet.song.224000.json','["百花頭上選羣芳，收拾香腴入洞房。", "但得蜜成甘衆口，一身雖苦又何妨。"]'),
('a9ad1303-8b0c-4a7e-846d-ac7b2007a2af','贈電眸陳相士','姚勉','宋','宋诗','song-poetry','','[]','巖電當年說阿戎，清談于世竟何功。',32,'全唐诗/poet.song.224000.json','["巖電當年說阿戎，清談于世竟何功。", "君今雙目真如電，舉世忠邪一覽中。"]'),
('6f8feb2d-89fd-4a4d-abfb-c8b5ec91aab0','贈談天星數王子貴','姚勉','宋','宋诗','song-poetry','','[]','談天客子晝敲門，相對晴窗話一樽。',32,'全唐诗/poet.song.224000.json','["談天客子晝敲門，相對晴窗話一樽。", "到底忘言方是妙，梅花枝上看乾坤。"]'),
('02b41e3b-2903-4b33-9cf2-91d40f0ce666','雪後同友人觀梅','姚勉','宋','宋诗','song-poetry','','[]','簷珠瀝瀝雪初晴，酒滴寒槽雜溜聲。',32,'全唐诗/poet.song.224000.json','["簷珠瀝瀝雪初晴，酒滴寒槽雜溜聲。", "旋釂梅花斟夜月，人間那得箇般清。"]'),
('85621c10-8a1a-4ceb-9925-b26583fa9248','和姚榷院送茉莉韻','姚勉','宋','宋诗','song-poetry','','[]','清甚冰葩淡不粧，能從盛暑到秋凉。',32,'全唐诗/poet.song.224000.json','["清甚冰葩淡不粧，能從盛暑到秋凉。", "瓊樓合著移春檻，却向山齋供凈香。"]'),
('50b4a1df-333a-43b1-ae70-dc33898a8630','新晴散步','姚勉','宋','宋诗','song-poetry','','[]','晴曉芳蹊潤，幽尋得自怡。',48,'全唐诗/poet.song.224000.json','["晴曉芳蹊潤，幽尋得自怡。", "露粘行草蝶，風舞罥花絲。", "竹靜聞鄰話，林虛度客棋。", "意行無伴侶，池上只鶑知。"]'),
('d6e10b17-5e36-41fd-85e6-997d577ca2f6','春日即事','姚勉','宋','宋诗','song-poetry','','[]','行野醒春困，看山立晝晴。',48,'全唐诗/poet.song.224000.json','["行野醒春困，看山立晝晴。", "鳩啼青樾破，鷺匝綠秧行。", "物到忘機樂，人因遠俗清。", "覓詩無斷句，敲板午茶聲。"]'),
('fb36d173-713b-4679-81ae-4765821d896c','山齋','姚勉','宋','宋诗','song-poetry','','[]','茅齋住翠林，一逕總清陰。',48,'全唐诗/poet.song.224000.json','["茅齋住翠林，一逕總清陰。", "澗近水聲入，窗虛山色侵。", "讀書依竹靜，送客出花深。", "此地無塵俗，令人長道心。"]'),
('2238d1d1-d8e4-4711-a667-ac76070d881c','芭蕉','姚勉','宋','宋诗','song-poetry','','[]','窗外幾芭蕉，幽懷慰寂寥。',48,'全唐诗/poet.song.224000.json','["窗外幾芭蕉，幽懷慰寂寥。", "晚宜風颭颭，秋稱雨瀟瀟。", "清滴漁篷碎，徐翻鳳扇摇。", "進修期似爾，日日長新苗。"]'),
('9d4d29d7-c458-425f-80ee-b47890760789','歲暮','姚勉','宋','宋诗','song-poetry','','[]','歲暮仍爲客，書空默自嗟。',48,'全唐诗/poet.song.224000.json','["歲暮仍爲客，書空默自嗟。", "鴈聲催念友，魚鱠起思家。", "廊靜風鳴葉，窗虛雪入花。", "醉鄉聊避世，天外自寒鴉。"]'),
('b3281b7d-cf1d-4124-af06-f2d55fe1eaac','山市','姚勉','宋','宋诗','song-poetry','','[]','路詢山市宿，店近石橋橫。',48,'全唐诗/poet.song.224000.json','["路詢山市宿，店近石橋橫。", "老水穿簷過，低窗照水明。", "雨聲凄客思，野處愜幽情。", "沽酒聊牽睡，茅柴醉不成。"]'),
('c33d9ea1-7a4f-4514-822f-8b343f0523b9','舟泊蘭溪湖頭市遇雨','姚勉','宋','宋诗','song-poetry','','[]','望燈投野市，衝雨泊征船。',48,'全唐诗/poet.song.224000.json','["望燈投野市，衝雨泊征船。", "茅店不容客，柳堤聊枕舷。", "欹眠濤拍枕，起坐漏沾肩。", "夜半瀟瀟歇，推篷月在天。"]'),
('cb00e4e0-ab79-4dac-8460-adfd133f0fa9','送王仲安歸武昌','姚勉','宋','宋诗','song-poetry','','[]','武昌洲畔去，端不爲魚肥。',48,'全唐诗/poet.song.224000.json','["武昌洲畔去，端不爲魚肥。", "要起初平石，同娛萊子衣。", "夜長秋雨急，天闊白雲飛。", "何日鵲烏喜，北風鴻鴈歸。"]'),
('efeb3ed1-5549-4e6d-bad7-e88126f5d799','登四聖觀月桂亭有感','姚勉','宋','宋诗','song-poetry','','[]','將軍休戰伐，居士號清凉。',48,'全唐诗/poet.song.224000.json','["將軍休戰伐，居士號清凉。", "亭創煙蘿古，山深月桂香。", "夢魂猶朔漠，風景已錢塘。", "往事都休問，鐘聲又夕陽。"]'),
('7416a568-6b2f-4724-b7e2-e65fc9f8c5d6','登北高峰','姚勉','宋','宋诗','song-poetry','','[]','秋風吹鬢影，凉意足登山。',48,'全唐诗/poet.song.224000.json','["秋風吹鬢影，凉意足登山。", "人立晴林杪，猿啼霜霧間。", "好山多佛占，浮世只僧閒。", "我亦耽奇者，禪扉日叩關。"]'),
('9832c9fe-a8e2-431f-9c7c-e447c4aa5780','冷泉亭納凉','姚勉','宋','宋诗','song-poetry','','[]','人間方鼎鑊，個裏獨冰霜。',48,'全唐诗/poet.song.224000.json','["人間方鼎鑊，個裏獨冰霜。", "自是清難濁，能令暑亦凉。", "客遷愁瘴海，妃浴涴溫湯。", "惟有茲泉冷，冷中滋味長。"]'),
('8c44414c-9ee1-4588-b2be-10c619eecf89','放生池納凉晚歸','姚勉','宋','宋诗','song-poetry','','[]','湖面輕煙起，前山漸不分。',48,'全唐诗/poet.song.224000.json','["湖面輕煙起，前山漸不分。", "鐘聲連寺答，人語隔船聞。", "吟客衣生月，歸僧笠带雲。", "及城門未掩，燈火已紛紛。"]'),
('b66eec22-b533-4e92-8493-14e8a2d04a50','湖上隠者所居','姚勉','宋','宋诗','song-poetry','','[]','家計松梅竹，日程琴酒碁。',48,'全唐诗/poet.song.224000.json','["家計松梅竹，日程琴酒碁。", "呼猿僧到處，放鶴客來時。", "壁上皆蘇字，窗門只白詩。", "卜鄰心已决，未得買山資。"]'),
('3e57042f-020a-4887-b689-87d6d170d966','病後久不到湖上晚與客到斷橋','姚勉','宋','宋诗','song-poetry','','[]','病後久不出，未知湖上秋。',48,'全唐诗/poet.song.224000.json','["病後久不出，未知湖上秋。", "偶逢佳客至，小作斷橋遊。", "荷暗仍香岸，柳疎猶舞樓。", "相期明月夜，更此放扁舟。"]'),
('116829d7-ca91-48e3-9697-f4807d8fefac','次劉仲山餞歸韻','姚勉','宋','宋诗','song-poetry','','[]','幾同湖上飲，俱愛晚山青。',48,'全唐诗/poet.song.224000.json','["幾同湖上飲，俱愛晚山青。", "雅趣方泉寺，離舟又浙亭。", "贈行詩自好，愁別酒休醒。", "後夜思君處，桐江傍客星。"]'),
('051c7b73-0cb0-4fae-9c83-490454f8c606','富陽道中','姚勉','宋','宋诗','song-poetry','','[]','翠駕凋零盡，芒鞋響葉聲。',48,'全唐诗/poet.song.224000.json','["翠駕凋零盡，芒鞋響葉聲。", "晴江潮後綠，寒日竹間清。", "曝背翁微睡，挑包僧自行。", "離京纔一日，便覺愜幽情。"]'),
('fb67ec8c-935e-458a-988d-9d18d059567d','道傍水閣','姚勉','宋','宋诗','song-poetry','','[]','一川澄不動，山色浸分明。',48,'全唐诗/poet.song.224000.json','["一川澄不動，山色浸分明。", "噪晚鴉寒甚，窺魚鷺瘦生。", "人家江閣好，天下釣翁清。", "想此幽居者，何知有利名。"]'),
('d1264883-e446-4022-8f77-b7d1c65f736f','丈室','姚勉','宋','宋诗','song-poetry','','[]','蕭然丈室虛，彷彿似僧居。',48,'全唐诗/poet.song.224000.json','["蕭然丈室虛，彷彿似僧居。", "影與身爲伴，琴和鶴也無。", "飯時三種菜，香畔一函書。", "不似僧家處，曇曇髮幾株。"]'),
('f24e9da1-8f88-499d-966c-6ecc34fe4939','贈徐處士','姚勉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','劍津徐處士，湖海盡知名。',48,'全唐诗/poet.song.224000.json','["劍津徐處士，湖海盡知名。", "術造勾庚妙，書研遁甲精。", "寒齋留爾久，別驛若爲情。", "定赴秋風約，西湖酒重傾。"]'),
('b21bf7e8-9a8d-4272-a021-ab747e9826fc','客中遇雨','姚勉','宋','宋诗','song-poetry','','[]','名韁驅遠役，挈挈未遑安。',48,'全唐诗/poet.song.224000.json','["名韁驅遠役，挈挈未遑安。", "春只雨中過，花從客裏看。", "水聲添昨夜，風力盡餘寒。", "但喜前程闊，不愁行路難。"]'),
('46a248f9-7cde-4a9b-a0e1-1920919063ad','及第歸入江西界','姚勉','宋','宋诗','song-poetry','','[]','得得還初隠，秋風信馬蹄。',48,'全唐诗/poet.song.224000.json','["得得還初隠，秋風信馬蹄。", "此心宸極北，今日大江西。", "戲綵呈君賜，擎珠教御題。", "家庭真樂近，蓐食聽晨鷄。"]'),
('ad7289c2-b254-4109-bac1-494e46a11286','送梁新恩夢雷歸鄉','姚勉','宋','宋诗','song-poetry','','[]','晝錦賦歸歟，梅花萬里餘。',48,'全唐诗/poet.song.224000.json','["晝錦賦歸歟，梅花萬里餘。", "同盟難此別，後會定何如。", "袍綠爲親壽，編青課弟書。", "燕山今再有，五桂耀鄉閭。"]'),
('833860e9-cba4-4f27-897b-0816c8f3e679','送王希聖歸興國赴舉','姚勉','宋','宋诗','song-poetry','','[]','之子趣裝歸，占黄已在眉。',48,'全唐诗/poet.song.224000.json','["之子趣裝歸，占黄已在眉。", "雕蟲觀暇日，薦鶚信秋期。", "喜有傳衣鉢，慙無助鼓旗。", "捷書來報我，端的菊花時。"]'),
('25f82dd6-6060-4bcd-8a37-a7f36fe688d7','贈煜上人','姚勉','宋','宋诗','song-poetry','','[]','遶院蕭蕭竹，僧中爾獨清。',48,'全唐诗/poet.song.224000.json','["遶院蕭蕭竹，僧中爾獨清。", "佛燈行道影，梵磬誦經聲。", "露葉晨蔬熟，風松晝茗烹。", "夜深誰伴侶，月在石窗明。"]'),
('e45ca026-0547-44ae-8649-0033e5780b68','送趙僉判美任  其一','姚勉','宋','宋诗','song-poetry','','[]','佐幕此三年，邦人盡說賢。',48,'全唐诗/poet.song.224000.json','["佐幕此三年，邦人盡說賢。", "吏寒清夜月，民暖小春天。", "祖帳旗交綵，歸裝石壓船。", "甘棠在何許，積粟市橋邊。"]'),
('b45ed8d1-3b99-4c06-9451-5ebc523e12fa','送趙僉判美任  其二','姚勉','宋','宋诗','song-poetry','','[]','底事三年裏，纔膺兩薦書。',48,'全唐诗/poet.song.224000.json','["底事三年裏，纔膺兩薦書。", "邦侯辨寶晚，使者設羅疎。", "知己初何計，能官自有餘。", "漢庭今欠者，子政與朱虛。"]'),
('52f8ec9e-1c4d-4034-9422-01c4f96a4dee','與毛教授','姚勉','宋','宋诗','song-poetry','','[]','舉世無清濁，誰歟障倒瀾。',48,'全唐诗/poet.song.224000.json','["舉世無清濁，誰歟障倒瀾。", "獨能驅鴈鶩，不使汙鵷鸞。", "此事雖云小，其人已可觀。", "近來峨豸者，欠此廣文官。"]'),
('276ecd3e-895d-4ac5-840a-7ae1b621b893','次陳肩夔韻','姚勉','宋','宋诗','song-poetry','','[]','蠻觸爭蝸角，興亡土兩丘。',48,'全唐诗/poet.song.224000.json','["蠻觸爭蝸角，興亡土兩丘。", "一家文到古，萬世月行秋。", "鰲可三山冠，鵬須八極遊。", "胸中治安策，時事幾堪憂。"]'),
('8ad99fa2-68e7-4c36-b9f6-3402cd7bfeb3','贈廬陵三劉神童','姚勉','宋','宋诗','song-poetry','','[]','唐時劉正字，今復見廬陵。',48,'全唐诗/poet.song.224000.json','["唐時劉正字，今復見廬陵。", "珠樹三根秀，金門一日登。", "贈君無句錦，覓我到溪冰。", "不爲炎凉變，童年有此能。"]'),
('dffbeafb-2a50-4bbd-bfe6-d0dd6ecd11a6','寄題上饒周儀仲西疇','姚勉','宋','宋诗','song-poetry','','[]','聞君負北郭，築室扁西疇。',48,'全唐诗/poet.song.224000.json','["聞君負北郭，築室扁西疇。", "綠水人家曉，黄雲穡事秋。", "吾生如有此，外物更何求。", "堪卜東鄰否，耕餘著釣舟。"]'),
('98bf79d8-eaa3-4edc-9d37-3f121f163cee','送胡教授之沅水任  其一','姚勉','宋','宋诗','song-poetry','','[]','君今鳴木鐸，名與芷俱香。',48,'全唐诗/poet.song.224000.json','["君今鳴木鐸，名與芷俱香。", "後夜月千里，美人天一方。", "往追湖學躅，更挈楚臣芳。", "了却臯比事，歸來振鷺行。"]'),
('de160aa0-bac7-44ef-8da0-2b66016c54b6','送胡教授之沅水任  其二','姚勉','宋','宋诗','song-poetry','','[]','近聞沅水路，今亦是風寒。',48,'全唐诗/poet.song.224000.json','["近聞沅水路，今亦是風寒。", "忠信如先教，邊陲儘易安。", "勿云師可去，甘與國辭難。", "文武能兼盡，功名更好看。"]'),
('2e787195-be93-4630-9912-d51a5c2871a8','有感','姚勉','宋','宋诗','song-poetry','','[]','范張心許友，餘耳面爲朋。',48,'全唐诗/poet.song.224000.json','["范張心許友，餘耳面爲朋。", "世路巇於嶺，交情薄似冰。", "綈袍非舊戀，結綬况同登。", "亦莫他人責，先施恐未能。"]'),
('82b822c9-7523-48f0-8f31-880f6349d210','夢太夫人如平生','姚勉','宋','宋诗','song-poetry','','[]','山鹿隨麋樂，林烏反哺慈。',48,'全唐诗/poet.song.224000.json','["山鹿隨麋樂，林烏反哺慈。", "傷心惟夢裏，有母似兒時。", "愛子平生念，思親隔世悲。", "松楸霜露冷，北望淚交頤。"]'),
('c43fab34-054c-4610-8b5a-16ebb3a4beeb','靈源上太夫人塚','姚勉','宋','宋诗','song-poetry','','[]','一別慈闈面，春風十五花。',48,'全唐诗/poet.song.224000.json','["一別慈闈面，春風十五花。", "不知人有母，誰念子無家。", "社雨鄰巢燕，清明壟樹鴉。", "動皆傷感處，慟哭夕陽斜。"]'),
('75450b7d-c8a6-4e7f-a0e7-47e89363ab5c','題族子霆伯西征錄','姚勉','宋','宋诗','song-poetry','','[]','閒味西征錄，霜橙嚼鱠虀。',48,'全唐诗/poet.song.224000.json','["閒味西征錄，霜橙嚼鱠虀。", "俊聲壓湖北，詩派接江西。", "鎮日心相憶，何時手重携。", "相期一樽酒，重與叩雲溪。"]'),
('12512b4a-2083-45ba-87ea-d144eee1fd4e','贈玉隆都監周抱一','姚勉','宋','宋诗','song-poetry','','[]','一別丹霞洞，何年到此邦。',48,'全唐诗/poet.song.224000.json','["一別丹霞洞，何年到此邦。", "犬隨燒藥鼎，鶴伴改詩窗。", "談柄風生席，清標月在江。", "西山聞欲隠，來訪鹿門龐。"]'),
('28ff5b23-5043-410b-a628-6f916c90d17d','晨興','姚勉','宋','宋诗','song-poetry','','[]','晨興未梳盥，此興亦何清。',48,'全唐诗/poet.song.224000.json','["晨興未梳盥，此興亦何清。", "看竹鈎簾坐，澆花遶逕行。", "葛巾聊復正，塵事即時生。", "安得簞瓢足，扃門遂野情。"]'),
('ba8e6caf-1907-46f1-8147-042ef53b3373','贈趙神眼','姚勉','宋','宋诗','song-poetry','','[]','杜門人事少，排闥相師來。',48,'全唐诗/poet.song.224000.json','["杜門人事少，排闥相師來。", "童子忙驅鶴，先生正看梅。", "煩君滕口說，如我豈身媒。", "水鏡能司馬，隆中覓異才。"]'),
('6157541c-f72f-4bea-a0f2-aa0826a9320b','安象祖携子餞行英爽可愛贈以詩嘉其有好德秉彝之天必能世其家','姚勉','宋','宋诗','song-poetry','','[]','西蜀安公子，爲謀不在身。',48,'全唐诗/poet.song.224000.json','["西蜀安公子，爲謀不在身。", "倚楹惟國事，于道亦忠臣。", "偉矣雙書藁，清哉箇逸民。", "丹心天所相，宜有此麒麟。"]'),
('fd1e9547-72ae-4e3b-ab2a-03e7e085f598','和姜明甫','姚勉','宋','宋诗','song-poetry','','[]','詔放山林去，時人冷眼看。',48,'全唐诗/poet.song.224000.json','["詔放山林去，時人冷眼看。", "新詩爲我贈，高義似君難。", "又說同年弟，尤知取友端。", "市將梅子隠，冠尚貢公彈。"]'),
('7e5d039d-13da-4a13-944f-c8924c61c9cc','和葛德遠  其一','姚勉','宋','宋诗','song-poetry','','[]','脫兔驚罝逸，潜魚畏餌逃。',48,'全唐诗/poet.song.224000.json','["脫兔驚罝逸，潜魚畏餌逃。", "山林聊復爾，湖海可曾豪。", "藥笑多方誤，棋嗟不著高。", "且須隨野鹿，共此食苹蒿。"]'),
('755a23fc-5a7a-42b3-b6c9-abc1b9152cda','和葛德遠  其二','姚勉','宋','宋诗','song-poetry','','[]','霧豹文雖隠，風蟬蛻即僊。',48,'全唐诗/poet.song.224000.json','["霧豹文雖隠，風蟬蛻即僊。", "伴書猶有劍，食硯豈無田。", "發藻多師董，思經敢笑邊。", "晚成知大器，天詔正求賢。"]'),
('4b217ea7-3b17-445e-bd00-b687a44ddc33','挽十尊長居士','姚勉','宋','宋诗','song-poetry','','[]','聘君今已矣，月入少微星。',48,'全唐诗/poet.song.224000.json','["聘君今已矣，月入少微星。", "又失宗盟長，空悲族譜亭。", "生芻嗟莫致，歌薤若爲聽。", "只喜陰功在，三槐已綠庭。"]'),
('c9609029-e262-42f2-8ae9-0e11fc4a6e12','又代作','姚勉','宋','宋诗','song-poetry','','[]','鹿門龐德公，款段馬少遊。',48,'全唐诗/poet.song.224000.json','["鹿門龐德公，款段馬少遊。", "古人不可今，君賢抑其流。", "清風足廉頑，厚德亦鎮浮。", "君今復古人，善士吾何求。"]'),
('f61d2206-e839-4ae4-8273-704a560137db','代挽甯西雲','姚勉','宋','宋诗','song-poetry','','[]','杜牧先銘墓，淵明自祭文。',48,'全唐诗/poet.song.224000.json','["杜牧先銘墓，淵明自祭文。", "兩賢真造理，百世又逢君。", "把釣溪沈月，著書山鎖雲。", "誰能上遺藁，堪辟木天雲。"]'),
('e7f8392e-fbb1-4318-a76e-ef0babeb8af0','元日試筆','姚勉','宋','宋诗','song-poetry','','[]','今歲新元最喜晴，宿陰都化作清明。',64,'全唐诗/poet.song.224000.json','["今歲新元最喜晴，宿陰都化作清明。", "氣從地角天涯轉，春向梅邊柳上生。", "鵷路五更鏘劍佩，虎關半夜出弓旌。", "羣賢儻在新除目，懽喜山中飽菜羹。"]'),
('a04bb449-b455-45c2-8a71-92f701a66a16','元宵雨','姚勉','宋','宋诗','song-poetry','','[]','東風已辦上元晴，入夜敲簷又雨聲。',64,'全唐诗/poet.song.224000.json','["東風已辦上元晴，入夜敲簷又雨聲。", "天下更無燈可賞，雲頭應是月孤明。", "遥知日甸驚回祿，未用星橋詫太平。", "旅舍一枝梅在燭，照人紅影十分清。"]'),
('7ae992c7-c1b2-484f-8a93-97a6106fd891','遊曲江分韻得日字','姚勉','宋','宋诗','song-poetry','','[]','曲江磯頭山崒嵂，此景江南誇第一。',64,'全唐诗/poet.song.224000.json','["曲江磯頭山崒嵂，此景江南誇第一。", "漁舟晚弄暖波閒，市樓春映晴嵐出。", "擁肩寒吟入圖畫，席地草飲成真率。", "更叩僧房借榻眠，再上山椒約明日。"]'),
('2e7ee06d-0ee9-4cec-be39-f4593b0606da','遊感山題甘露臺','姚勉','宋','宋诗','song-poetry','','[]','講師曾此雨天花，臺築山椒幾歲華。',64,'全唐诗/poet.song.224000.json','["講師曾此雨天花，臺築山椒幾歲華。", "一蓋雲松擎羽葆，四盤江水走龍蛇。", "好教絕頂崚嶒出，莫放濃陰薈蔚遮。", "應有醍醐餘味在，僧房試覓一盃茶。"]'),
('e97b2254-a2d2-4730-8d9f-39e955e861d3','題西湖竹閣寺  其一','姚勉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','入門纔見萬琅玕，便覺玲瓏日影寒。',64,'全唐诗/poet.song.224000.json','["入門纔見萬琅玕，便覺玲瓏日影寒。", "峰勢近環簷外立，湖光更好竹中看。", "煙霞古淡僧容瘦，風露清高鶴夢殘。", "已占兩亭凉坐足，再須登閣倚欄干。"]'),
('f4f0fd8d-15e8-46ad-953c-84e551e0d8ed','題西湖竹閣寺  其二','姚勉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','千古清風白樂天，昔時曾此飽談禪。',64,'全唐诗/poet.song.224000.json','["千古清風白樂天，昔時曾此飽談禪。", "自從西閣無吟跡，惟有東坡嗣舊傳。", "來往祇應湖上寺，聽聞誤說海中僊。", "我來再拜祠堂下，笑摘巖花薦井泉。"]'),
('f3eea3cd-4e6c-4ac5-9d20-97ff8fdb0179','瀛嶼','姚勉','宋','宋诗','song-poetry','','[]','自是瀛洲近帝鄉，孤峰宛在水中央。',64,'全唐诗/poet.song.224000.json','["自是瀛洲近帝鄉，孤峰宛在水中央。", "地雄海上三山境，天與僊家六月凉。", "雲母屏寒蒼檜色，水精奩啟碧湖光。", "雪中來此尤須別，好著珠蓑棹玉航。"]'),
('a9b976cf-0854-4169-8f85-6b53b54e6808','觀畫竹','姚勉','宋','宋诗','song-poetry','','[]','外間盾日正相仇，忽有清風起筆頭。',64,'全唐诗/poet.song.224000.json','["外間盾日正相仇，忽有清風起筆頭。", "坐對不知三伏熱，起行如與七賢遊。", "洗空京洛塵埃氣，化作江南水石秋。", "我有一溪恰如此，因君思去理扁舟。"]'),
('13694c7a-4932-4e38-b76e-87ad4064c940','詠金橘團','姚勉','宋','宋诗','song-poetry','','[]','雪不能甜橘小酸，若爲有此蜜冰團。',64,'全唐诗/poet.song.224000.json','["雪不能甜橘小酸，若爲有此蜜冰團。", "比將金彈可勝軟，嚼破水精如許寒。", "泉石碎聲鳴齒頰，乾坤清氣入脾肝。", "京華六月塵生渴，頼爾煩襟得自寬。"]'),
('8dcce5b0-42d6-43a3-b1e4-9d51b271bb36','思家信不至','姚勉','宋','宋诗','song-poetry','','[]','又是秋風入芰荷，尚無黄耳到如何。',64,'全唐诗/poet.song.224000.json','["又是秋風入芰荷，尚無黄耳到如何。", "慈親想自精神健，嬌女應添智慧多。", "踪跡自嗟成漫浪，利名底苦欲奔波。", "幾時了却胸中事，只傍南溪理釣蓑。"]'),
('8b1fd58a-75f1-485e-b186-f7c33b0b670d','有懷學子','姚勉','宋','宋诗','song-poetry','','[]','吾生傳癖更書癡，俳笑紛紛獨喜隨。',64,'全唐诗/poet.song.224000.json','["吾生傳癖更書癡，俳笑紛紛獨喜隨。", "篝火共窺韓子筆，煮茶細說杜陵詩。", "論交無此知心友，得句常于見面時。", "一念不教千里隔，慈恩花下夢微之。"]'),
('88cc749a-a49c-43d6-b86a-0f66b7a854fe','有懷族子','姚勉','宋','宋诗','song-poetry','','[]','秀出吾宗獨有君，等閒相別又秋新。',64,'全唐诗/poet.song.224000.json','["秀出吾宗獨有君，等閒相別又秋新。", "江山憔悴生歸思，風雨凄凉夢故人。", "天境儘供分石釣，雲溪擬卜住山鄰。", "何時對酒聽佳句，洗我胸中一斛塵。"]'),
('dd98b981-d25c-4247-82e8-7830e76c9f05','贈陳柏堂道士','姚勉','宋','宋诗','song-poetry','','[]','孤山古柏鬰蒼蒼，中有高人住此堂。',64,'全唐诗/poet.song.224000.json','["孤山古柏鬰蒼蒼，中有高人住此堂。", "峻入太空摩日月，清蟠勁氣挾風霜。", "葉餐曉露通僊藥，子爇宵煙謁帝香。", "已結歲寒方外友，願分一半白雲鄉。"]'),
('96a20fe5-3bf0-4dea-beaf-0c34c9b6ced5','題釣臺','姚勉','宋','宋诗','song-poetry','','[]','等閒伸脚動天文，須信乾坤繫此身。',64,'全唐诗/poet.song.224000.json','["等閒伸脚動天文，須信乾坤繫此身。", "天上有星猶是客，漢庭何事肯爲臣。", "祇當泉石容真隠，安可文書役故人。", "豈但雲臺高不似，釣臺草木至今春。"]'),
('e3051061-96d8-46aa-b9c4-b0fb076dee39','送陳新恩赴殿試','姚勉','宋','宋诗','song-poetry','','[]','桂花香滿月輪秋，穩送鵬程萬里遊。',64,'全唐诗/poet.song.224000.json','["桂花香滿月輪秋，穩送鵬程萬里遊。", "身近清光瞻帝座，手携多士上瀛洲。", "戊申奏對規模闊，庚戌掄魁氣數周。", "陳亮自來天下選，老年更好作龍頭。"]'),
('898ea403-7da8-4062-8c5c-d669984ca1f1','送同窗趙章甫上舍入京  其一','姚勉','宋','宋诗','song-poetry','','[]','正誼羣英自藹然，喜君已是著先鞭。',64,'全唐诗/poet.song.224000.json','["正誼羣英自藹然，喜君已是著先鞭。", "翼摶北海三千里，身在西雝尺五天。", "學舍快升優褐上，酒樓莫戀軟紅邊。", "雙親教子相期切，成取功名趁妙年。"]'),
('9ccafe21-2bd8-430d-9a79-093ae1674d68','送同窗趙章甫上舍入京  其二','姚勉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一別西湖又見春，夢魂長是繞湖濱。',64,'全唐诗/poet.song.224000.json','["一別西湖又見春，夢魂長是繞湖濱。", "爲煩竹閣揩題墨，更向梅花道故人。", "槐市舊遊休復問，龍門佳客尚能新。", "明年儻共昕庭對，願過當時蔡與陳。"]'),
('6b1e109c-45ce-44bd-8d52-47e4d2c8cb04','寄鄒希聖兄弟','姚勉','宋','宋诗','song-poetry','','[]','槐花又向此秋黄，槐未黄時趁早忙。',64,'全唐诗/poet.song.224000.json','["槐花又向此秋黄，槐未黄時趁早忙。", "龍到水高衝浪化，鵬因風厚貼雲翔。", "棠金鏃取霜筠健，越砥磨開電劍光。", "努力晨窗并夜案，天庭已動桂枝香。"]'),
('370ecd1c-91d9-4c0a-9413-b6ae0891c015','和郡侯勸駕韻  其一','姚勉','宋','宋诗','song-poetry','','[]','聖朝珍重設儒科，總總英賢入禮羅。',64,'全唐诗/poet.song.224000.json','["聖朝珍重設儒科，總總英賢入禮羅。", "天下豈無偕計上，日邊此獨得人多。", "僊橋快應龍頭讖，工席忻聆燕衎歌。", "雅志不爲溫飽計，尚期勳業等山河。"]'),
('242267b9-ebc4-44eb-b024-352b4c19775f','和郡侯勸駕韻  其二','姚勉','宋','宋诗','song-poetry','','[]','睎顔欲進聖門科，何意嫦娥剪綠羅。',64,'全唐诗/poet.song.224000.json','["睎顔欲進聖門科，何意嫦娥剪綠羅。", "拾紫不知如芥易，一紅也覺占春多。", "興賢借此雙旌重，得士歡於五袴歌。", "九萬扶摇風力健，穩吹槎馭上天河。"]'),
('d809a8c3-7e01-4c4c-b417-6bd4eb1a450d','和郡侯喜雨韻','姚勉','宋','宋诗','song-poetry','','[]','玉龍捲動海千尋，一滴天瓢水尺深。',64,'全唐诗/poet.song.224000.json','["玉龍捲動海千尋，一滴天瓢水尺深。", "農父带雲耕宿潤，使君喜雨入新吟。", "浪低麥隴收難速，針短秧疇插未禁。", "三日頓回生意滿，天心只在我公心。"]'),
('f6919536-673f-4be3-a1c4-fa250c89f25b','送趙判縣美任改除閬倅','姚勉','宋','宋诗','song-poetry','','[]','仁如愛日潔冰壺，鞭不曾施豈用蒲。',64,'全唐诗/poet.song.224000.json','["仁如愛日潔冰壺，鞭不曾施豈用蒲。", "吏服官清羞鬻獄，民憐邑窘競輸租。", "甘棠舍在春常滿，行李船空月亦無。", "展驥分州猶未稱，合於紫禁著飛鳬。"]'),
('c523dc08-b85e-4c57-80da-ea91db36dd05','和劉月湖縣尉','姚勉','宋','宋诗','song-poetry','','[]','不見元城不泗州，令人媿汗直如流。',64,'全唐诗/poet.song.224000.json','["不見元城不泗州，令人媿汗直如流。", "獲瞻沂水春風點，說到濂溪太極周。", "我豈能爲前輩役，君真合向古人求。", "考亭一派今寥落，還肯同登道閫不。"]'),
('985fcbb2-c7c8-4e50-8712-3710bbfeb99d','用樂魁聲道寄李後林韻寄聲道  其一','姚勉','宋','宋诗','song-poetry','','[]','尺書春寄忽驚秋，未見新除入報郵。',64,'全唐诗/poet.song.224000.json','["尺書春寄忽驚秋，未見新除入報郵。", "鐵漢尚疎丞相馬，玉兒肯伴秀才牛。", "欲令世事更新易，可使時賢不進休。", "子職顯揚千古事，聖恩深重更龍頭。"]'),
('9d4be440-7d6e-4328-9692-0dc477db42cd','用樂魁聲道寄李後林韻寄聲道  其二','姚勉','宋','宋诗','song-poetry','','[]','一葉梧桐喚動秋，分投閒散亦無郵。',64,'全唐诗/poet.song.224000.json','["一葉梧桐喚動秋，分投閒散亦無郵。", "超踰未羨詔金馬，遲鈍不妨騎土牛。", "天爵夐殊人爵貴，僞心那似德心休。", "讀書豈爲榮身計，何必三公要黑頭。"]'),
('d296da71-0fec-412d-9f9b-8262dac08494','再用前韻寄後林  其一','姚勉','宋','宋诗','song-poetry','','[]','別來知是幾三秋，書倩洪喬懶作郵。',64,'全唐诗/poet.song.224000.json','["別來知是幾三秋，書倩洪喬懶作郵。", "帛足忽傳來自鴈，軸腰更喜大如牛。", "信知蓋世名非枉，吟到驚人句未休。", "何日杖藜參口訣，歸來閉戶學從頭。"]'),
('5d1d24a7-54cc-4de0-878c-cf9ab1e0f4d1','再用前韻寄後林  其二','姚勉','宋','宋诗','song-poetry','','[]','貞心古幹健凌秋，人似淵明愧督郵。',64,'全唐诗/poet.song.224000.json','["貞心古幹健凌秋，人似淵明愧督郵。", "覽德未能儀舜鳳，干時那肯食秦牛。", "紋楸失著誰能整，黄間同機底未休。", "杜若山中人窈窕，白蘋風嫋楚江頭。"]'),
('8f2e102e-f0f9-47d6-8f64-daf612e424ea','送王新恩赴省','姚勉','宋','宋诗','song-poetry','','[]','老泉坡潁成名了，曾應君家木假山。',64,'全唐诗/poet.song.224000.json','["老泉坡潁成名了，曾應君家木假山。", "父與子偕升禮部，弟隨兄去入賢關。", "龍驅萬馬空如洗，鳳挾雙雛逸莫攀。", "早早歸來榮晝錦，綠衣爭映綵衣斑。"]'),
('9fb44575-627d-4725-ba33-16535ebd51b7','送萬仲榮赴省','姚勉','宋','宋诗','song-poetry','','[]','梅梢枯處忽東風，魁壓千花一點紅。',64,'全唐诗/poet.song.224000.json','["梅梢枯處忽東風，魁壓千花一點紅。", "歡喜馬頭飛雪處，安排龍首綵雲中。", "內訌外阻憂方大，東拄西撐策已窮。", "試了南宮趨北闕，好輸鯁論發天聰。"]'),
('9d78fe47-6a6e-40c9-94c8-40262a95a88a','送童子敬赴省','姚勉','宋','宋诗','song-poetry','','[]','滿望飛騰幾許年，一聞充賦喜如顛。',64,'全唐诗/poet.song.224000.json','["滿望飛騰幾許年，一聞充賦喜如顛。", "金經爐冶鋒方銳，木飽風霜節始堅。", "此去穩登雲裏路，定知榮冠籍中僊。", "近聞上蔡鸕洲合，一似前年錦水連。"]'),
('deac90a6-26cb-4f70-bd09-42ed2e0ac0df','送王元高兄弟東上  其一','姚勉','宋','宋诗','song-poetry','','[]','前歲親從月殿回，素娥引領到瑶臺。',64,'全唐诗/poet.song.224000.json','["前歲親從月殿回，素娥引領到瑶臺。", "桂枝指點教先折，僊籍披陳看後來。", "恰見拱辰名字接，一如公序弟兄魁。", "預將消息而今報，好作百花頭上梅。"]'),
('5da3fd7a-2e5b-432a-9152-229d28710563','送王元高兄弟東上  其二','姚勉','宋','宋诗','song-poetry','','[]','去去龍門客又新，一鞭猛過禹濤春。',64,'全唐诗/poet.song.224000.json','["去去龍門客又新，一鞭猛過禹濤春。", "竚觀極論陳三策，切莫潜兵救八人。", "沂國素無溫飽志，梅溪不作諂諛臣。", "二難兄弟當如此，及第歸來喜拜親。"]'),
('3fd446c7-3d7f-4f9c-a463-eca42d385385','送羅道甫歸廬陵應舉','姚勉','宋','宋诗','song-poetry','','[]','西風滿路桂枝香，催整登雲步月裝。',64,'全唐诗/poet.song.224000.json','["西風滿路桂枝香，催整登雲步月裝。", "羣輩總皆推德行，三年稔已聽文章。", "琅琅議論須披腹，瑣瑣功名只探囊。", "捷了早來談傑作，聳聞鳴鳳瑞朝陽。"]'),
('c3221248-d290-407c-831b-9ee6fd51d04e','送陳縣尉之太和新任','姚勉','宋','宋诗','song-poetry','','[]','古來尉自號神僊，况是棲身快閣天。',64,'全唐诗/poet.song.224000.json','["古來尉自號神僊，况是棲身快閣天。", "好向盤根施利器，如登熟路著先鞭。", "可知豈患無知己，自愛應能不愛錢。", "近世末僚卿相少，願儲遠業繼前賢。"]'),
('e72f5bf7-1378-4001-a51e-4a8b3c9f8681','送洪右司去官','姚勉','宋','宋诗','song-poetry','','[]','戀陟懷遷怕去官，近時君子退如難。',64,'全唐诗/poet.song.224000.json','["戀陟懷遷怕去官，近時君子退如難。", "中書堂拂高風袖，神武門留太華冠。", "此舉直堪驚醉夢，斯人端是障狂瀾。", "先生真正平齋子，凜凜清標萬古寒。"]'),
('7f4bf928-945d-42ae-8019-927e68aab6a5','寄題陳肩夔兄弟夢草堂','姚勉','宋','宋诗','song-poetry','','[]','謝池草句本無奇，千古流傳五字詩。',64,'全唐诗/poet.song.224000.json','["謝池草句本無奇，千古流傳五字詩。", "祇是可人醒枕席，許多生意在壎篪。", "信渠風雨聽眠處，快甚江山得助時。", "顧我此懷今已矣，羨君兄弟撚吟髭。"]'),
('2645713e-637e-4a2f-915a-a8d8791a596c','寄題陳肩夔雲錦窗','姚勉','宋','宋诗','song-poetry','','[]','八窗面面受新凉，萬蓋盈盈擁靚粧。',64,'全唐诗/poet.song.224000.json','["八窗面面受新凉，萬蓋盈盈擁靚粧。", "倩得天孫雲杼軸，織成騷客錦衣裳。", "雨翻綠浄盤中玉，風攪紅嬌鏡底香。", "箇裏搜詩最奇絕，吐爲黼黻五文章。"]'),
('fba6ec88-efb9-4d16-8c22-bf2580ed4bd7','奉題呂氏宜老堂','姚勉','宋','宋诗','song-poetry','','[]','此堂清不著珠璣，只要雙親佚老宜。',64,'全唐诗/poet.song.224000.json','["此堂清不著珠璣，只要雙親佚老宜。", "春酒儘堪眉壽介，斑衣長似乳時嬉。", "婦垂鶴髮陪姑緯，翁撚銀髯課子詩。", "飽飲菊花潭上水，鷄窠猶自拜孫枝。"]'),
('5d5f0b5b-4b70-4997-8392-69b28c68af38','和豐城鄒端簡韻就送其歸  其一','姚勉','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','千里携書謁帝閽，如君忠義出天根。',64,'全唐诗/poet.song.224000.json','["千里携書謁帝閽，如君忠義出天根。", "筳篿已卜回淵聽，寸草還思報厚恩。", "且共漁樵談帝霸，豈無豪俊整乾坤。", "細吟窗下廬山句，亦欲鄉人訪道原。"]'),
('2512174d-384a-47b1-8344-88c9609625e1','和豐城鄒端簡韻就送其歸  其二','姚勉','宋','宋诗','song-poetry','','[]','批了龍鱗歸釣魚，江濤帖息果天歟。',64,'全唐诗/poet.song.224000.json','["批了龍鱗歸釣魚，江濤帖息果天歟。", "腰雖未印衣重綵，囊縱無金篋有書。", "日可事劉宜令伯，天教名子更僑如。", "本原培養非愚計，遠業何妨厚自儲。"]'),
('3e225ca2-39ea-45fb-9293-c10832771fa9','題百花林書堂','姚勉','宋','宋诗','song-poetry','','[]','書堂靜占百花林，蜀錦香浮一逕陰。',64,'全唐诗/poet.song.224000.json','["書堂靜占百花林，蜀錦香浮一逕陰。", "楊柳軟風吹雨醒，海棠輕霧擁春深。", "盈樽有酒供清醉，滿眼皆詩足勝吟。", "冰雪相看人更好，竹君梅友歲寒心。"]'),
('684cad87-31e7-437a-88aa-976f2bb68858','溪山堂翫月','姚勉','宋','宋诗','song-poetry','','[]','前山杳靄翠煙凝，幾點疎星隔岸燈。',64,'全唐诗/poet.song.224000.json','["前山杳靄翠煙凝，幾點疎星隔岸燈。", "不是飛來千里月，如何照徹一壺冰。", "天開圖畫無窮趣，人在林巒最上層。", "動智靜仁須有得，欄干莫只等閒凭。"]'),
('0519783e-c750-467e-856d-c14ff268ef21','招友人鳳山觀雪','姚勉','宋','宋诗','song-poetry','','[]','霜風纔辦兩朝晴，怪聽敲窗又雨聲。',64,'全唐诗/poet.song.224000.json','["霜風纔辦兩朝晴，怪聽敲窗又雨聲。", "一夜忽生虛室白，六花已與短簷平。", "酒斟銷帳真成俗，興盡扁舟且未清。", "想得鳳山高處好，試來著屐水精城。"]'),
('9dad032c-6458-44d3-8b8a-8b38d0296fde','入京遇雪','姚勉','宋','宋诗','song-poetry','','[]','馬頭雪絮舞花深，便覺新陽改故陰。',64,'全唐诗/poet.song.224000.json','["馬頭雪絮舞花深，便覺新陽改故陰。", "天上素光開玉府，眼前一色是瓊林。", "定知洄曲師當捷，且把新豐酒獨斟。", "萬木怯寒頭正縮，梅花一點露春心。"]'),
('0cb2b4ef-be80-4902-9fc3-83ddf36b71d4','道中積雨','姚勉','宋','宋诗','song-poetry','','[]','纔起程時雪絮春，雪餘又是雨兼旬。',64,'全唐诗/poet.song.224000.json','["纔起程時雪絮春，雪餘又是雨兼旬。", "肩輿聊復能安穩，步屧其如受苦辛。", "楮賤米窮嘗世味，風餐露宿鍊官身。", "一朝儻有青雲上，莫忘泥耕水耨人。"]'),
('50fe4cec-abad-4e33-80df-4bb53c7c4efd','贈俊上人雪崖','姚勉','宋','宋诗','song-poetry','','[]','雪崖來覓雪坡詩，崖險坡平雪總宜。',64,'全唐诗/poet.song.224000.json','["雪崖來覓雪坡詩，崖險坡平雪總宜。", "每羨僧房聞竹折，終强俗客聽窗知。", "巖收泉竇無聲溜，石壓梅花側出枝。", "到了紅爐融一片，須還門外尺深時。"]'),
('8ae85b91-e21d-474d-af49-8d6c835ac25c','題道士碧潭','姚勉','宋','宋诗','song-poetry','','[]','幽人何處倚漁竿，百頃清潭浸碧寒。',64,'全唐诗/poet.song.224000.json','["幽人何處倚漁竿，百頃清潭浸碧寒。", "不動一波疑水定，中涵萬象覺天寬。", "山將螺髻堆銅鏡，月借玻瓈現玉盤。", "莫作窈深無底看，是間應有卧龍蟠。"]'),
('0912af4c-6dac-4d59-b660-7b8e8e772434','贈朱五星','姚勉','宋','宋诗','song-poetry','','[]','貴賤由來不自齊，巧將躔次說高低。',64,'全唐诗/poet.song.224000.json','["貴賤由來不自齊，巧將躔次說高低。", "星環雲漢胸羅列，斗挹天漿手獨提。", "太乙昨傳當蜀道，文昌今喜尚江西。", "中興氣運應從此，試問何時復聚奎。"]'),
('e9c9a87c-f13e-43ff-9e13-33c9c9fc56c2','廷唱謝恩','姚勉','宋','宋诗','song-poetry','','[]','赭袍黄屋儼臨軒，獨立班頭領衆僊。',64,'全唐诗/poet.song.224000.json','["赭袍黄屋儼臨軒，獨立班頭領衆僊。", "五色雲乘金殿日，一聲雷繞玉除天。", "浮榮何敢矜科第，實地惟知學聖賢。", "深重君恩無以報，疾風草勁雪松堅。"]'),
('ec736fa3-6a77-4bfa-87f7-e6558dcb7d29','恭和御賜詩','姚勉','宋','宋诗','song-poetry','','[]','叨塵愧甚鶴乘軒，誓報洪私敢塞源。',64,'全唐诗/poet.song.224000.json','["叨塵愧甚鶴乘軒，誓報洪私敢塞源。", "回有聖明真願輔，軻於仁義豈忘言。", "清朝長欲諸賢在，公論常扶一脈存。", "湛露獨霑慚過厚，盍推四海遍皇恩。"]'),
('12c536b8-5731-4cf9-bc69-109309e565b9','聞吳山鐘','姚勉','宋','宋诗','song-poetry','','[]','舉世昏昏醉夢中，一聲震撼自天宮。',64,'全唐诗/poet.song.224000.json','["舉世昏昏醉夢中，一聲震撼自天宮。", "鼇呿大海三山動，獅吼危巔萬獸空。", "待漏早朝驚假寐，求衣宵起寤宸聰。", "須臾濁霧都收歛，喚出扶桑皎日紅。"]'),
('46488ec5-7d73-4d4f-86b5-68e3146fde1f','寄題武安節推同年萬君定翁露香堂','姚勉','宋','宋诗','song-poetry','','[]','盡將心事寫成碑，大要操修在不欺。',64,'全唐诗/poet.song.224000.json','["盡將心事寫成碑，大要操修在不欺。", "此一瓣香前輩似，只三箇字老天知。", "素瓶貯豆應先滿，匹馬携琴料自隨。", "吾榜得人今又盛，會排介甫擊升之。"]'),
('7d8ad59b-14c7-446a-90a5-b6c28f6c1a64','送鄭編修子四省元  其一','姚勉','宋','宋诗','song-poetry','','[]','文章得印天嘗靳，家世傳燈古亦疎。',64,'全唐诗/poet.song.224000.json','["文章得印天嘗靳，家世傳燈古亦疎。", "幸甚遷能紬石室，惜哉昶亦誤銀車。", "君今自是人龍子，名復高橫薦鶚書。", "讀飽鄴侯三萬軸，放高通德舊門閭。"]'),
('145436ea-5e64-40eb-a90f-be0da35eae5b','送鄭編修子四省元  其二','姚勉','宋','宋诗','song-poetry','','[]','著身書带草堂中，得與郎君硯席同。',64,'全唐诗/poet.song.224000.json','["著身書带草堂中，得與郎君硯席同。", "能學鳴蟬宜賦好，不求野鶩自書工。", "壯懷直擬聯龍虎，別恨休驚背燕鴻。", "他日東山香宇宙，格齋方不負誠翁。"]'),
('e93d7b21-3ed2-421f-b057-0245761b08d5','次韻黄東野德明且識初識','姚勉','宋','宋诗','song-poetry','','[]','敲冰燒葉煮槍旗，一笑平生識面遲。',64,'全唐诗/poet.song.224000.json','["敲冰燒葉煮槍旗，一笑平生識面遲。", "道上孔程傾蓋日，酒邊賀白解貂時。", "飽參霽月光風趣，似讀晴煙暖霧詩。", "甚欲爲雲從上下，只愁龍去渺無期。"]'),
('7cc941b3-3f4d-4347-b139-c8b0e4145c6f','奉餞萬安贊府兄長之官  其一','姚勉','宋','宋诗','song-poetry','','[]','有客來從仕國中，多時竹馬閙兒童。',64,'全唐诗/poet.song.224000.json','["有客來從仕國中，多時竹馬閙兒童。", "爭言記壁崔斯立，今屬詩家姚武功。", "一節清如金掌露，十分明似水晶籠。", "先聲已好爲官易，飛鶚聯翩遇順風。"]'),
('e59d472f-8bbc-4f9b-97ca-ea1b9a7c7727','奉餞萬安贊府兄長之官  其二','姚勉','宋','宋诗','song-poetry','','[]','天下如今怕縣灘，廬陵見說縣尤難。',64,'全唐诗/poet.song.224000.json','["天下如今怕縣灘，廬陵見說縣尤難。", "抉搜隠匿嘖豪戶，遲鈍催科怒上官。", "革弊有方須是漸，卹民到底莫如寬。", "萬家壯邑雖煩劇，邑相能賢儘易安。"]'),
('ba0d19e2-56dc-428a-868f-fbd1f2a8a608','奉餞萬安贊府兄長之官  其三','姚勉','宋','宋诗','song-poetry','','[]','吾族年來亦自奇，兩年兩度報瓜時。',64,'全唐诗/poet.song.224000.json','["吾族年來亦自奇，兩年兩度報瓜時。", "班行笑我難安脚，州縣輸君省皺眉。", "學不濟時非有用，官能及物儘堪爲。", "山林肥遯方深密，夢入春池但寄詩。"]'),
('406df4c7-abe5-4146-8643-ae88fb749146','和趙提刑韻送呂堂長主簿  其一','姚勉','宋','宋诗','song-poetry','','[]','道在顔瓢樂不憂，清風端可繼前修。',64,'全唐诗/poet.song.224000.json','["道在顔瓢樂不憂，清風端可繼前修。", "朅將西澗重新了，莫是東萊再出不。", "學校諸生俱嚮仰，文章太守共賡酬。", "戍瓜忽及東吾道，輕重從知繫去留。"]'),
('671c01a9-f797-41a0-9cd7-a0795ce7ecf1','和趙提刑韻送呂堂長主簿  其二','姚勉','宋','宋诗','song-poetry','','[]','擘脯鈎鱸倩老羝，離腸那肯話酸悽。',64,'全唐诗/poet.song.224000.json','["擘脯鈎鱸倩老羝，離腸那肯話酸悽。", "題橋舊事傳邛蜀，衣錦新榮耀會稽。", "未領衆星朝極北，且擎一柱立天西。", "鳳鸞止止寧棲棘，五色雲間有紫泥。"]'),
('49581193-2c6b-4863-bf78-95cb6c7ae463','乙卯七月庚子魁祀禮成同舍諸新元相與宴擬鹿鳴也故敢亦擬勸駕詩呈幸領此意','姚勉','宋','宋诗','song-poetry','','[]','四州八邑此同窗，鏗石鏘金日擊撞。',64,'全唐诗/poet.song.224000.json','["四州八邑此同窗，鏗石鏘金日擊撞。", "鵬翼相將摶北海，龍頭更奪過西江。", "蒿苹是日開先宴，萸菊他時捷各邦。", "橫浦自期吾豈敢，玉山對策又無雙。"]'),
('4cacd2fd-1428-457c-a263-9d9482918879','次友人示詩集  其一','姚勉','宋','宋诗','song-poetry','','[]','杖藜看笋數犀株，天墮香雲五色書。',64,'全唐诗/poet.song.224000.json','["杖藜看笋數犀株，天墮香雲五色書。", "落月照人驚夢昨，光風識面記春初。", "珠駢巧語誰能揀，錦比新詩迥不如。", "轉讀轉佳難去手，眉間愁思爲君舒。"]'),
('9e1139f5-e6bd-465f-9d37-ba9723fa087a','次友人示詩集  其二','姚勉','宋','宋诗','song-poetry','','[]','錦江前日解征鞍，剩擬春衫準酒歡。',64,'全唐诗/poet.song.224000.json','["錦江前日解征鞍，剩擬春衫準酒歡。", "杜宇有聲催客去，海棠無伴與誰看。", "而今柳巷青春老，又是秧塍白水漫。", "君欲相思須命駕，休言別易盍簪難。"]'),
('209970d2-3d20-463e-b79e-71c366059ecc','次友人示詩集  其三','姚勉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','去歲春風客帝京，西湖煙雨過清明。',64,'全唐诗/poet.song.224000.json','["去歲春風客帝京，西湖煙雨過清明。", "蘇堤畫舫春三月，天竺清鐘夜五更。", "行李裹書歸舊隠，野花沽酒賞新晴。", "只緣未讀時文熟，端合山中且菜羹。"]'),
('ba930eae-296c-4375-917c-955a3ec277dc','次韻諸友遊雲居  其一','姚勉','宋','宋诗','song-poetry','','[]','又是東風柳絮時，催春尚喜杜鵑遲。',64,'全唐诗/poet.song.224000.json','["又是東風柳絮時，催春尚喜杜鵑遲。", "雨晴蔓綠侵高木，風定殘紅閣舊枝。", "眼底好山娛意思，耳邊幽鳥話心期。", "雲居見說郊行樂，不得騎馿背錦隨。"]'),
('f9c6d7d4-2d8c-4db7-9e05-ea4d4584eaf9','次韻諸友遊雲居  其二','姚勉','宋','宋诗','song-poetry','','[]','絮風絲日颺新晴，望柳前川學大程。',64,'全唐诗/poet.song.224000.json','["絮風絲日颺新晴，望柳前川學大程。", "浪不起花澄沼徹，雲無留葉太虛清。", "林間整屐聞鶑語，竹外搘筇數蟻行。", "底事春愁都減盡，新來不似舊鍾情。"]'),
('ff98b909-9c40-4dde-b51d-fec5b67c25e7','和松窗主人薦墨客詩','姚勉','宋','宋诗','song-poetry','','[]','久不欹眠聽說詩，心茅又塞介然蹊。',64,'全唐诗/poet.song.224000.json','["久不欹眠聽說詩，心茅又塞介然蹊。", "那能蠶雨鳴窗葉，徒自鷄天舞甕醯。", "詩態笑看雲靄靄，客懷喚醒曉凄凄。", "龍香惠我真安用，君有佳篇好自題。"]'),
('f1487717-d037-4fbe-bad1-6941fafd047a','和通判直閣立春聞鶑  其一','姚勉','宋','宋诗','song-poetry','','[]','寂寂江城又立春，土牛何物竟無神。',64,'全唐诗/poet.song.224000.json','["寂寂江城又立春，土牛何物竟無神。", "試傾官酒梅花畔，不似園丁菜把新。", "綵勝豈留良夜夢，紙窗靜拂隔年塵。", "東風畢竟於人好，早有鶑聲入鬢唇。"]'),
('4d72c1ea-eae6-4bb2-b3a9-0715d0529c92','和通判直閣立春聞鶑  其二','姚勉','宋','宋诗','song-poetry','','[]','畫角聲中曉喚春，依城柳眼又精神。',64,'全唐诗/poet.song.224000.json','["畫角聲中曉喚春，依城柳眼又精神。", "試呼臘蟻梅邊酌，恰喜朝鶑雪底新。", "幽谷暖融空翠濕，上林香動軟紅塵。", "燕樓暗想翻新曲，惱破朱櫻一點唇。"]'),
('b0fe7bfa-5572-4e2c-97d6-8a610d6c31c7','和張公望苦熱韻  其一','姚勉','宋','宋诗','song-poetry','','[]','火傘停空更不移，此身如著甑中炊。',64,'全唐诗/poet.song.224000.json','["火傘停空更不移，此身如著甑中炊。", "蠅方附熱爭投案，蟬欲追凉別過枝。", "靜話竹窗煎雪浪，倦投水館卧風漪。", "渠儂箇底休嫌熱，聞道瀘南正出師。"]'),
('d638e864-8bd8-4563-b749-4a78c6038859','和張公望苦熱韻  其二','姚勉','宋','宋诗','song-poetry','','[]','一榻尋凉晝幾移，畏看煙火欲停炊。',64,'全唐诗/poet.song.224000.json','["一榻尋凉晝幾移，畏看煙火欲停炊。", "喜聽晚雨鳴荷葉，安得秋風起桂枝。", "林靜獨宜眠綠蔭，波寒誰伴釣清漪。", "讀君妙句真如濯，願拜敲推一字師。"]'),
('14676500-0653-45f1-9b97-94f821878aaa','題朱氏梅芳書院','姚勉','宋','宋诗','song-poetry','','[]','玉梅蒼竹擁冰壺，中有揚雄宅一區。',64,'全唐诗/poet.song.224000.json','["玉梅蒼竹擁冰壺，中有揚雄宅一區。", "地占清虛開境界，人從確實作工夫。", "窮經得趣床橫易，體道存心壁畫圖。", "格物致知功用大，的傳願繼考亭朱。"]'),
('d40c0582-1531-46b9-bc38-dbe38627402e','題胡景顔雙清堂','姚勉','宋','宋诗','song-poetry','','[]','石灘江上一詩仙，家住雙清小有天。',64,'全唐诗/poet.song.224000.json','["石灘江上一詩仙，家住雙清小有天。", "句裏出奇超象外，人閒無事到吟邊。", "讀騷長在滋蘭畹，好客多留種秫田。", "見說尚參顔樂處，今時誰似若人賢。"]'),
('9ea36cba-004c-4577-9b3e-3cf00fb89b0f','題華嚴寺','姚勉','宋','宋诗','song-poetry','','[]','蕭寺恭拈一瓣香，漢宮遥上萬年觴。',64,'全唐诗/poet.song.224000.json','["蕭寺恭拈一瓣香，漢宮遥上萬年觴。", "庚申再造皇基遠，甲子新開御曆長。", "萬物總歸春宇宙，八荒都入壽封疆。", "小臣政此朝天闕，葵藿傾心仰太陽。"]'),
('86223e61-8842-47f8-92c8-a6f4c233f7ca','送別張倅','姚勉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滿襟霽月皎無塵，愛客寧嫌客過頻。',64,'全唐诗/poet.song.224000.json','["滿襟霽月皎無塵，愛客寧嫌客過頻。", "倚竹題詩驚思妙，傍花尋柳見情真。", "如今南浦傷行客，此處西湖有主人。", "與著三年端的約，孤山同訪早梅春。"]'),
('f5664d2d-415f-4cda-90d4-92de5b087261','送別趙倅','姚勉','宋','宋诗','song-poetry','','[]','寶婺星邊太白僊，馭風飛下錦河邊。',64,'全唐诗/poet.song.224000.json','["寶婺星邊太白僊，馭風飛下錦河邊。", "朅來盡散陽春脚，歸去獨撐明月船。", "名重題輿千里郡，詔催步履八花磚。", "只愁此後民艱食，誰與邦民作食天。"]'),
('881c76eb-4ffc-4d36-a0fd-fd7c7993fe91','和友人春雪韻','姚勉','宋','宋诗','song-poetry','','[]','曉來積雪被長巒，約住春和縱臘寒。',64,'全唐诗/poet.song.224000.json','["曉來積雪被長巒，約住春和縱臘寒。", "諂賀豈堪隨味道，高眠且只學袁安。", "謾驚柳絮攙先舞，獨愛梅花奈久看。", "安得化爲千萬庾，放教糴事一分寬。"]'),
('63c3f9c9-c1b7-412f-bed7-ec92e7b7cfac','丁巳春夏之交巨浸屢至小民艱食郡侯請諸寓貴講行賑濟漸就次第僉幕有撓其議而變其法者楊監簿再來請入局商榷不赴寄以詩','姚勉','宋','宋诗','song-poetry','','[]','趁晴亦欲强追陪，爭奈濃陰墨樣堆。',64,'全唐诗/poet.song.224000.json','["趁晴亦欲强追陪，爭奈濃陰墨樣堆。", "燕子纔銜春色至，鵓鴣又喚雨聲來。", "從教野草爭先長，勒住名花莫浪開。", "世道而今總如此，竹關深閉且擎杯。"]'),
('f8c5bd47-0a3f-401e-8ed2-9e52f9a24c73','戊午喜罷和糴  其一','姚勉','宋','宋诗','song-poetry','','[]','聖主天姿本至仁，豈容重糴久傷民。',64,'全唐诗/poet.song.224000.json','["聖主天姿本至仁，豈容重糴久傷民。", "聳傳丹鳳銜來詔，媿殺蒼鷹枉做人。", "方峻符移譁叫突，忽收箠楚罷吟呻。", "歡聲和氣乾坤滿，爭祝皇齡萬萬春。"]'),
('22993a9b-5872-4f97-9a22-8cbe3cb58130','戊午喜罷和糴  其二','姚勉','宋','宋诗','song-poetry','','[]','到處相思虎政苛，設官本意果如何。',64,'全唐诗/poet.song.224000.json','["到處相思虎政苛，設官本意果如何。", "民今不足將誰足，糴本名和豈是和。", "一例冉求增聚歛，幾人陽子拙催科。", "昨來投劾歸歟者，到底賢聲却不磨。"]'),
('4f425b7e-e3a8-458f-a5a6-691569bcb5b7','戊午喜罷和糴  其三','姚勉','宋','宋诗','song-poetry','','[]','珍重蕭灘刺史賢，能令四海遍皇恩。',64,'全唐诗/poet.song.224000.json','["珍重蕭灘刺史賢，能令四海遍皇恩。", "奏篇纔上旋如請，明主何嘗不可言。", "彼已任教書課最，若人方稱冊臨軒。", "正愁舉世皆喑啞，也有朝陽鳳叫閽。"]'),
('598a845b-1971-4453-a564-e6f391401e33','戊午喜罷和糴  其四','姚勉','宋','宋诗','song-poetry','','[]','虐糴安能峙糗糧，只因根本暗中戕。',64,'全唐诗/poet.song.224000.json','["虐糴安能峙糗糧，只因根本暗中戕。", "並緣鼠猾豐衣食，受納狼貪富橐囊。", "中戶白科都罄室，列城黑腐謾盈倉。", "邊塵澒洞烽煙急，民命如絲謹勿傷。"]'),
('28ae8ee7-8aed-479b-9960-24fb8ab0564f','和鄒希賢舟中遇風雨','姚勉','宋','宋诗','song-poetry','','[]','湖干野泊不知更，水國荒寒愴旅情。',64,'全唐诗/poet.song.224000.json','["湖干野泊不知更，水國荒寒愴旅情。", "一夜奔雷吁可怪，滿空寒雨注如傾。", "颶風翻海驅潮勢，戰鼓轟天震地聲。", "到曉定應三尺雪，短篷忽漏赤暾明。"]'),
('cfd2a02b-e4ee-41ca-95f8-573181538a13','次方峻峰餞行韻并柬蛟峰','姚勉','宋','宋诗','song-poetry','','[]','公孫曲學聽渠阿，正則寧隨上下波。',64,'全唐诗/poet.song.224000.json','["公孫曲學聽渠阿，正則寧隨上下波。", "浪憶笑談今已矣，不知眠飯近如何。", "故人几上書應少，俗客門前屨豈多。", "頼有潁濱相慰藉，夜床風雨對東坡。"]'),
('332cadda-d122-4266-8fe3-9e4c5384a5ec','和劉山居見惠之什  其一','姚勉','宋','宋诗','song-poetry','','[]','久矣蓴鱸欲趁歸，自知花樣不隨時。',64,'全唐诗/poet.song.224000.json','["久矣蓴鱸欲趁歸，自知花樣不隨時。", "巖張欲保君心泰，英竦終嫌聖德詩。", "榮辱不知欣我在，怨尤俱泯恃天知。", "達官格子那能學，橫艇何妨釣野池。"]'),
('432c34f5-7a8e-48e5-b5a9-000b049d642b','和劉山居見惠之什  其二','姚勉','宋','宋诗','song-poetry','','[]','喜逐秋風馬後歸，及君猶未戍瓜時。',64,'全唐诗/poet.song.224000.json','["喜逐秋風馬後歸，及君猶未戍瓜時。", "盡傾無底囊中語，細讀新吟卷裏詩。", "好趣莫教兒輩覺，此心惟有故人知。", "只愁天欲孤籠翼，早晚芙蓉在綠池。"]'),
('1a12302c-4443-48c0-97a9-181bcf984c07','西山庵居','姚勉','宋','宋诗','song-poetry','','[]','作者于今已幾人，謝天放我出紅塵。',64,'全唐诗/poet.song.224000.json','["作者于今已幾人，謝天放我出紅塵。", "尋渠林鹿沙鷗伴，乞得孤雲野鶴身。", "閒味聖賢皆古意，靜觀景物四時春。", "元正除授君知否，食邑西風號逸民。"]'),
('4bc00be9-cca3-4586-b2b2-fb5e4d826dd2','贈術士姚有應自號通靈心神仙口  其一','姚勉','宋','宋诗','song-poetry','','[]','一點靈虛鏡樣明，只須提掇要常醒。',64,'全唐诗/poet.song.224000.json','["一點靈虛鏡樣明，只須提掇要常醒。", "微幾纔動先知吉，萬象交森獨測靈。", "至寂靜中能有感，遍酬應後却無形。", "死灰枯木都非法，但讀吾儒一字經。"]'),
('42abdf49-8bc2-4e76-84ab-0b6462fa707d','贈術士姚有應自號通靈心神仙口  其二','姚勉','宋','宋诗','song-poetry','','[]','僊在虛懷不可知，神僊有口欲何爲。',64,'全唐诗/poet.song.224000.json','["僊在虛懷不可知，神僊有口欲何爲。", "餐風吸露囂塵表，說地談天爛醉時。", "不带一星煙火氣，儘饒三寸帝王師。", "到頭莫把真機泄，靜默元來未是癡。"]'),
('e166bfda-c116-4f5e-bdc9-855e52773687','代謁張別駕  其一','姚勉','宋','宋诗','song-poetry','','[]','入境歡聲聽野農，題輿今有曲江公。',64,'全唐诗/poet.song.224000.json','["入境歡聲聽野農，題輿今有曲江公。", "官居寒露清冰裏，人在光風霽月中。", "席有新詩吟客滿，案無滯牘訟庭空。", "只愁驥足難淹久，行捧絲綸入漢宮。"]'),
('0df51169-e819-4210-b5f7-aee649431631','代謁張別駕  其二','姚勉','宋','宋诗','song-poetry','','[]','放浪江湖已幾年，袖携長劍倚天邊。',64,'全唐诗/poet.song.224000.json','["放浪江湖已幾年，袖携長劍倚天邊。", "草廬不見蜀諸葛，采石謾思唐謫僊。", "虎穴未能酬素志，龍門端合謁時賢。", "鄉邦幸有乖崖在，庶許諸生學李畋。"]'),
('a11ae0f7-c5a8-4567-b592-3eb4659c7397','挽趙制機','姚勉','宋','宋诗','song-poetry','','[]','見說襄陽墮甑時，公嘗前此料危機。',64,'全唐诗/poet.song.224000.json','["見說襄陽墮甑時，公嘗前此料危機。", "傷心漢峴疆重拓，回首羊鄒事已非。", "安得籌邊書日報，誰能薦士剡天飛。", "當年子羽知吳玠，尚作西撐一柱巍。"]'),
('340d0f20-c523-4c43-9af1-405c70f094d0','梅境','姚勉','宋','宋诗','song-poetry','','[]','僊家瑶林天，移來在江國。',24,'全唐诗/poet.song.224000.json','["僊家瑶林天，移來在江國。", "誰歟境中人，山立而玉色。"]'),
('9c09d9c8-a214-429d-9c40-129094febc60','桂莊','姚勉','宋','宋诗','song-poetry','','[]','不求田二頃，只種桂爲莊。',24,'全唐诗/poet.song.224000.json','["不求田二頃，只種桂爲莊。", "秋滿黄金粟，飽餐風露香。"]'),
('6c6c2af2-12ff-42c4-b39f-96488d838d1d','仁山','姚勉','宋','宋诗','song-poetry','','[]','山爲仁者樂，况復字爲仁。',24,'全唐诗/poet.song.224000.json','["山爲仁者樂，况復字爲仁。", "坐與茲山對，靜中天地春。"]'),
('f11eff1f-2bfa-458e-883d-d1e2ec324001','題月磯詩藁','姚勉','宋','宋诗','song-poetry','','[]','古苔磯上立，釣爲月明垂。',24,'全唐诗/poet.song.224000.json','["古苔磯上立，釣爲月明垂。", "夜半清歌起，無魚釣得詩。"]'),
('bb8de132-d779-4463-896f-a2bbe9bb07de','湖上釣者','姚勉','宋','宋诗','song-poetry','','[]','荷風湖面曉，垂釣柳陰中。',24,'全唐诗/poet.song.224000.json','["荷風湖面曉，垂釣柳陰中。", "何日能蓑笠，扁舟此興同。"]'),
('6d75eae2-7c39-431e-ab60-ff538c637cbe','題雪竹扇','姚勉','宋','宋诗','song-poetry','','[]','此君腰不折，玉立有餘清。',24,'全唐诗/poet.song.224000.json','["此君腰不折，玉立有餘清。", "曉窗擁鼻吟，聽渠落冰聲。"]'),
('80eefa4b-0eaf-446b-8b60-7b163a776195','王君猷花圃八絕 海棠城','姚勉','宋','宋诗','song-poetry','','[]','家住山水國，種花以爲城。',24,'全唐诗/poet.song.224000.json','["家住山水國，種花以爲城。", "詩將日登陴，圍春驅酒兵。"]'),
('484395c2-c6e4-41ab-b296-ea69364c1b05','王君猷花圃八絕 薇香洞','姚勉','宋','宋诗','song-poetry','','[]','密粟出濃紫，幽花間深黄。',24,'全唐诗/poet.song.224000.json','["密粟出濃紫，幽花間深黄。", "有誰吟其間，含香一薇郎。"]'),
('7e212a7a-de66-4d2e-b30f-a1d36268954c','王君猷花圃八絕 若春','姚勉','宋','宋诗','song-poetry','','[]','靜中見萬物，各各有春意。',24,'全唐诗/poet.song.224000.json','["靜中見萬物，各各有春意。", "收拾入襟懷，陽和散天地。"]'),
('06428217-1416-49ce-9135-03cdd6ab56a1','王君猷花圃八絕 花谷','姚勉','宋','宋诗','song-poetry','','[]','羣花各嬌春，粲若錦繡谷。',24,'全唐诗/poet.song.224000.json','["羣花各嬌春，粲若錦繡谷。", "於焉日逍遥，中有人如玉。"]'),
('fa7ab0f6-7670-4046-a819-4812174b87fa','王君猷花圃八絕 橘隠','姚勉','宋','宋诗','song-poetry','','[]','商山不茹芝，對弈寄此橘。',24,'全唐诗/poet.song.224000.json','["商山不茹芝，對弈寄此橘。", "巴人忽招隠，似爲子房出。"]'),
('56b42350-19ff-4d8b-abc6-cd0782f75c3f','王君猷花圃八絕 臨清橋','姚勉','宋','宋诗','song-poetry','','[]','通渠入小池，循除㶁㶁鳴。',24,'全唐诗/poet.song.224000.json','["通渠入小池，循除㶁㶁鳴。", "羣魚忽悠然，過橋聞屐聲。"]'),
('efc823a6-90b9-472c-8d72-d0f87db42f86','王君猷花圃八絕 山扉','姚勉','宋','宋诗','song-poetry','','[]','一逕綠陰去，隠隠花竹幽。',24,'全唐诗/poet.song.224000.json','["一逕綠陰去，隠隠花竹幽。", "主人地行仙，終日杖屨遊。"]'),
('326b1622-7f21-40f9-a976-46a4eccb3bd4','王君猷花圃八絕 鑑池','姚勉','宋','宋诗','song-poetry','','[]','春風鑑池水，長年弄清暉。',24,'全唐诗/poet.song.224000.json','["春風鑑池水，長年弄清暉。", "仙翁晚歸來，子孫笑牽衣。"]'),
('a94a1960-f9be-474a-9bc1-ba473f171a34','感山十詠 松關','姚勉','宋','宋诗','song-poetry','','[]','舍舟上招提，遥入松林間。',24,'全唐诗/poet.song.224000.json','["舍舟上招提，遥入松林間。", "透脫俗塵網，是名第一關。"]'),
('0522509b-f7e3-4455-a181-173b727b1285','感山十詠 翠鎖','姚勉','宋','宋诗','song-poetry','','[]','濃綠滴濕衣，煙嵐翠交鎖。',24,'全唐诗/poet.song.224000.json','["濃綠滴濕衣，煙嵐翠交鎖。", "名韁莫能縶，方此不失我。"]'),
('80a2df43-99c8-4d44-a8c4-7f4df17faff4','感山十詠 感山','姚勉','宋','宋诗','song-poetry','','[]','山以感爲名，可見天地情。',24,'全唐诗/poet.song.224000.json','["山以感爲名，可見天地情。", "萬籟恬不作，風來自松聲。"]'),
('bce1cab6-864c-41ea-8e56-8cac0991dea3','感山十詠 石橋','姚勉','宋','宋诗','song-poetry','','[]','石梁平砥似，池水明鏡如。',24,'全唐诗/poet.song.224000.json','["石梁平砥似，池水明鏡如。", "晚凉散步穩，凭欄此觀魚。"]'),
('1260bd84-8901-440a-a2e8-4759e6a68d76','感山十詠 華嚴堂','姚勉','宋','宋诗','song-poetry','','[]','寂寂華嚴堂，富貴佛境界。',24,'全唐诗/poet.song.224000.json','["寂寂華嚴堂，富貴佛境界。", "何須九九編，吾有艮一卦。"]'),
('cd61c9a7-4378-4028-851d-5471d0dd8ffe','感山十詠 旃檀林','姚勉','宋','宋诗','song-poetry','','[]','心清聞妙香，宴坐旃檀林。',24,'全唐诗/poet.song.224000.json','["心清聞妙香，宴坐旃檀林。", "坐香元不斷，莫作死灰心。"]'),
('611b4f57-69cf-4dd5-939c-2b89efceeab5','感山十詠 慈航','姚勉','宋','宋诗','song-poetry','','[]','佛手撐慈航，尚欲濟我人。',24,'全唐诗/poet.song.224000.json','["佛手撐慈航，尚欲濟我人。", "寄語作舟者，江濤渺無津。"]'),
('a8628f84-4ac3-47f9-bb05-2f4712efaf7c','感山十詠 甘露臺','姚勉','宋','宋诗','song-poetry','','[]','有唐太和年，宮中亦甘露。',24,'全唐诗/poet.song.224000.json','["有唐太和年，宮中亦甘露。", "曾不如此臺，空山自甘霪。"]'),
('089c6323-4e1a-4521-9715-5c3538dff9e4','感山十詠 雪窗','姚勉','宋','宋诗','song-poetry','','[]','地爐宿松火，紙帳橫梅枝。',24,'全唐诗/poet.song.224000.json','["地爐宿松火，紙帳橫梅枝。", "春蟲撲蔌蔌，惟有蒲團知。"]'),
('ef61665a-880e-4284-ac4a-b9011f80da81','感山十詠 雲卧菴','姚勉','宋','宋诗','song-poetry','','[]','動靜貴一如，妙處非塊坐。',24,'全唐诗/poet.song.224000.json','["動靜貴一如，妙處非塊坐。", "高人定不死，枕此白雲卧。"]'),
('7adf22b1-01a4-442d-ab6a-48c9b4b43f8e','先賢八詠 三閭紉蘭','姚勉','宋','宋诗','song-poetry','','[]','三閭紉佩秋，志在公子蘭。',24,'全唐诗/poet.song.224000.json','["三閭紉佩秋，志在公子蘭。", "荃不察予衷，江干淚潺湲。"]'),
('cd15cf21-7d40-462d-b07b-8f11c30c4cf4','先賢八詠 濂溪愛蓮','姚勉','宋','宋诗','song-poetry','','[]','斯蓮君子花，幾爲佛所汙。',24,'全唐诗/poet.song.224000.json','["斯蓮君子花，幾爲佛所汙。", "先生獨拈出，萬世知向慕。"]'),
('d1bca220-4fb5-4f03-b914-dfdc6d5b0c3e','先賢八詠 靖節採菊','姚勉','宋','宋诗','song-poetry','','[]','腰不爲米折，頭獨採菊低。',24,'全唐诗/poet.song.224000.json','["腰不爲米折，頭獨採菊低。", "晚節名元亮，思與隆中齊。"]'),
('d8bb2a26-db48-40ac-8ca3-219df7f8f502','先賢八詠 和靖探梅','姚勉','宋','宋诗','song-poetry','','[]','孤山養孤鶴，宜與梅爲隣。',24,'全唐诗/poet.song.224000.json','["孤山養孤鶴，宜與梅爲隣。", "處士若輕出，梅花應笑人。"]'),
('ea1087ea-58fd-490e-9e3e-0250fd96910a','先賢八詠 嵇康撫琴','姚勉','宋','宋诗','song-poetry','','[]','先生人中豪，志不肯司馬。',24,'全唐诗/poet.song.224000.json','["先生人中豪，志不肯司馬。", "一曲廣陵散，絕世不可寫。"]'),
('3877c726-69a5-4dc6-8096-7c08cac7be27','先賢八詠 謝安圍碁','姚勉','宋','宋诗','song-poetry','','[]','安石廊廟姿，豈不嫻將略。',24,'全唐诗/poet.song.224000.json','["安石廊廟姿，豈不嫻將略。", "氐奴驚偉人，良已先得著。"]'),
('84e5fc8d-a8fd-43af-9789-45d82e3bc370','先賢八詠 杜甫吟詩','姚勉','宋','宋诗','song-poetry','','[]','平生忠義心，一飯不少忘。',24,'全唐诗/poet.song.224000.json','["平生忠義心，一飯不少忘。", "臣甫寧餓死，願君堯舜唐。"]'),
('add779c9-7013-4949-977d-09698a4d132e','先賢八詠 李白醉酒','姚勉','宋','宋诗','song-poetry','','[]','殿前伸脚時，奴視高力士。',24,'全唐诗/poet.song.224000.json','["殿前伸脚時，奴視高力士。", "羣閹旁吐舌，翰林醒不醉。"]'),
('1e9fa143-3db8-4335-b9a6-ff49a0a16a59','雪景四畫 剡溪乘興','姚勉','宋','宋诗','song-poetry','','[]','山骨凍稜稜，溪色清練練。',48,'全唐诗/poet.song.224000.json','["山骨凍稜稜，溪色清練練。", "溪山中雪月，如對故人面。", "門扃隠廬深，舟捩征柁轉。", "勿云興已盡，不見方真見。"]'),
('e86f835b-c98d-4c18-9912-5bfa25f83b25','雪景四畫 寒江獨釣','姚勉','宋','宋诗','song-poetry','','[]','殘蘆颯欲乾，枯柳漸已集。',48,'全唐诗/poet.song.224000.json','["殘蘆颯欲乾，枯柳漸已集。", "彼舟者誰子，被此玉蓑笠。", "寒鱗正依藻，垂餌安可及。", "此興不在魚，携竿雪中立。"]'),
('f28286f5-1da4-4157-a073-07ebb94fcef1','雪景四畫 灞橋騎馿','姚勉','宋','宋诗','song-poetry','','[]','飄飄風中雪，瀝瀝橋下水。',48,'全唐诗/poet.song.224000.json','["飄飄風中雪，瀝瀝橋下水。", "雪寒換清骨，水淺潄塵耳。", "詩情散天壤，妙處乃在此。", "得句欲似誰，岸梅是知己。"]'),
('adc47848-78eb-4a7e-93f8-ab0172838ba0','雪景四畫 藍關擁馬','姚勉','宋','宋诗','song-poetry','','[]','雪擁尚秦嶺，天盡爲潮陽。',48,'全唐诗/poet.song.224000.json','["雪擁尚秦嶺，天盡爲潮陽。", "吾馬不能前，吾骨凍不殭。", "崒屼雪中峰，萬仞摩蒼蒼。", "非馬度藍關，騎龍白雲鄉。"]'),
('3de6ada6-af69-4532-97c5-5b84112c1c3c','謝久軒蔡先生惠墨九首  其一','姚勉','宋','宋诗','song-poetry','','[]','孔鐸經百年，誣世有楊墨。',48,'全唐诗/poet.song.224000.json','["孔鐸經百年，誣世有楊墨。", "天生子輿氏，邪說一以息。", "紫陽曾未遠，人復詆無極。", "先生嚴衛道，功比異端闢。"]'),
('4cc21f0d-a1d5-47ea-ab5f-fd5cc5b7a9b2','謝久軒蔡先生惠墨九首  其二','姚勉','宋','宋诗','song-poetry','','[]','使從武夷來，惠我墨長咫。',48,'全唐诗/poet.song.224000.json','["使從武夷來，惠我墨長咫。", "黝然禹玄圭，上有久軒字。", "他珍不余畀，遺此良有以。", "天未喪斯文，誓將立人紀。"]'),
('a4ca0a5f-1884-4b6e-aa92-1736075ebb4a','謝久軒蔡先生惠墨九首  其三','姚勉','宋','宋诗','song-poetry','','[]','孔學授顔曾，有孫復能傳。',48,'全唐诗/poet.song.224000.json','["孔學授顔曾，有孫復能傳。", "道脈萃一家，壽此嘻其天。", "西山宗紫陽，妙會衆理全。", "先生嗣派嫡，再演中庸篇。"]'),
('c18df9cb-aef0-4d29-a926-e324df8dfddc','謝久軒蔡先生惠墨九首  其四','姚勉','宋','宋诗','song-poetry','','[]','軒冕儻來物，豈足羈聖賢。',48,'全唐诗/poet.song.224000.json','["軒冕儻來物，豈足羈聖賢。", "素王萬世功，杏壇誨三千。", "平世膺戎狄，事功止當年。", "六經發蒙蔀，今古日在天。"]'),
('68a8de98-7d90-49f4-858f-6de8b365d28d','謝久軒蔡先生惠墨九首  其五','姚勉','宋','宋诗','song-poetry','','[]','巍巍無極翁，昌代正學祖。',48,'全唐诗/poet.song.224000.json','["巍巍無極翁，昌代正學祖。", "生從道州地，如孔出姬魯。", "西山道州派，上接濂溪武。", "天意豈偶然，真傳紹先古。"]'),
('9f2646ef-0b19-4926-9e6f-67e1378f36c2','謝久軒蔡先生惠墨九首  其六','姚勉','宋','宋诗','song-poetry','','[]','科目動榮想，葩華競浮文。',48,'全唐诗/poet.song.224000.json','["科目動榮想，葩華競浮文。", "既獲釣名位，鄙夫豈知君。", "愚生不此志，願策克復勳。", "蕞軀夕可死，但欲朝有聞。"]'),
('b3badcf8-2454-45a6-820b-0402afeb6352','謝久軒蔡先生惠墨九首  其七','姚勉','宋','宋诗','song-poetry','','[]','寥寥六經餘，天下無文章。',48,'全唐诗/poet.song.224000.json','["寥寥六經餘，天下無文章。", "揚韓特近似，班馬熏何香。", "道至文亦精，萬世朱紫陽。", "願言楫洋海，安敢航絕潢。"]'),
('6bf34e3d-2998-4df3-b6e3-f66c56f5d042','謝久軒蔡先生惠墨九首  其八','姚勉','宋','宋诗','song-poetry','','[]','世路既如此，皇皇欲何之。',48,'全唐诗/poet.song.224000.json','["世路既如此，皇皇欲何之。", "閉門事古學，妙處倘可窺。", "欣然或會心，俯仰得自怡。", "先生惠終教，勿作門牆麾。"]'),
('ddb68974-dd8d-43d2-898d-259323e6f6ce','謝久軒蔡先生惠墨九首  其九','姚勉','宋','宋诗','song-poetry','','[]','摳衣憶初時，謹獨拜明訓。',48,'全唐诗/poet.song.224000.json','["摳衣憶初時，謹獨拜明訓。", "冥途方擿埴，夷軌忽發軔。", "始知顔四勿，於此道有進。", "敢云聖賢遠，二字古心印。"]'),
('90dc23f8-13e8-44db-8411-0697ca72a516','和楊鐵菴送子監鎮之任韻五首  其一','姚勉','宋','宋诗','song-poetry','','[]','關西夫子家，清白乃世傳。',48,'全唐诗/poet.song.224000.json','["關西夫子家，清白乃世傳。", "傳授已到君，此脈要渾全。", "青雲開亨衢，况及此妙年。", "願言植名節，照映東西川。"]'),
('cb2dfb58-a071-42bc-99a2-a943b01bf7ef','和楊鐵菴送子監鎮之任韻五首  其二','姚勉','宋','宋诗','song-poetry','','[]','君家遺子籯，只在一卷書。',48,'全唐诗/poet.song.224000.json','["君家遺子籯，只在一卷書。", "四世續科第，積善慶有餘。", "乃翁一片心，秋月行太虛。", "宜哉有是子，大似回不愚。"]'),
('6a4564a6-3e2e-4858-a6ec-de4a25dddf23','和楊鐵菴送子監鎮之任韻五首  其三','姚勉','宋','宋诗','song-poetry','','[]','去年唱第時，文陣見整齊。',48,'全唐诗/poet.song.224000.json','["去年唱第時，文陣見整齊。", "萬花迎歸來，白馬黄金羈。", "及今催戍瓜，步武青雲低。", "風埃溘上征，飄飄乘白鷖。"]'),
('3a8ae9f7-cffc-4a43-a2c3-dfbdef1a8175','和楊鐵菴送子監鎮之任韻五首  其四','姚勉','宋','宋诗','song-poetry','','[]','初仕謂之筮，已是行道時。',48,'全唐诗/poet.song.224000.json','["初仕謂之筮，已是行道時。", "爲官要自强，謹勿事詭隨。", "一命可及民，官正不論卑。", "當今淮堧清，犬眠足生氂。"]'),
('ab2615ec-3d12-45a5-90b5-42ab3b397fb8','和楊鐵菴送子監鎮之任韻五首  其五','姚勉','宋','宋诗','song-poetry','','[]','文章世家難，有子夫何憂。',48,'全唐诗/poet.song.224000.json','["文章世家難，有子夫何憂。", "吾亦有青氈，未作菟裘謀。", "駑鞭不及驥，汗喘徒呀齁。", "願隨君後塵，擊楫江中流。"]'),
('48f6a795-9bf6-490c-891b-85c3e9a5c2e9','番陽張君叔振觀予以其家雙瑞圖俾詩之叔振大參忠定公諸孫也惟忠定公政和八年魁天下某先世實隸其榜今某於叔振令子若鳳爲同年生世科之契也又何辭雖不能詩謹課二首  其一','姚勉','宋','宋诗','song-poetry','','[]','望月犀角明，涵星蚌胎聚。',48,'全唐诗/poet.song.224000.json','["望月犀角明，涵星蚌胎聚。", "斯石卧龍枕，宜有蜿蜒具。", "龍頭君家舊，有子踵高步。", "層雲觸石出，四海望甘霔。"]'),
('e3f00ad4-0c57-41dc-ab89-bf382c4f78a0','番陽張君叔振觀予以其家雙瑞圖俾詩之叔振大參忠定公諸孫也惟忠定公政和八年魁天下某先世實隸其榜今某於叔振令子若鳳爲同年生世科之契也又何辭雖不能詩謹課二首  其二','姚勉','宋','宋诗','song-poetry','','[]','堂堂忠定家，三世蘭爲祥。',48,'全唐诗/poet.song.224000.json','["堂堂忠定家，三世蘭爲祥。", "父子繼科第，菲菲姓名香。", "雙英今復然，階庭煜生光。", "願言紉佩之，百世當流芳。"]'),
('81493272-2920-4577-9f1a-156195a6f551','贈星學彭砥齋','姚勉','宋','宋诗','song-poetry','','[]','彭君妙星數，爲人說窮通。',48,'全唐诗/poet.song.224000.json','["彭君妙星數，爲人說窮通。", "爵祿特磨鈍，是名砥齋翁。", "我鈍不可磨，礲礪煩良工。", "寸鐵足刳蟇，遥遥廣寒宮。"]'),
('3f6cbe43-8b11-4b68-8c73-9040970ed170','贈月堂徐相士','姚勉','宋','宋诗','song-poetry','','[]','衡門選龍首，摸索未容易。',48,'全唐诗/poet.song.224000.json','["衡門選龍首，摸索未容易。", "龍首許黄扉，却亦非難事。", "濟物乃素心，好爵豈予志。", "時來亦不辭，焉用早諛媚。"]'),
('8374c135-5039-43f8-bfcc-194939b165bb','人皆以貧憂','姚勉','宋','宋诗','song-poetry','','[]','人皆以貧憂，君子獨能樂。',48,'全唐诗/poet.song.224000.json','["人皆以貧憂，君子獨能樂。", "中心賤榮利，外物甘寂寞。", "富貴如春花，時去易凋落。", "不如一簞瓢，可以長處約。"]'),
('06d7878f-9d0b-4f2a-a78b-e5b67ca415f0','送廬陵郭僉判致仕歸','姚勉','宋','宋诗','song-poetry','','[]','世俗風波甚，誰能退急流。',288,'全唐诗/poet.song.224000.json','["世俗風波甚，誰能退急流。", "淵明存菊日，張翰憶鱸秋。", "高躅今云遠，清風孰與侔。", "明公回末習，逸韻踵前修。", "元振才高古，林宗學鮮儔。", "未爲川上楫，姑運幄中籌。", "太守先公孝，同僚上伯遊。", "德偕才並茂，文與政俱優。", "士有春風慕，民無北雪愁。", "寬平人自服，欺紿吏應羞。", "逸足方當展，閒身欲早抽。", "聲名從日起，富貴等雲浮。", "帝許掛冠請，人多卧轍留。", "山中無怨鶴，海上有盟鷗。", "西澗先生渙，平園老叟周。", "高風追故國，雅節映吾州。", "巧祿慚奔競，懷安鄙懦偷。", "號應重拜散，亭欲遂名休。", "親戚娛清話，溪山豁遠眸。", "詩情入囊錦，世事付紋楸。", "陸子新茶具，嚴灘舊釣裘。", "問松猶在逕，種秫喜盈疇。", "眼覺功名夢，心輕利祿漚。", "竇山森桂茂，謝砌長蘭幽。"]'),
('9d99d6a9-b114-45ca-83e3-55779e33b2f2','送鄧若思赴南劍鄉舉','姚勉','宋','宋诗','song-poetry','','[]','龍泉與太阿，紫氣牛斗衝。',96,'全唐诗/poet.song.224000.json','["龍泉與太阿，紫氣牛斗衝。", "神物離必合，龍津復相從。", "悠悠千餘年，神秀人物鍾。", "高密雲礽孫，星宿羅心胸。", "居常佩此劍，溝瀆難鯨容。", "朅來磨劍池，清水爲淬鋒。", "秋風催斫桂，迥脫塵泥蹤。", "勉哉各努力，更作延平龍。"]'),
('da2004ec-b1ed-47b7-8f09-00617b9ba082','次友人王半山韻','姚勉','宋','宋诗','song-poetry','','[]','詩家王半山，妙語占清絕。',120,'全唐诗/poet.song.224000.json','["詩家王半山，妙語占清絕。", "曲高和斯寡，郢曲愧春雪。", "句中寓深意，端爲我輩設。", "以規不以頌，如玉得磋切。", "予生戰場屋，一勝久未决。", "勇餘尚欲賈，磨硯欲穿鐵。", "第慚不善斲，顔汗指亦血。", "乞靈濟楚師，此敵儻可滅。", "如君洗塵累，盆盎易甄別。", "鷹揚會有日，奮翅脫籠紲。"]'),
('8f0fe5f5-3888-4900-afa2-5b1e1887438d','贈霆伯姪','姚勉','宋','宋诗','song-poetry','','[]','靈源聚英氣，融作雲霞精。',288,'全唐诗/poet.song.224000.json','["靈源聚英氣，融作雲霞精。", "霆伯挹其秀，胸府懷光晶。", "誦書過萬卷，落筆超羣英。", "文章有餘力，賦詩吟性情。", "短章或大篇，點翰長風生。", "或吐健麗句，氣象高崢嶸。", "雲濤洶萬里，出沒蛟龍驚。", "或寫閒逸句，句法如天成。", "微泉溜石壁，清吹調松聲。", "或句和且婉，純如奏英莖。", "晴風舞雪絮，曉日歌春鶑。", "或句端且嚴，凜凜不可輕。", "星辰列雲漢，營壘森甲兵。", "變化千萬狀，發越無定名。", "清標鎮浮態，沈謝隳文成。", "勁氣擬古作，甫白焚詩泓。", "不負飄逸姿，孰爭前輩衡。", "學海不汗漫，安見酌復盈。", "文章用無盡，蓋以天才宏。", "宏才戲翰墨，筆勢宜如傾。", "譬之一輪月，皎皎當天明。", "晴輝照春夜，花柳皆敷榮。", "高秋爽氣盛，桂影翻凄清。", "又如百川水，滔滔地中行。"]'),
('108ecd29-4aae-4260-a90e-94ba05501a7e','訪郭德甫','姚勉','宋','宋诗','song-poetry','','[]','美人在駒谷，久別良懷哉。',180,'全唐诗/poet.song.224000.json','["美人在駒谷，久別良懷哉。", "秋風天氣清，特爲斯人來。", "踏月訪清夜，巖扉肯予開。", "弟兄儼相對，松竹間古梅。", "子姪環侍側，蘭植依瓊瑰。", "青燈照圖史，新酒羅瓶罍。", "一家三代風，和氣熙春臺。", "富學飽停蓄，厚德深栽培。", "情周思孔子，志伊學顔回。", "皇路方嶮巇，天馬須龍媒。", "旱歲渴霖雨，神鱗起淵雷。", "君家多生賢，吾國正選才。", "詔書明年近，競踏黄花槐。", "造榜正此天，桂籍浮香催。", "鵰鶚相聯飛，燕雀更願陪。"]'),
('14062b1b-f9dd-4f94-ab4f-38d529716ddc','訪胡景顔','姚勉','宋','宋诗','song-poetry','','[]','適齋詩僊人，吟境天寬廣。',132,'全唐诗/poet.song.224000.json','["適齋詩僊人，吟境天寬廣。", "聞詩未識面，魚鴈空來往。", "道周歘相遇，慰此積歲仰。", "煙林指深處，邀我稅塵鞅。", "入門境自勝，萬竹颯蕭爽。", "燈前酌夜雨，談笑劇拊掌。", "錦囊出新什，句字兩俱響。", "明當早脂車，未別先惆悵。", "嗟予走紅塵，方此墮世網。", "羨君飽林壑，四序足幽賞。", "努力喜自珍，清名照天壤。"]'),
('de18c85c-3cc3-41ff-ae86-6afde1b9c29f','贈宗人簡齋','姚勉','宋','宋诗','song-poetry','','[]','博文約以禮，夫子誨子淵。',180,'全唐诗/poet.song.224000.json','["博文約以禮，夫子誨子淵。", "詳說將反約，斯語在七篇。", "由繁乃入簡，此學本聖賢。", "卓哉紫陽公，道統得正傳。", "剖析到精微，而後會大全。", "譏以爲支離，此說恐未然。", "閑邪至敬義，簡易斯坤乾。", "後學懶用功，疎略取自便。", "藉口鵝湖詩，一蹴登青天。", "浪云即心是，所學竟類禪。", "不知格物學，蓋在誠意先。", "如斯謂之簡，毋乃墮一偏。", "此風近頗張，門戶欲自專。", "君既學雙峰，趨向尚慎旃。", "路頭且要正，莫踏船兩舷。"]'),
('17896f87-8113-4dfc-9ef9-0f65927a5c42','題陳致中環溪','姚勉','宋','宋诗','song-poetry','','[]','出門何所有，四面圍青山。',84,'全唐诗/poet.song.224000.json','["出門何所有，四面圍青山。", "是溪從山來，亦復茲回環。", "高人潁川君，結茅此中間。", "溪光挹瀲灧，溪響聽潺湲。", "四面勿著橋，往來聽渠艱。", "是名僊凡界，亦曰清濁關。", "可人送過溪，否則溪上還。"]'),
('dbcafe78-42ce-4d8d-b9e1-700dd798f387','同張公望湖上避暑到四聖觀招柏堂月潭二道士出飲','姚勉','宋','宋诗','song-poetry','','[]','清晨有客來，畏暑思避地。',168,'全唐诗/poet.song.224000.json','["清晨有客來，畏暑思避地。", "凉多獨湖上，一棹拍空翠。", "長堤舞楊柳，餘雨在荷芰。", "炎蒸俱已失，滿抱足清意。", "頗思孤山頂，有客具高致。", "扣門聞琴聲，便覺洗塵累。", "湖邊出問酒，飲興隨所至。", "池鮮煮珍甘，水果剝香脆。", "好風林外來，吹面凉不醉。", "清談詣物表，絕不挂世事。", "畫舫何人斯，簫鼓正喧沸。", "清遊彼應笑，世味吾不嗜。", "尚思携枕簟，同叩竹間寺。", "從今日日來，莫厭驚晝睡。"]'),
('58dfa9f3-8929-4228-86b5-e380b00455ed','題章秀才畫山水魚龍','姚勉','宋','宋诗','song-poetry','','[]','章生畫中師，神秀蟠心胸。',240,'全唐诗/poet.song.224000.json','["章生畫中師，神秀蟠心胸。", "兒時學山水，近復能魚龍。", "拂素欲畫時，默吮南山松。", "斯須景與物，以次生筆鋒。", "畫出巧安排，咫尺千萬重。", "陰晴弄明晦，近遠分淡濃。", "雪月清瘦嶼，煙雨朦朧峰。", "有時作江湖，萬派俱朝宗。", "雲濤洶澎湃，雪屋驚奔衝。", "風平坦如掌，皺縠浮溶溶。", "因水魚更巧，回翻態從容。", "翻荷猛跳珠，聚藻相噞喁。", "中有化龍鯉，靜伺機便逢。", "天門露頭角，滃滃祥雲從。", "看君此四畫，衆史特奴傭。", "當知各有意，不特誇纖穠。", "丈夫抱膝時，清樂山水供。", "觀魚或濠上，笑倚臨流筇。", "一朝蛻鱗鬣，屣脫塵泥蹤。", "甘霖澤四海，霓望慰九農。"]'),
('80d6e3d3-64f8-442f-aa1e-4f780bc288dd','日食罪言','姚勉','宋','宋诗','song-poetry','','[]','皇帝十四載，新元紀嘉熙。',288,'全唐诗/poet.song.224000.json','["皇帝十四載，新元紀嘉熙。", "仲冬戊寅朔，午漏方中時。", "朔風震丘壑，猛籟號枯枝。", "黯如商雪天，四野昏垂垂。", "晝炊煙始息，暝色來庭帷。", "雞登杙榤立，鳥急林梢棲。", "頗訝南至後，晷度宜舒遲。", "胡爲景尚促，疾甚駒隙馳。", "兒童忽走報，日壁無全規。", "倉忙出仰視，如月初蛾眉。", "金烏失焰彩，玉象潜光輝。", "蒼天玳瑁色，列宿爭依稀。", "老稚相喧呼，伐社沸鼓鼙。", "不知何物怪，掩此清陽暉。", "吾聞陰陽家，日月以曆推。", "日遲月行速，贏縮數不齊。", "遇朔必會合，差忒無毫釐。", "氣盛或相掩，二曜斯一虧。", "望日日掩月，陽感陰故衰。", "朔日月掩日，陰盛陽乃微。", "又聞玉川子，月蝕曾有詩。", "謂此日月者，天眼生東西。", "兩眼不相攻，相食其說非。", "食月乃蟆精，伊慼蓋自貽。"]'),
('c31a2e65-4081-4054-aada-1d9b5bd2da81','遊靈源天境遇雨各奔歸晚坐以不是溪居者那知風雨來分韻得那字奉呈一笑','姚勉','宋','宋诗','song-poetry','','[]','靈源水有天，日涉勝趣多。',252,'全唐诗/poet.song.224000.json','["靈源水有天，日涉勝趣多。", "同行十數子，散策經山坡。", "溪行小盤礴，石坐閒摩挲。", "野菊留餘花，新梅看微柯。", "寒鴉落平田，暖鯉跳枯荷。", "是日冬曦溫，景象如春和。", "笑談不知歸，亦有載酒過。", "忽瞻彼北山，黑雲生嵯峨。", "陰晴反覆手，天測不可俄。", "長風舞紅葉，急雨翻銀河。", "儒冠各欹墊，僮屨皆奔波。", "路滑爭牛羊，泥濺亂鴨鵝。", "席地聽沾濕，樽沙委駢羅。", "五十笑百步，曳杖如橫戈。", "林間偶自芘，棄甲我則那。", "留戀歸不早，顛沛逢滂沱。", "出遊不知時，廢此嘯且歌。", "綢繆無遠慮，其如近憂何。", "茲遊已狼籍，後計毋蹉跎。", "歸歟亟誅茅，結亭依巖阿。", "震陵有帡幪，樂哉澗槃薖。"]'),
('254629ad-b67b-441b-951a-ee7040f539c7','麻子湖遇逆風','姚勉','宋','宋诗','song-poetry','','[]','嘉平既望餘，玉冰發歸槳。',288,'全唐诗/poet.song.224000.json','["嘉平既望餘，玉冰發歸槳。", "舟行苦灘澀，三日葛陂上。", "天寒歲云晏，道遠空悵惘。", "行行且旬日，僅此舟泱漭。", "順流風忽逆，進尺退或丈。", "魚黿反出沒，濤浪相潏蕩。", "茫茫水接天，四望極空敞。", "雖令歸思滯，亦覺胸次廣。", "是時羣魚集，軋軋亂輕榜。", "紛來以千百，並進或三兩。", "懸金上絲綸，跳玉中層網。", "中間數十輩，蓑笠牽畫舫。", "沿流勤按視，似是此湖長。", "彼行良甚捷，此進不可强。", "倘無觀魚樂，孰慰岑寂想。", "篙師不告瘁，奇觀亦可賞。", "黄昏成野泊，風雨助悽愴。", "勢如潮汐來，怒若鼙鼓響。", "吾獨安所適，幸不愧俯仰。", "緬懷金蘭友，氣義特慨慷。", "念我歸苦遲，舍我願先往。", "亟趨南浦城，擇館待稅鞅。", "今宵此風雨，露宿必草莽。", "繼茲更三日，會面一拊掌。"]'),
('81ebb522-aa08-417f-a85a-44669fabe6c8','白鶴','姚勉','宋','宋诗','song-poetry','','[]','白鶴有奇質，從古巢神僊。',96,'全唐诗/poet.song.224000.json','["白鶴有奇質，從古巢神僊。", "饑餐必瑶草，渴飲惟瓊泉。", "朝飛閬苑霞，莫宿炎洲煙。", "一從落塵埃，六翮翦不全。", "身居樊籠中，心往雲霄邊。", "長鳴欲誰訴，顧影私自憐。", "清都夢如昨，欲去曾無緣。", "安得支道林，使之遂飄然。"]'),
('9492eafd-a1c2-4fb6-99cb-f80f29e4de1b','蓮竹鶴','姚勉','宋','宋诗','song-poetry','','[]','蓮爲君子花，竹有君子操。',132,'全唐诗/poet.song.224000.json','["蓮爲君子花，竹有君子操。", "深衣古君子，清以仙自號。", "徘徊蓮竹間，似覺皆所好。", "水邊立良久，林外復高蹈。", "翩然側翅舞，意喜佳客到。", "客家江南村，幽處著吟帽。", "有蓮環釣石，有竹近茶竈。", "胎仙夜生子，併入平安報。", "朅來踏京塵，久矣不聞耗。", "今晨三君子，一見慰懷抱。", "主人勿却客，借此日笑傲。"]'),
('c55b561e-bf93-4271-8dcd-a0447c77f90c','醉芙蓉','姚勉','宋','宋诗','song-poetry','','[]','庭前木芙蓉，姿色夐殊異。',108,'全唐诗/poet.song.224000.json','["庭前木芙蓉，姿色夐殊異。", "初開花微碧，僊子淡雲袂。", "逡巡改瑩白，玉骨浄無滓。", "爛漫欲謝時，潮臉暈紅媚。", "詩人第花品，獨號此爲醉。", "花雖無情物，司者定有意。", "晨醒粲初發，晚醉颯欲墜。", "乃知沉湎者，顛沛在造次。", "可以爲酒箴，看花當欹器。"]'),
('22f282c6-0cd2-41e3-af29-36f66c32185d','贈相道士梁彌仙','姚勉','宋','宋诗','song-poetry','','[]','羅浮古洞天，花木麗春曉。',96,'全唐诗/poet.song.224000.json','["羅浮古洞天，花木麗春曉。", "仙人住其間，鸞鵠飛矯矯。", "尚有蒼生心，一念百憂繞。", "日與諸賢遊，仙人如此少。", "徐潘不可作，空有贈子詩。", "一蔡二李存，請子善視之。", "願言福壽兼，長在白玉墀。", "壽域躋吾民，安用神仙爲。"]'),
('d2f635d2-12dc-4bec-b422-f5a9621e730c','題廉泉','姚勉','宋','宋诗','song-poetry','','[]','凜凜清獻公，盛德世所儀。',60,'全唐诗/poet.song.224000.json','["凜凜清獻公，盛德世所儀。", "當年章貢治，去止琴鶴隨。", "於水取廉泉，於人識濂溪。", "廉泉水之清，濂溪道之師。", "斯濂願力學，彼廉猶可爲。"]'),
('eaafe3d8-5b85-4def-a95d-6a65e17d2a12','題騰芳書院','姚勉','宋','宋诗','song-poetry','','[]','若稽隆古時，教者家有塾。',288,'全唐诗/poet.song.224000.json','["若稽隆古時，教者家有塾。", "英材歸樂得，粹學就私淑。", "淳風日云遠，美意久不續。", "朱君魁傑士，卓見拔流俗。", "燕山靄椿桂，謝砌峙蘭玉。", "所居必精舍，高繼紫陽躅。", "朅來十畝地，建此一書屋。", "前山畫屏列，暖翠潑晴麓。", "騰芳揭佳扁，意匠雅營築。", "依牆御史柏，繞舍君子竹。", "雪香冠春葩，月馥播秋肅。", "回廊啟齋扉，雲蔭納喬木。", "亭橋跨天沼，檻影浸寒綠。", "中堂富圖史，縹帙照籤軸。", "仰瞻聖賢像，冠履森在目。", "虛櫺設棐几，日靜嘗好讀。", "南窗最明快，天籟響琴筑。", "延師啟堂壇，規矩倣白鹿。", "義方已家庭，仁意更閭族。", "朋來秀子弟，戶屨輻輳轂。", "擊撞金石樂，真趣寄沂浴。", "似聞入腴壤，將使任教育。", "如斯邁種德，豐報在名祿。", "願言衆龍駒，相與策驥服。"]'),
('2457403f-d3a8-4c0c-99ab-fa8a3b2b9105','題雪巖胡則潛詩卷首','姚勉','宋','宋诗','song-poetry','','[]','君有雪巖余雪坡，坡中雪少巖雪多。',256,'全唐诗/poet.song.224000.json','["君有雪巖余雪坡，坡中雪少巖雪多。", "試將二雪平章看，坡中雪比巖如何。", "有人問我坡間雪，一色平鋪寒玉潔。", "夜深明月可中庭，化作冰壺底俱徹。", "不如君巖雪更奇，怪松夭矯銀龍垂。", "倚巖一嘯望清曉，千崖萬壑俱瑶池。", "莫將多少分優劣，只喜坡間同此雪。", "蘆花月色一樣看，吾雪本來無欠缺。", "羣芳禿盡梅始花，同雲羃羃天之涯。", "蒲團竹屋坐聽雪，春蟲撲窗蟹行沙。", "書來題作雪家契，最愛君書此三字。", "世人愛熱冷即嫌，我獨與君同此嗜。", "雪無彼此只一家，玉堂茅舍何等差。", "紅壚一片會真趣，藩籬剖破非封蝸。", "雪堂僊伯騎鯨去，天台雪巢復何處。", "與君分釣雪江寒，同唱孤舟蓑笠句。"]'),
('63946301-46a4-4370-a97d-6df8949a21ce','題李銳父所藏陳所翁龍軸','姚勉','宋','宋诗','song-poetry','','[]','所翁先生人中龍，豪氣下吞江海空。',96,'全唐诗/poet.song.224000.json','["所翁先生人中龍，豪氣下吞江海空。", "當其得意作龍首，老手直與神天通。", "雄辭妙語層層出，醉中千幅筆一息。", "不遇先生大醉時，人間安肯留真蹟。", "先生往往自寫真，非龍之龍蓋其人。", "請君什襲寶此墨，此翁此墨不易得。"]'),
('e37701c0-bbdd-4e1f-b155-31cea1f3e352','題墨梅風煙雪月水石蘭竹八軸','姚勉','宋','宋诗','song-poetry','','[]','清晨有客南昌來，袖出數幅春風梅。',356,'全唐诗/poet.song.224000.json','["清晨有客南昌來，袖出數幅春風梅。", "芳根不種生綃上，安得的皪霜葩開。", "霜葩能開不能謝，始信筆端生造化。", "細看入趣直欲攀，亦復不知梢是畫。", "迎風冷笑斜窺簷，披煙淡竚拖輕縑。", "豐腴略带清曉雪，疎瘦半橫初夜蟾。", "根栖怪石增奇絕，倒影寒溪照清潔。", "斜枝蘭外侶幽姿，冷蕊竹間標勁節。", "超然筆法無糝塵，正欹仰俯態逼真。", "幾回卷軸却復展，生意不窮看轉新。", "只看幽韻自堪玩，莫道無香真可嘆。", "清香已在杳默中，暗起芬芳浮鼻觀。", "平生愛梅如愛賢，恨無好句模幽妍。", "看君此畫得天趣，妙寫無聲詩八篇。", "吾聞古來能畫者，畫馬胸中有全馬。", "君應滿腹皆梅花，不爾安能筆瀟灑。", "想君家住西山邊，萬梅谷中廬數椽。", "月宵携筇雪著屐，坐石瞰水窺風煙。", "紉蘭傲竹今幾年，餐香換骨身可僊。", "凝神吮墨淡一掃，不覺筆下花真傳。", "嘆予自愛冰玉幹，久藏一幅鵝溪絹。", "請君爲作雪中百花頭上開，掛我壁間供客看。"]'),
('58ee90b2-14ee-49bd-9f54-ff1e1dddd7ef','送友人陳上舍兄弟試太學','姚勉','宋','宋诗','song-poetry','','[]','東風颯颯吹行李，榮送雙龍璧池水。',128,'全唐诗/poet.song.224000.json','["東風颯颯吹行李，榮送雙龍璧池水。", "璧池浪闊高化龍，直透銀河三萬里。", "君家兄弟真鴈行，季方學行如元方。", "中眉不是弓刀軟，個般人物宜膠庠。", "只今膠庠多俊傑，正是功名到時節。", "陳家原有兩狀元，釋褐傳臚未應別。", "顧余亦問京華春，蒼蠅願附驥尾塵。", "干將先去抉雲雨，太阿行亦龍延平。"]'),
('413fd164-066c-4ff1-a66c-43ab8c702ac3','送松麓李應龍彝甫携阿穎鵬升參學','姚勉','宋','宋诗','song-poetry','','[]','老龍本自天門出，躍入璧池聊換骨。',96,'全唐诗/poet.song.224000.json','["老龍本自天門出，躍入璧池聊換骨。", "鵬雛夭矯更不凡，平視南溟渺東渤。", "玉京道上五年前，曾見鱗翮雙飛天。", "祇今江國梅花路，又送鵬雛逐龍去。", "明年秋風層雲飛，後年春浪桃花肥。", "摶鵬高鶱龍速化，倘許共勒青冥鞿。"]'),
('0a73acb1-d8e1-483b-9120-8d0a666fac65','送胡從甫劉仲山入京','姚勉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅花先臘開香雪，魁信已隨春漏泄。',183,'全唐诗/poet.song.224000.json','["梅花先臘開香雪，魁信已隨春漏泄。", "送君聯騎入天京，不作人間兒女別。", "錦江俊秀皆朋儔，其間偏善胡與劉。", "胸襟巧蟠錦繡段，文采互照珊瑚鈎。", "采芹宮裏群遊戲，文字頡頏春燕翅。", "西湖萬柳嬌春風，相期同緩看花轡。", "棘闈風動桂香秋，一駑那輸雙驊騮。", "我悲日色謾迷眼，君喜朱衣皆點頭。", "青天一界蟾宮路，只要朋儕先著步。", "祝君猛去化爲龍，行繼延平躍雲霧。", "君不見蘇易簡，不事探花與榜眼，明番狀元未爲晚。"]'),
('0900c4de-098a-4b4d-bb71-cf72508e2d89','龍道者生日就狀元局中置酒寄以詩','姚勉','宋','宋诗','song-poetry','','[]','去年六月初九日，天地光明一佛出。',128,'全唐诗/poet.song.224000.json','["去年六月初九日，天地光明一佛出。", "今年六月初九日，慈恩名標千佛一。", "吾家德本深栽培，庭階煜煜芝蘭開。", "自從有子即擢第，阿兒生時都带來。", "今朝宴客龍頭局，遥想吾翁抱孫浴。", "手携俎豆與干戈，更提一筆蒼生福。", "願兒長成勤讀書，忠孝一脈天相扶。", "張家師德梁家固，重入衣冠盛事圖。"]'),
('c4d2efd4-491b-4248-a47c-280f0e9a6cb0','姪阿鍾覓字與詩','姚勉','宋','宋诗','song-poetry','','[]','阿鍾五歲已大奇，從我覓字與覓詩。',296,'全唐诗/poet.song.224000.json','["阿鍾五歲已大奇，從我覓字與覓詩。", "栗梨不愛愛紙筆，此意豈是尋常兒。", "吟詩寫字非難事，字畫是心詩是志。", "器量充周志氣宏，勁筆雄辭皆極致。", "吾家鼻祖豐城公，庭叱百萬無虓雄。", "子孫世襲節義風，流傳直至江西翁。", "江西夫子今希有，四經七舉爲龍首。", "不作孫弘曲學儒，文章只是宗元祐。", "祖宗積善源深長，爭奇競秀生諸郎。", "諸郎更有如鍾者，引領丹山羣鳳凰。", "曉窗讀書肯至午，夜燈琅琅明月廡。", "只今小年已勤苦，從此讀書到十五。", "貫經穿史包今古，雪坡癡叔未足多。", "十駑驥子一躍過，河南晁氏曾有樣。", "二十子弟俱高科，汝今羣從多兄弟。", "勳業相期各如意，家塾相師學聖賢。", "廟堂再拜傳忠義，羲獻帖，李杜詩，遺蹤雖在不必追。", "請賡慶曆徂徠頌，更立中興浯水碑。"]'),
('60bbd0b9-692a-44ed-8035-5778b3765ab6','賀族兄寵妾生子','姚勉','宋','宋诗','song-poetry','','[]','艷紅香紫春正中，扶輿磅礴清氣融。',96,'全唐诗/poet.song.224000.json','["艷紅香紫春正中，扶輿磅礴清氣融。", "玉麟夜掣香案鎖，五雲裹送光玲瓏。", "吾家自是詩書裔，秀傑相承擢丹桂。", "太丘合有二方兒，省華須著三堯繼。", "近聞絡秀生伯仁，喜君掌上明珠新。", "願言種德相扶植，此子定是高車人。"]'),
('faa3cf0d-3fa7-4584-9cca-f8a585d7e00d','賀趙宰夫美任生子','姚勉','宋','宋诗','song-poetry','','[]','趙侯德與甘棠種，製邑三年民善頌。',192,'全唐诗/poet.song.224000.json','["趙侯德與甘棠種，製邑三年民善頌。", "玉皇有詔趣歸班，一夜長庚來入夢。", "豐江羅峰神秀奪，龍泉太阿光芒動。", "玉女擎香龍吐水，慈雲親抱麒麟送。", "懷玉僊人秀眉目，披羽笑出蓬萊洞。", "奇骨崢嶸千里駿，異采繽紛九苞鳳。", "人生有子萬事足，又值朝天欲飛鞚。", "驪珠在掌鳬在舄，慶事方新殊渥重。", "周公爲父伯禽子，清廟明堂要梁棟。", "長成傳取魁衣鉢，天生奇材須大用。", "此兒見說骨已異，壯氣衝天摇螮蝀。", "我識英物試使啼，他日定當磐石宋。"]'),
('344fc959-ac95-43ca-8edf-698bee162d2e','賀孫舜皋子周歲','姚勉','宋','宋诗','song-poetry','','[]','卯君元是月中兔，藥擣長生壽根固。',64,'全唐诗/poet.song.224000.json','["卯君元是月中兔，藥擣長生壽根固。", "去年此際挹秋清，飛駕冰輪碾風露。", "來爲龍谷曾孫兒，生來一歲骨骼奇。", "廣寒宮殿出身處，僊桂須還第一枝。"]'),
('99b7e3bc-1a9d-4c9c-8ce2-ffb1a4317d31','贈新昌王藍田三子','姚勉','宋','宋诗','song-poetry','','[]','太原曾有三珠樹，花萼一團光彩聚。',98,'全唐诗/poet.song.224000.json','["太原曾有三珠樹，花萼一團光彩聚。", "清晨肯挾三鳳來，真是王家兒可譽。", "乃翁哦詩松竹陰，三兒吾伊玉應金。", "不須累碁撚蠟作跳虎，駿響續取河汾琴。", "沂公不作溫飽計，他日簾前退丁謂。", "讀書有用須濟時，莫止覓官求富貴。"]'),
('d63e9bf8-a6e2-4322-a956-ce4283a2ed75','訪李興伯不遇其家人命二子留宿有古人截髮撤薦之風喜詩之','姚勉','宋','宋诗','song-poetry','','[]','暮煙蒼莽浮林麓，征人尚殿歸鴉宿。',144,'全唐诗/poet.song.224000.json','["暮煙蒼莽浮林麓，征人尚殿歸鴉宿。", "山前知有故人家，急往叩門驚啄木。", "主人多日出未歸，鵲飛三匝愁無依。", "刲羊忽逢伯仁母，設饌乃有襄陽妻。", "竹窗掛燈見二子，褒已自佳融更偉。", "烹雞炊黍羅酒漿，奴飯馬芻更充美。", "慨然好客尚父風，謫僊家人自不同。", "古來如此能有幾，截髮留賓書入史。", "王珪他日貴勿疑，不須論客母可知。"]'),
('f7cecb45-1ddf-4e8e-a2ab-82220b40e846','薦黄平仲過雪巖以詩代簡','姚勉','宋','宋诗','song-poetry','','[]','秀巖萬仞拔天起，劃堮剜垠爭怪詭。',128,'全唐诗/poet.song.224000.json','["秀巖萬仞拔天起，劃堮剜垠爭怪詭。", "六花一夜積三尺，化作冰壺無表裏。", "幼輿丘壑自不凡，何况有雪被此巖。", "天教管領清凉界，雪巖自號冰書銜。", "巖前列植梅松竹，三友相從吾事足。", "靈臺片雪晛不消，吐作新詩動驚俗。", "有客有客山水僊，揮毫欲寫雪洞天。", "敲門試驚袁安眠，莫作剡溪王子船。"]'),
('972227c8-9320-4662-8662-86cc2d950257','贈墨客呂雲叔','姚勉','宋','宋诗','song-poetry','','[]','昔我奏賦趨南宮，路逢墨客回仙翁。',128,'全唐诗/poet.song.224000.json','["昔我奏賦趨南宮，路逢墨客回仙翁。", "筆端攪動雲霧起，裹送龍入天門中。", "薰風入對經前路，更覓僊翁一丸去。", "硯光旗影照丹墀，一笑天顔承雨露。", "謝恩獨拜雖偶然，回翁墨好蛻使僊。", "時人從此填戶買，錙銖可博黄金千。", "一名一第秋蟬翼，視草判花兒戲劇。", "殿頭漬筆和金盂，方得回翁龍劑力。"]'),
('edd19f05-9e35-4f0b-9417-bf1b8b6df63b','贈丹客鄒道士','姚勉','宋','宋诗','song-poetry','','[]','退之不肯學神僊，寧只崛强處世間。',64,'全唐诗/poet.song.224000.json','["退之不肯學神僊，寧只崛强處世間。", "紫陽先生亦有語，金鼎偷生詎能安。", "政令白日生羽翰，瓊臺玉宇高應寒。", "虎鉛龍汞吾豈曉，獨有炯炯心如丹。"]'),
('023d8577-0b7b-47d3-888f-7786b79965bb','贈宗道士元一','姚勉','宋','宋诗','song-poetry','','[]','黄冠元帥之子孫，於今身入虛皇門。',128,'全唐诗/poet.song.224000.json','["黄冠元帥之子孫，於今身入虛皇門。", "當年元帥扶宇宙，瑣瑣粘罕氣可吞。", "汪黄沮撓不如意，空使英雄滿襟淚。", "子孫從此懶作官，隠入雲間羞用世。", "誓掃塵氛志未伸，中宵往往泣鬼神。", "家傳一點心及物，燒作金丹功活人。", "蒼生億萬方受苦，莫戀蓬萊隔風雨。", "急鞭禿角起豐隆，瀉作甘霖蘇旱土。"]'),
('4ed38cfc-3872-4226-a999-35303e3ff789','贈黄道士思成祈雨感應','姚勉','宋','宋诗','song-poetry','','[]','丁巳孟秋春戊午，不雨三時嗟旱苦。',192,'全唐诗/poet.song.224000.json','["丁巳孟秋春戊午，不雨三時嗟旱苦。", "低田高壠皆黄埃，佳種幾成不入土。", "富家倉廩鐵灌鎖，民腹爲雷淚爲雨。", "更遲十日天不問，血肉磨牙總豺虎。", "縣官祈禱聊具文，饑聲嗷嗷恬不聞。", "山中道士睡不著，鞭龍起電驅風雲。", "天瓢點滴翻駿馬，一日甘霖遍天下。", "盡將昨夜赤千里，化作今朝青四野。", "農家笑語無愁聲，指日可望天太平。", "熙朝真主聖且明，漢雨不待宏羊烹。", "或言天民天自恤，或誇調燮有新術。", "山中道士不言功，飽飯熟睡聽松風。"]'),
('f130d68d-f2eb-4117-96b3-4e5c6788f2f0','贈山月道士','姚勉','宋','宋诗','song-poetry','','[]','山高月小赤壁遊，夢中道士鶴掠舟。',64,'全唐诗/poet.song.224000.json','["山高月小赤壁遊，夢中道士鶴掠舟。", "當時此鶴是君否，猶愛山月懸高秋。", "夜深萬籟寂不囂，金波行空爛將流。", "劃然一嘯拍欄玉，宇宙萬物皆浮漚。"]'),
('dfc82ad0-12c7-423e-bdf3-e6208dcc74fc','題道士瀟碧','姚勉','宋','宋诗','song-poetry','','[]','此君蒼蒼誰手植，萬箇琅玕列如戟。',64,'全唐诗/poet.song.224000.json','["此君蒼蒼誰手植，萬箇琅玕列如戟。", "翠寒綠浄不可唾，一片化作瀟湘碧。", "堂中有人有詩癖，日坐清陰聽玉擊。", "巖廊舜正南風琴，不作江邊淚斑滴。"]'),
('2eb31cd9-b690-4712-bb2c-805f5b63a334','中秋放舟','姚勉','宋','宋诗','song-poetry','','[]','玉壺瀟灑澄風露，一派銀河卷輕素。',144,'全唐诗/poet.song.224000.json','["玉壺瀟灑澄風露，一派銀河卷輕素。", "九秋此夜恰平分，冰輪碾上青霄路。", "繞枝散亂驚飛鵲，搗藥分明見靈兔。", "荻花冷浸一汀水，桂子香飄半天霧。", "江山如畫洗塵目，風景入詩多秀句。", "乘風緩放牛渚舟，仰空長歌赤壁賦。", "狂來舉楫直欲舞，興到行盃不知數。", "此江流水自千古，此月照人知幾度。", "一年好處在今宵，不到天明莫歸去。"]'),
('8c9ad898-3602-4c70-9b46-ebd116ee8835','西山雪嶺','姚勉','宋','宋诗','song-poetry','','[]','風掀晴空作頑冷，雪欲成冰漫翠嶺。',64,'全唐诗/poet.song.224000.json','["風掀晴空作頑冷，雪欲成冰漫翠嶺。", "白雲崷崒堆不散，玉龍蜿蜒睡未醒。", "岷峨太白橫參井，移作西山奇處景。", "洪崖安在呼使來，與駕飛車登絕頂。"]'),
('b241a287-342b-436b-a303-391bd545868f','清江曲','姚勉','宋','宋诗','song-poetry','','[]','夾岸桃花燕子飛，一江春水鱖魚肥。',256,'全唐诗/poet.song.224000.json','["夾岸桃花燕子飛，一江春水鱖魚肥。", "絲綸百尺煙波闊，午夜鳴榔載月歸。", "扁舟一葉橫沙觜，得魚爛醉東風裏。", "綠楊深處酒醒時，半江潮落天如水。", "萬頃滄波五月凉，一川紅錦藕花香。", "綠蓑青笠鳴疎雨，老樹殘烟带夕陽。", "野船細火夜明滅，一笛風清楚天闊。", "無魚無酒且歸來，篷底蕭疎卧明月。", "萬里西風雙鬢華，江南江北老天涯。", "瀟瀟兩岸梧桐葉，漠漠半川蘆荻花。", "柔櫓聲中山水綠，一絲買斷黄金屋。", "沙邊鷗鳥莫相猜，是非不到清江曲。", "葦折荷枯人未歸，波寒霜落鴈初飛。", "不知節物時時換，又折梅花下釣磯。", "青山四面清歌發，幾點沙鷗起天末。", "一任長年醉則休，醒時獨釣寒江雪。"]'),
('46df7b5f-4270-4c12-89e5-b10bb8f0c46b','桃源行','姚勉','宋','宋诗','song-poetry','','[]','武陵溪邊翁好漁，笭箵釣車日採魚。',384,'全唐诗/poet.song.224000.json','["武陵溪邊翁好漁，笭箵釣車日採魚。", "扁舟爲家葦爲屋，豈知世有神僊居。", "曉來不記舟行路，忽在桃花深絕處。", "紅雲杳靉望欲迷，絳雪繽紛落無數。", "水源盡處便逢山，一逕似通人往還。", "穿花竟出洞谷口，別有天地如人間。", "青山高下鱗鱗屋，秀野桑麻深潑綠。", "春深耕罷犢牛眠，晝靜人閒雞犬熟。", "村中老幼皆相知，驚逢外人子爲誰。", "平生採魚不到此，借問此是蓬萊非。", "笑言此亦人間耳，聞有蓬萊何處是。", "秦初避亂偶此來，今日已傳秦幾世。", "漁家不識青史編，相傳去秦六百年。", "吁嗟已不聞漢魏，豈復知今晉太元。", "當時祇恐秦萬世，携家挈鄰相遠避。", "早知秦不五十年，安得種花來此地。", "採藥山人去不歸，啖松女子今何之。", "種桃著花尚未實，未必歲月多如斯。", "家家置酒延雞黍，便好卜鄰花底住。", "中心自喜口不言，後日重來今且去。", "悽然辭別便登舟，依舊花間溪水流。", "插竹謾標來處路，鳴榔無復舊時遊。", "顧家一念僊凡隔，如夢驚回尋不得。", "當時不與俗吏知，或可重尋舊踪跡。"]'),
('64905046-0687-487c-bc35-2cef1a6a60b3','送陳糾任滿歸','姚勉','宋','宋诗','song-poetry','','[]','江西道院春風裏，田里嘆愁聲不起。',352,'全唐诗/poet.song.224000.json','["江西道院春風裏，田里嘆愁聲不起。", "黄堂太守政如神，館閣掾官清似水。", "掾官皆清誰最優，寮中錄參陳太丘。", "奮身原自科第出，不比刀筆庸常流。", "生平妙得書中趣，默會欽哉恤刑句。", "木天玉堂未肯遊，且爲黎黔了冤訴。", "操心仁恕真崔公，湯瀋沐浴羣囚同。", "雷轟電燭不留滯，狴犴昔滿今俱空。", "歸巢羣鵲依庭木，春晝圜扉芳草綠。", "政成來泛幕中蓮，吏案凝塵無訟牘。", "幾年摧政冰霜嚴，生怕歡與愁俱添。", "公揮椽筆議革弊，和氣靄靄生青帘。", "感恩戴德殊未已，鳳詔飛來趣行李。", "雲衢直上驟驊騮，一日追風千萬里。", "昔公留此民如瘳，今公去此民如愁。", "父老何嘗欲君去，州縣但恐難公留。", "陳平他日宰天下，大志奇材見分社。", "况公陰德似于公，寧不高車乘駟馬。", "于公受報在子孫，天今報公及公身。", "公身榮顯復子孫，造物豈負真賢人。", "錦帆招颭鼕鼕鼓，愁聽數聲離岸櫓。", "公還爲雨澤九州，多爲高安添滴雨。"]'),
('cb56813f-6cb3-4542-a4ee-93085214cee7','送楊帥參之任','姚勉','宋','宋诗','song-poetry','','[]','古來幕府俱才雄，子美嚴武韓裴公。',128,'全唐诗/poet.song.224000.json','["古來幕府俱才雄，子美嚴武韓裴公。", "近時幕府養清望，一事不到籌帷中。", "先生人物宜臺省，豈合官曹坐閒冷。", "祇今時事欠撐拄，袖手旁觀應不肯。", "潯陽戈甲屯如雲，天子命我參卿軍。", "江頭策馬梟黠虜，快作當年虞允文。", "欲知允文宰相業，只觀采石江頭捷。", "滿望麒麟第一功，不唱陽關第三疊。"]'),
('1f1088e9-b4dc-4d32-b7ae-069091d1ff37','送高錄參美任','姚勉','宋','宋诗','song-poetry','','[]','高安之民椎且質，空蒙惡聲頭上筆。',192,'全唐诗/poet.song.224000.json','["高安之民椎且質，空蒙惡聲頭上筆。", "獨惟猾吏可怕人，架鷹騰霄柙虎出。", "貪官乞錢吏手中，庸官仰筆描吏容。", "獄情黯菼直爲曲，雖欲辨雪何由從。", "先生來糾高安獄，直道仁心作民福。", "吏知積德不忍欺，囚感吐誠爭首服。", "掉頭不肯狥上官，幾回拂意思掛冠。", "伸冤振抑必得請，媿殺同列雙顴丹。", "先生種滿甘棠了，天子知賢恨官小。", "若人底處可安排，不在玉堂應鳳沼。", "鱣鯨自不溝瀆留，郡官無賢民却愁。", "愁公歸去莫報德，但祝高門于定國。"]'),
('4742ea85-5a4f-4202-a34a-c9a4111d137b','送鄭編修罷任','姚勉','宋','宋诗','song-poetry','','[]','江城雪作陰如莫，兒樣老翁啼塞路。',256,'全唐诗/poet.song.224000.json','["江城雪作陰如莫，兒樣老翁啼塞路。", "雲深日隠天不知，驅馬蕭蕭使君去。", "使君四海鄭村邊，人是白玉堂中僊。", "君謨政事文永叔，五花爲筆蒲爲鞭。", "民酣醇酎春風裏，吏姦如魚在寒水。", "橫江立石霓截流，要使千年履如砥。", "瓜時且及報政成，漢法選表宜公卿。", "况今世號天清明，如何饑烏啼夜聲。", "饑烏聒聒正攫肉，驚起鸞鳳騰去速。", "世間公論竟有否，汙此無瑕雪團玉。", "杭州白傅亦自無，若有薏苡猶疑珠。", "中湖築堤到今賜，當時憸兒羣謗蘇。", "先生去住輕蟬翼，一笑歸歟黜如陟。", "但民失母士失師，欲取讒人投有北。", "浮雲豈解終爲昏，先生即來直北門。", "偏州畢竟著不得，滂沛霖雨蘇乾坤。"]'),
('a2b65a90-ed05-46d9-9bf5-b2f14bb75121','次楊監簿上陳守賑災韻','姚勉','宋','宋诗','song-poetry','','[]','稻田碁局分郊區，人煙盡障聯城隅。',368,'全唐诗/poet.song.224000.json','["稻田碁局分郊區，人煙盡障聯城隅。", "新秧入夏種俱了，一色秀綠連天鋪。", "年豐正爲憂國願，雨霪忽動民愁吁。", "浪浪竹瓦日鳴瀑，爛爛苔砌長跳珠。", "江流入市舞篙楫，野潦斷路迷樵蘇。", "孤樹空留白屋少，平地欲縮青天舒。", "犬雞登簷叫雲霧，蛟鼉上岸疑江湖。", "使君視民容有蹙，憂且蕭牆非顓臾。", "家沒半扉鼃上竈，食不一粟糟爲餔。", "鶉衣鵠形避淪沒，槁項髫額相携扶。", "下車以來宣德意，但有寬政無急符。", "溺饑沓至蓋由己，食必稷奏土禹敷。", "故侯遺我四百萬，指此亟作民良圖。", "餽無所處不受是，君子貨取安可乎。", "分甘固欲買不語，溝清那肯同渠汙。", "一朝盡散色不靳，可使被澤遺匹夫。", "錢從民來復還民，塗血不用子母蚨。", "坐令鴈澤得復集，豈但魚沫聊相濡。", "四旬奚堪水五至，十室不忍煙九無。", "只求編氓易菜色，寧計私橐如匏虛。", "方今汙吏爭侵漁，溪壑不厭求贏餘。", "官錢花破入私帑，期限火急催民輸。", "貪者盡笑公迂儒，安得天下皆公迂。"]'),
('75e9d7ec-951b-4b62-b6ea-ad3890d19572','次楊監簿新闢小西湖韻','姚勉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','搜奇抉異三十載，此湖如玉韞而待。',176,'全唐诗/poet.song.224000.json','["搜奇抉異三十載，此湖如玉韞而待。", "發源遠自錦江來，匯流近與柴門對。", "山川融結自古有，造物扃藏深意在。", "瘦筇曾作日尋討，一見便覺天廣大。", "兩山宛似南北峰，况有層塔相映带。", "芰荷十里萼綠華，雪月三千銀色界。", "深藏最有君子意，自衒殊非小人態。", "西湖每遇蘇雪堂，妙句尚憶秦淮海。", "此湖端爲舊遊發，㘲重未信吾州隘。", "鐵菴蜀珍坡僊派，下筆作詩風雨快。", "從今新瑞次古杭，敢賀此湖貢慶會。"]'),
('f07b3c6f-4afb-41e0-aa8e-086bdc9b7bcf','題河沙寺西崖','姚勉','宋','宋诗','song-poetry','','[]','河沙古寺臨江干，山如蜿蜒翠龍蟠。',192,'全唐诗/poet.song.224000.json','["河沙古寺臨江干，山如蜿蜒翠龍蟠。", "入門雙石踞虎豹，排雲萬竹森琅玕。", "山中有景開屏面，路入西崖羊角轉。", "一湖橫陳白於銀，一溪西來浄如練。", "僧言此處好結亭，孔方絕交呼不應。", "竹陰深中即亭子，風月爲戶雲爲櫺。", "寄貲錄事今豈少，不日誅茅坐林杪。", "飯餘曳杖一登臨，看盡青天沒飛鳥。", "晚天落日浮湖光，漁舟相連鴻鴈行。", "浩歌橫笛互相答，底處更欲求瀟湘。", "荷山對面不盈咫，門前吾家錦江水。", "何時亭子高崔嵬，年年釣蓑爲此來。"]'),
('241783ec-0024-4574-b13f-ed0bc041de40','題南昌邑大夫俞君尊公坦庵','姚勉','宋','宋诗','song-poetry','','[]','人心機擭日以非，太行羊膓同一巇。',64,'全唐诗/poet.song.224000.json','["人心機擭日以非，太行羊膓同一巇。", "坦庵先生獨不爾，方寸境界天平夷。", "絃歌武城有賢子，寬曠襟懷亦如此。", "會令天下歸此庵，蕩蕩康莊行九軌。"]'),
('c5a0c0ec-edc8-4c08-aa87-6730f1a4b588','梁新恩送龍涎香盃','姚勉','宋','宋诗','song-poetry','','[]','神龍側枕瓊瑰卧，表裏透薰香玉唾。',96,'全唐诗/poet.song.224000.json','["神龍側枕瓊瑰卧，表裏透薰香玉唾。", "巧工斲取破天馨，碎屑沉蘭百芳和。", "製成七寶金霞觴，猶带嶺外梅花香。", "醁醽一酌發奇馥，滿中灧灧浮龍光。", "感君遺我真情厚，歸拜庭椿一盃酒。", "峻第高官不足榮，人生只願親庭壽。"]'),
('1d869b1d-95c3-4148-8789-769592086dc9','謝胡龍溪惠酒材及五德','姚勉','宋','宋诗','song-poetry','','[]','臘寒無酒虛瓶罍，雪窗孤此梅花開。',96,'全唐诗/poet.song.224000.json','["臘寒無酒虛瓶罍，雪窗孤此梅花開。", "乾簷鵲噪帳鶴舞，蒼頭疾足龍溪來。", "龍溪遺我明珠斛，玉蕊僊花光照目。", "急呼侍兒洗甕盎，壓此蒲萄一江綠。", "缸中酒熟雞更肥，癭樽竹筯常相隨。", "故人故人來何時，安得勇赴雞黍期。"]'),
('91adc97f-3221-4713-ac45-3857c348587e','余評事惠龍團獸炭香瓔鳬實且許以百丈山楮衾而未至','姚勉','宋','宋诗','song-poetry','','[]','青禽銜雲落蓬壺，風簷快讀光眉鬚。',192,'全唐诗/poet.song.224000.json','["青禽銜雲落蓬壺，風簷快讀光眉鬚。", "百朋珍貺羅庭隅，一一皆可當清娛。", "建溪龍焙香雲腴，香瓔巧製來東吳。", "鬅鬙獸炭奇形模，辟邪天祿獅熊貙。", "王家舄種君家鳬，晴沙暖抱明月珠。", "雅意下照僊人癯，矮窗醉兀詩情孤。", "蒲團松拂燒紅爐，蝸廬積凍春潜驅。", "侍兒金珞香玉膚，月鐺著雪煎春酥。", "窗前笑玩嬌黄雛，能言直可貢上都。", "其波及晉皆君餘，獨欠一幅橫雲鋪。", "王孫醉擁紅氍毹，楮生長揖非吾徒。", "藤床紙帳恰此須，能供梅花清夢無。"]'),
('ce75bab8-9c60-45b1-bb33-41d24c836128','贈棋翁挾二童皆高弈','姚勉','宋','宋诗','song-poetry','','[]','蓬萊閬風白雲鄉，瓊樓玉館相低昂。',224,'全唐诗/poet.song.224000.json','["蓬萊閬風白雲鄉，瓊樓玉館相低昂。", "蟠桃影滴仙露濕，壺天晝日和春長。", "老僊鬢眉白於雪，雙侍女僊冰玉潔。", "龍牙棋子琅玕盤，消遣洞中閒日月。", "乘風來戲塵凡中，皓鵠驂以雙鸞紅。", "女僊似是王屋婦，老僊似是商山翁。", "一聲飛雹枰中落，應手鈞天僊樂作。", "環看側睨驚相呀，盡是人間未曾著。", "人間事變如雲輪，面勢更改番番新。", "撫枰不是少奇著，往往當局多迷人。", "五老峰前白鶴址，晝眠扃門日清美。", "棋聲流水古松間，忽然聞之雪堂喜。", "雪堂欲學竟不能，不如旁觀眼自明。", "馬鞍聽朽柯聽爛，局中有路能長生。"]'),
('a5b2fe6f-078e-41a6-8c48-93a41f7fc564','贈定軒游季升','姚勉','宋','宋诗','song-poetry','','[]','海風吹潮濁如泥，咫尺不辨魚與龜。',176,'全唐诗/poet.song.224000.json','["海風吹潮濁如泥，咫尺不辨魚與龜。", "秋潭表裏冰鏡浄，下瞰直可莖鬚眉。", "乃知有萬不齊物，心到定處皆能窺。", "君心久矣波不起，天地不逃圓鏡裏。", "胸中玲瓏列星宿，眼底遠近佳山水。", "人言君脚踏四方，不知君閒謂君忙。", "寒爐曾與話清夜，始覺牖戶虛生光。", "我生之日直南斗，逢人得駡不脫口。", "而今只把定眼看，得失空花總何有。", "但愁國事紛披猖，舉棋不定觀驚旁。", "天傾地仄欠撐拄，安得不動鐵脊梁。"]'),
('31b3dac0-238f-4e99-9708-93720ac22f2d','贈郵文秀才','姚勉','宋','宋诗','song-poetry','','[]','風行水上真文章，不羽不脛遊四方。',128,'全唐诗/poet.song.224000.json','["風行水上真文章，不羽不脛遊四方。", "妙語綴入牙頰香，意有佳客揚其芳。", "美君金璧不願將，多文爲富紛儲藏。", "牙籤玉軸緗縹囊，書船貫月飛虹光。", "鼎肉試取一臠嘗，珠璣璀璨錦繡張。", "疾指快讀下五行，虎鳳蔚躍蛟龍翔。", "尚欲效學雞林商，遍索偉製豐行裝。", "哲匠謹勿麾門牆，當遣紙價貴洛陽。"]'),
('a1c8df57-5a65-4aba-927c-9959790432fa','贈真術秀才','姚勉','宋','宋诗','song-poetry','','[]','天台真術李秀才，手持先兄遺墨來。',96,'全唐诗/poet.song.224000.json','["天台真術李秀才，手持先兄遺墨來。", "先兄已矣遺墨在，三讀感噎重生哀。", "哀餘試問子何術，星斗紛翻舌端出。", "不須問術只觀詩，詩好應知術真實。", "大凡學術總要真，不真誤殺天下人。", "近來世人多弄假，不獨肆中談命者。"]'),
('2cae8d3b-81a3-4781-9e03-e4b0a8cb1401','贈古朴相士','姚勉','宋','宋诗','song-poetry','','[]','巧夫縱誕爭說相，口角瀾翻如剪樣。',160,'全唐诗/poet.song.224000.json','["巧夫縱誕爭說相，口角瀾翻如剪樣。", "眼中元不識英奇，隨世炎凉分下上。", "貢諛乞得貴人詩，紅籤綵軸珍携持。", "未遭窮士或有贈，爛在醤瓿問不知。", "如斯等輩真肉眼，砂裏精金豈能揀。", "古朴相士却不然，品題每在未遇前。", "前時贈詩紙欲朽，逢人誇張不去手。", "古朴相士真識人，識人須要當賤貧。", "信知巧者盡虛僞，惟有朴者全天淳。", "願君終身如此朴，俗態高低不須學。"]'),
('f59a6b1b-6438-4da2-bf3a-17ae15f05644','贈金斗相士','姚勉','宋','宋诗','song-poetry','','[]','君有金斗盍自珍，持此量我非其人。',32,'全唐诗/poet.song.224000.json','["君有金斗盍自珍，持此量我非其人。", "欲我覓印如蘇秦，我寧滿喫三斗塵。"]'),
('9c3db147-823d-4d69-a5ed-c3f3896080e1','贈行在李主人二子','姚勉','宋','宋诗','song-poetry','','[]','李家自古兩詩仙，太白長吉相後先。',64,'全唐诗/poet.song.224000.json','["李家自古兩詩仙，太白長吉相後先。", "蟠螭屈曲作妙語，到今氣焰干雲天。", "君家家裏二奇子，眼如明珠頭玉峙。", "長成學取二仙人，要使詩人常姓李。"]'),
('2659e6ef-5684-43f2-b178-b424bdfa0fbc','贈天王長老無著','姚勉','宋','宋诗','song-poetry','','[]','唐有一僧妙醫藥，得大醫王三昧覺。',160,'全唐诗/poet.song.224000.json','["唐有一僧妙醫藥，得大醫王三昧覺。", "雨中盥手瀑簷飛，驚嘆病龍腥唾落。", "須臾雲霧忽銷霽，白髮老人來矍鑠。", "自言病中困行雨，願得良鍼蘇脈絡。", "授方寸劑應時愈，拜奉僊方效思邈。", "此事今無古信然，說與時人謾驚噱。", "早來忽得絹素軸，挺挺祥龍露頭角。", "心知此龍非病者，噴霧灑雲天洗濯。", "龍身不病澤四方，萬物全生總安樂。", "此龍此醫今是誰，天王長老僧無著。"]'),
('6dff8b33-0a10-4e81-b369-9bd09155109d','贈饒春卿','姚勉','宋','宋诗','song-poetry','','[]','扁鵲華佗不可作，龍宮寶方閉金籥。',132,'全唐诗/poet.song.224000.json','["扁鵲華佗不可作，龍宮寶方閉金籥。", "春卿奚氏劍江饒，老眼熒熒仙授藥。", "傳翳五世活幾人，計日而愈功何神。", "縣疣附贅夜驚失，立使笑語開嚬呻。", "方今氣運乖生盭，天地中盤大癰痔。", "護疽養疾誰見憂，彼何人斯甘吮舐。", "石猶生我疢毒多，能治不使如國何。", "嗚呼安得醫國之老如此手，勿談時事且飲酒。"]'),
('1d00fbf5-ed5b-4b7c-9356-a7072eb95de7','潘吳二察甚振風采劉仲山有詩因次其韻','姚勉','宋','宋诗','song-poetry','','[]','國家元氣幾如髮，章李以來幾臺察。',256,'全唐诗/poet.song.224000.json','["國家元氣幾如髮，章李以來幾臺察。", "翻盆窺甕若不聞，射影含沙但潜發。", "坦途自詫忘羊腸，堅冰恐已在履霜。", "熙豐舊人正伺隙，乃爾寂寂無精光。", "抨彈已上旨宣諭，諫不能行法當去。", "老烏欲食不再鳴，幸有新來柏臺疏。", "蟄霆忽擊聵者驚，不待數月如陽城。", "中書君已非偃月，何事亦惡仗馬鳴。", "奏疏流傳人吐舌，未死姦諛面赬熱。", "祇今時事尚可言，奏四十章當一月。", "直言不憚方威靈，本朝未嘗言罪人。", "但圖奏上天子喜，莫管近前丞相嗔。", "向來慶曆子唐子，千古名垂汗青史。", "瘴山炎海固鬼愁，志士寧能彼易此。", "風塵澒洞何如時，麒麟豺虎方爭馳。", "士所當爲未止此，志完幸聽承君規。"]'),
('fa04786e-4f15-4fbf-8a9f-4780d4e763c4','丁巳春言事西歸和朱子雲賜詩韻','姚勉','宋','宋诗','song-poetry','','[]','鯉魚書來上誰字，斗牛光中湖海士。',208,'全唐诗/poet.song.224000.json','["鯉魚書來上誰字，斗牛光中湖海士。", "梅花臘雪曾會面，桃李春風一彈指。", "剝書得詩意雄傑，鍾呂驚聞箏笛耳。", "懦夫有聞氣可作，姦諛未誅神已死。", "奴唇爭笑乃獨否，我心有同固如此。", "君家請劍攀折檻，遠勝衣繡誇歸里。", "立朝日少諫多藁，况有竹林老夫子。", "百年易了富與貴，萬古不磨天此理。", "笑駡從渠官欲好，妻妾羞人身不恥。", "獲禽一朝固可十，天下良工安肯詭。", "古人寥寥今不見，舉世滔滔此皆是。", "蛾眉方遭衆女嫉，足音忽動空谷喜。", "我欲浄洗后土泥，子爲快挽天河水。"]'),
('1bc591d8-c54a-4854-bb19-6d000b31a355','和楊監簿咏梅','姚勉','宋','宋诗','song-poetry','','[]','不知年換山無曆，日短著書陰自惜。',128,'全唐诗/poet.song.224000.json','["不知年換山無曆，日短著書陰自惜。", "臞僊誰與伴清孤，竹裏梅花破幽寂。", "月窗看影嗔曉奪，雪徑尋花驚夜失。", "絕憐一點清淡意，不作羣芳妖艷質。", "夢寒翠羽真恐涴，香遠細腰何敢即。", "廣平亦作軟媚語，可笑鐵心輕變易。", "梅州參徹梅花髓，句中有味供紬繹。", "冰甌滌筆想更奇，試爲此花重請益。"]'),
('b85a86c5-7f28-4f5f-a8a2-2f237358f9ac','送孫龍谷','姚勉','宋','宋诗','song-poetry','','[]','煌煌南方老人星，天邊飛來地上行。',160,'全唐诗/poet.song.224000.json','["煌煌南方老人星，天邊飛來地上行。", "秀眉方瞳瑣骨聳，升降步履如風輕。", "生平見說勇爲義，十指團欒一和氣。", "祇今福壽天所報，眼底曾孫家四世。", "瑞祥融作合幹松，豈惟義聚蒙天封。", "義人合得松樣壽，孫枝蓊勃環老龍。", "先生教人忠與孝，家法可爲民則傚。", "道中有福理自然，必收詩書仁義效。", "子孫森列皆有文，次公長公爲弟昆。", "曾孫早娶見玄孫，蒲輪迎召登金門。"]'),
('f899a0ce-1f72-4977-9327-19e758c4d039','送李幼章','姚勉','宋','宋诗','song-poetry','','[]','梁間呢呢燕將雛，林中櫨櫨反哺烏。',144,'全唐诗/poet.song.224000.json','["梁間呢呢燕將雛，林中櫨櫨反哺烏。", "君前舍羹潁谷子，橐中寘簞翳桑夫。", "五年得金方還養，有婦有婦愁秋胡。", "士生志大雖江湖，不堪回首飛雲孤。", "伏雌扊扅且未論，占鵲日日旦及晡。", "篋中萊衣幸可著，腰下何必印若蘇。", "因君歸去長嗟吁，君有母遺我獨無。", "爲親負米今已矣，落日慟哭悲丘墟。", "願君升堂奉甘腴，毋使專美徐仲車。"]'),
('e9f2a8c9-f65c-4e93-9e6f-7fe646ef0ba7','九日簡張倅','姚勉','宋','宋诗','song-poetry','','[]','西風破帽吹不斜，東籬繞行空嗅花。',64,'全唐诗/poet.song.224000.json','["西風破帽吹不斜，東籬繞行空嗅花。", "隔牆酒熟無鄰家，草堂欠醉從誰賒。", "亦思峰頭作重九，安得天風吹灧酒。", "別駕倘作城南期，賢似江州王太守。"]'),
('4cc99c40-2211-46d4-901c-52fe09821969','送胡季㢸入太學','姚勉','宋','宋诗','song-poetry','','[]','春秋自有胡氏學，盡束諸家上高閣。',128,'全唐诗/poet.song.224000.json','["春秋自有胡氏學，盡束諸家上高閣。", "當時小試錦江城，橫翼秋風天一鶚。", "祇今冠带圜橋門，孤羆兀坐空狐羣。", "近來文氣頗卑苶，要使四海宗雄文。", "余生志願遊璧水，竟隔蓬萊三萬里。", "雖然末第偶成名，俗骨自憐凡可鄙。", "君今換骨向時中，六館名流自不同。", "宰相狀元三舍選，齋前碑字看填紅。"]'),
('8ec758ec-286a-4bff-9e8c-e81e9fe8381f','送漆文甫尉分宜','姚勉','宋','宋诗','song-poetry','','[]','吾兄梅花冰雪臞，胸中萬卷行石渠。',144,'全唐诗/poet.song.224000.json','["吾兄梅花冰雪臞，胸中萬卷行石渠。", "同生丙子自兄行，才學推兄更有餘。", "月中折桂仍先余，兄騎快馬余蟾蜍。", "一行作尉表貳邑，春臺春風宜吹噓。", "阿瞞綵棒謹勿設，民命今皆轍中魚。", "合得官職聽自除，覓薦莫作迎逢諛。", "寒齋話別酌霜月，祝子但此霜月如。", "欲留不可空攬袪，兄出我處從今疎。", "兄出我處從今疎，有便但寄箴規書。"]'),
('4f8be4e3-eb46-447c-b3ba-6dec43caad6f','送琴隠吳君','姚勉','宋','宋诗','song-poetry','','[]','天高日烈勢欲然，秧已生節未入田。',64,'全唐诗/poet.song.224000.json','["天高日烈勢欲然，秧已生節未入田。", "誰歟操琴尊師涓，使我赤地里至千。", "風雩且歌吾自樂，窮閻不可無炊煙。", "薰時解慍民望切，亟爲我作南風絃。"]'),
('b670dbc1-bdd7-4d43-bbce-29f8393c607a','題譚君詩集','姚勉','宋','宋诗','song-poetry','','[]','建州衣鉢傳武功，山谷濠梁窺謝公。',64,'全唐诗/poet.song.224000.json','["建州衣鉢傳武功，山谷濠梁窺謝公。", "譚君之詩何自工，君家詩有冰清翁。", "野塘千頃涵秋風，資奩盡在奚囊中。", "蘇僊今已騎虬龍，野塘釣艇君誰同。"]'),
('3782151d-986d-4855-a5ae-f3dfccfa4356','贈彭花翁牡丹障','姚勉','宋','宋诗','song-poetry','','[]','洛之花圖歐公詩，驚怪天巧呈新枝。',370,'全唐诗/poet.song.224000.json','["洛之花圖歐公詩，驚怪天巧呈新枝。", "自言當時記者數十種，姚魏後有潜溪緋。", "蜀之花圖景仁句，香雪蕊金藏不露。", "徑圍三尺瑞雲紅，尚有二花添未具。", "此花非惟今所無，世間久亦無此圖。", "東南花樣自來小，如盤能幾多如盂。", "曉來明眼花翁作，風韻宛然如蜀洛。", "寫作花中第一花，羣類一時都脫落。", "想渠欹筆小盤礴，心去化工無一膜。", "天上司花巧不神，筆底春風光欲爍。", "籠寒不假青蒻庵，護日何須碧油幙。", "月坡堤，張家園，郭令公宅東街偏。", "錦衾繡帳相接連，一夜移入歌堂巔。", "吳臺教戰娃數百，漢宮列侍娥三千。", "鮫綃十丈思公譜，錦茵萬態元輿賦。", "花自長春蠟不封，根無下土蟲難蠹。", "花翁花翁子誠能，見渠此畫萬感增。", "此花昔惟載本草，流傳至唐花始好。", "移來從武曌，愛重由環兒。", "名花與傾國，初著沉香詞。", "從此帝城春，爭逐賞花期。", "徑尺誇千朶，萬錢買一枝。", "三街九陌沸遊賞，冠蓋車馬相追隨。", "自入天朝花最盛，長壽不數唐崇敬。"]'),
('daa71ba9-3b46-466b-92c4-1b7bc517b8c2','京城苦熱','姚勉','宋','宋诗','song-poetry','','[]','羲和鞭日就地行，祝融張傘燒空明。',128,'全唐诗/poet.song.224000.json','["羲和鞭日就地行，祝融張傘燒空明。", "錢塘人家苦偪仄，行立坐卧皆如蒸。", "清宮水殿山峨雪，夜飲相携冰玉潔。", "溫泉浴罷清風來，太液池邊芰荷月。", "王公甲第連雲霄，松泉竹石秋蕭蕭。", "龍皮淺沁寒坐客，驪珠直上清塵囂。", "天上清凉不知暑，炎熱人間徒自苦。", "亦有江南雲水鄉，胡不歸歟釣煙雨。"]'),
('27e5cfd7-da53-4217-a6f5-98b77bced5a6','夢保母如兒時','姚勉','宋','宋诗','song-poetry','','[]','憶昔兒時衣百花，阿母扶我上戲車。',96,'全唐诗/poet.song.224000.json','["憶昔兒時衣百花，阿母扶我上戲車。", "兩歲讀書未離乳，書罷尋乳猶歸家。", "年方十三失阿保，弱冠慈母僊去早。", "祇今堂上獨靈椿，念及庭萱怨露草。", "夜來忽夢如兒年，阿保携抱慈母憐。", "人生安得常童顛，只作嬰兒啼母前。"]'),
('44e5de65-4536-4d73-8d69-9f72de2c25d3','題魁字軸','姚勉','宋','宋诗','song-poetry','','[]','玉衡杓建天之綱，枕參魁耀森寒芒。',128,'全唐诗/poet.song.224000.json','["玉衡杓建天之綱，枕參魁耀森寒芒。", "總提衆星環侍傍，仰望熠熠開神光。", "有美俊容分天章，收入翰墨何淋浪。", "一筆三丈超尋常，字勢直作蛟龍驤。", "錦裝玉軸垂高堂，標靈發異呈嘉祥。", "即吐奇策先衆芳，巍峨姓字壓四方。", "魁下三台炳煌煌，上拱紫極天中央。", "作第一流謹勿忘，冠冕今古萬世香。"]'),
('3b471402-294a-4cbe-bcb2-c4dabc7111ab','贊趙直閣所藏四美人畫 春','姚勉','宋','宋诗','song-poetry','','[]','晴絲暖絮浮春光，牡丹醉裏微風香。',64,'全唐诗/poet.song.224000.json','["晴絲暖絮浮春光，牡丹醉裏微風香。", "繡簾不捲日低柳，百囀黄鶑啼斷腸。", "玉兒步整金蓮穩，回首光流花面粉。", "嬌慵欲去未肯行，一逕落紅愁踏損。"]'),
('aef1979e-a2bd-406b-a182-3e72184985aa','贊趙直閣所藏四美人畫 夏','姚勉','宋','宋诗','song-poetry','','[]','瑶臺夢斷敲門竹，鳳蹬溫泉新出浴。',64,'全唐诗/poet.song.224000.json','["瑶臺夢斷敲門竹，鳳蹬溫泉新出浴。", "侍兒扶起嬌不禁，蟬翼紅綃影紅玉。", "晚蟬聲裏追新凉，藕腕輕拖龍巾長。", "留仙裙舞風力軟，不知何處荷花香。"]'),
('f5d4fe75-8ad1-4495-9497-4bdf47e4038c','贊趙直閣所藏四美人畫 秋','姚勉','宋','宋诗','song-poetry','','[]','林梢脫葉飛斜陽，寄書鴈着西風行。',64,'全唐诗/poet.song.224000.json','["林梢脫葉飛斜陽，寄書鴈着西風行。", "恩情怕學中斷絕，畫扇未忍高秋藏。", "小庭寂寞歸鴉後，蹙損遠山雙峰鬭。", "淚珠濕袖對黄花，人比黄花又更瘦。"]'),
('d0b34ea8-0414-4689-9c2a-7ee041bcdb9c','贊趙直閣所藏四美人畫 冬','姚勉','宋','宋诗','song-poetry','','[]','紅爐暖閣烘如春，玉琴不撫生微塵。',64,'全唐诗/poet.song.224000.json','["紅爐暖閣烘如春，玉琴不撫生微塵。", "梅花嗅罷寂無語，千里瀟湘思故人。", "燕釵和悶都敲折，愁攪柔腸千萬結。", "沉吟望斷信不來，同雲暗釀江天雪。"]'),
('b2b8254f-63f8-457f-9f81-639ecfeb79e7','題楊妃出浴圖','姚勉','宋','宋诗','song-poetry','','[]','溫泉暖滑留餘香，芙蓉出水紅生光。',64,'全唐诗/poet.song.224000.json','["溫泉暖滑留餘香，芙蓉出水紅生光。", "寶釵義髻嚲龍鳳，力困未必忺霓裳。", "歛衣側步無窮意，猶勝朝來海棠睡。", "誰知迎洗錦綳兒，已在華清賜浴時。"]');
